O Order_Items (id, order_id, product_id, quantity, price) VALUES (499, 499, 33, 1, 1295.00);\nINSERT INTO Shipments (id, order_id, warehouse, mode, status) VALUES (191, 499, 'Main Warehouse', 'Flight', 'DELIVERED');\nINSERT INTO Orders (id, user_id, store_id, status, created_at, grand_total) VALUES (500, 31, 1, 'CANCELLED', '2017-03-06 00:00:00', 1699.00);\nINSERT INTO Order_Items (id, order_id, product_id, quantity, price) VALUES (500, 500, 38, 1, 1699.00);\n-- INSERT REVIEWS\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (1, 29, 107, 4, 'this is the first 8 issues of the series. it is the starting point of all this... it also contains the sound of her wings. issue #8. which is the first appearance of death. and many peoples favorite issue. its not the best of the collected works. but its the start of them.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (2, 34, 73, 4, 'I''ve always been partial to immutable laws. The tape is entertaining, good car listening. The laws are clearly self evident once you''ve  heard them and you wonder why you didn''t know  all that already and were about to go off and  do something stupid.  It''s cheap, get it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (3, 13, 72, 5, 'This is a book about first contact with aliens, written by a prominent member of SETI, the Search for ExtraTerrestrial Intelligence. Sagan makes excellent use of  SETI''s current search methods as well as his own  knowledge of astronomy and physics to bring a sense of  reality to the book. But above its literacy, philosophy,  and speculation, it is an entertaining story that is not  overshadowed by gadgetry.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (4, 49, 182, 5, 'This is quite possibly *the* funniest book I have ever read.  Terry Pratchett is an absolute genius (read the Discworld books--NOW!),  and Gaiman manages to give the book the appropriate dark touches.  Brilliant');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (5, 23, 155, 5, 'The story behind the book is almost better than the work. But make no mistake, the work will endure.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (6, 23, 190, 5, 'Marion Zimmer Bradley brings King Arthur''s court to life through the eyes of a woman in The Mists of Avalon.  It is by far one of the best novels I''ve ever read, and I recommend it to anyone who is interested in seeing a legend from a different point of view');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (7, 32, 116, 5, 'Pulp Fiction the movie is one of my favorite movies. The   soundtrack is excellent. I reccommend it. E-Mail me and tell   me your thoughts on the movie &amp; the soundtrack of   PULP FICTION.  END');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (8, 32, 88, 5, 'The Doors is one of my favorite movies. Val Kilmer is a   great actor. E-Mail me and tell me your thoughts on this  movie  END');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (9, 45, 107, 5, 'The book in some way or another gives a deeper view into the chinese own set of behaviour. Touching at times.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (10, 32, 103, 5, 'This book is a fast read.   It covers strategic, high-level  marketing like no other marketing book,   and I''m a Marketing MBA who has read 400+ marketing books.    The book shows how &quot;positioning&quot; is critical for any business.    And the 22 laws can be reduced   to a list that fits on one page.    Absolutely Excellent.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (11, 42, 8, 5, 'John Grisham''s The Rainmaker keeps you guessing &amp; keeps  the pages turning as you route for the underdog &amp; recent law school graduate, Rudy Baylor, as he takes on the one of   the most revered law firms in Memphis.  I didn''t expect much - but I think this is John Grisham''s finest!  I highly recommend it!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (12, 12, 72, 5, 'This was my first (I''ve read all his books!) and favorite book.  The story is not only compelling but heartwarming as well.  It mixes horror and science fiction (fact?) with people who are very real with   believable problems and takes you on an amazing adventure.  If you were  interested in Dean Koontz and want to try one of his books, this is the  one!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (13, 49, 129, 5, 'I usually don''t like TSR books, but Homeland just blew me  away. A society of *EVIL* ''Drow'' elves live underground. One elf breaks the mold and fights for what he feels is  right. Beautifully written with increadible fighting scenes.  Intricate plot and so many twists and turns your head''ll  spin.        Book #1 in a 9 book series, it actually was the fourth  book written (Crystal Shard was first, from the Icewind   Trilogy) but it is MUCH better if you read the Dark Elf   Trilogy then Icewind Trilogy and then the following 3 books.  #9th book leaves so much unanswered and I don''t know if he''s  going to continue. Does anyone know?');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (14, 15, 109, 5, 'On the surface, first-person story of a young girl''s adventures in a small southern town during the depression. Story addresses impact of economic hardship and extreme  racial injustice through the eyes of the heroine without  patronizing her.    I believe the character of &quot;Dill&quot; was based on Truman  Capote, a childhood friend of Harper Lee.    One of the finest books I have ever read; I generally  reread it every year or two.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (15, 40, 13, 5, 'How do you review a life? Anne Frank was a child becoming an<br />adult at the onset of the Second World War, and the diary of<br />her life is the diary of any bright, perceptive young girl<br /> becoming a woman, and the diary of a Jew who died in the Nazi<br /> death camps.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (16, 20, 92, 4, 'After briefly visiting the world of Disco and commercialism,  Kiss is back with a hard and heavy return to their roots.  Includes the classics: &quot;I Love It Loud&quot;, &quot;I Still Love You&quot;   and the title track.  END');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (17, 31, 30, 5, 'Barnes is a true master of the English language. This book<br />is an absolute treat to read.  Barnes ability to weive seemingly<br />unrelated subjects such as woodworms, Noah''s Ark and golf into<br /> a master''s thesis on human life seperates him from<br /> any author I''ve ever read.  Truly a &quot;History of (Humans in) the World.&quot;');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (18, 14, 186, 5, 'I have to say, that when Stephen King wrote this book he truly outdid himself.  Stephen King enters you into the world of  seven children that are bonded by destiny to fight evil itself  in the form of a clown that haunts them and kills other children.    After they thought they had killed IT, 20 something years later, IT  comes back and they are drawn back to their hometown to face  the same evil they faced as children but now they are adults  and actually don''t have their innocence and imagination, which  were their advantages over IT.  You''ll be hooked until the end  until one of the forces wins, IT or the force that draws the children  (now adults) toghether.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (19, 19, 169, 5, 'I''ve been waiting for a book to take me by the hair and drag me, like Gaddis but enthralling, like Pynchon but still unread.  Wallace delivers genuis of our times (and times surely to come.)  Every character, every scene (seemingly every thought that''s gone through this guy''s head for the last few years...) is here.  Couldn''t push it on enough of my friends -- I don''t know what the naysayers could be talking about');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (20, 42, 33, 5, 'Ayn Rand was the foremost advocate, and indeed the creator of objectivist philosophy.  Howark Roark is the champion of  every man or woman who has ever felt beaten down by a system  created by and for self-serving incompetents.  His unwavering  devotion to himself and his ideals is an impressive testament   to Rand''s philosophy.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (21, 13, 143, 5, 'What''s the best way to whack yourself to a more creative way of life? Surely the Creative Whack Pack is one of the more practical systems to problem solving for anyone. I bought one sometime ago, now I''m buying four more for my colleagues at work and for Christmas I''ll be buying some more');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (22, 24, 74, 5, 'I think The Alchemsit is a wonderful story that can inspire anyone to realize what it is they want most from their life. The author creates a beautiful image and atmosphere that   pulls you right into the story.    Read it yourself and/or to your children.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (23, 32, 145, 5, 'Good Gravy!!! I read this book just after I had turned 17, and was blown away by the outstanding skill Card uses to convey his characters'' humanness - their trials, tribulations,   victories and defeats. The book touched me, moved me in a way   books don''t normally do - I read it in one sitting, from 2   til 5:30 in the morning - I just could NOT PUT IT DOWN!!!  Read this book, you will _not_ regret it.    BRAD ROHRER');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (24, 24, 10, 4, 'Review of  \\\\"It''s Not Luck\\\\" by Eliyahu M. Goldratt:This story is about marketing and competitive strategy.  Alex Rogo, Mr. Goldratt''s fictional hero, has to save three of his companies and hundreds of employees from the chopping block of corporate divestiture by applying logic and persuasive skills. Mr. Goldratt conducts his unique style of logical examination in a field different from that of the \\\\"The Goal\\\\", his first and more famous book.  While \\\\"The Goal\\\\" says run your production operation for cash, \\\\"It''s Not Luck\\\\" says the value of a product, or an entire business, is in the eye of the buyer, not the supplier.  A management book without the jargon and trendiness you get elsewhere.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (25, 41, 142, 5, 'I''ve already worn out a copy of this book, and I''m writing this review as I prepare to purchase another copy.  Don''t let this book pass you by!  If you have even the slightest sense of humor, you''ll be disappointed when the end finally comes.  However, Ignatius will make you laugh out loud several times before the end finally comes.  See how long it takes you to wear out your first copy...  Enjoy!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (26, 28, 17, 4, 'It is amazing (and embarrassing) how often I saw myself and my co-workers described in this book. The cartoons are excellent as usual. I didn''t give this book a 10 because some of the filler was very inane. I was often tempted to skip over the text just to read (and re-read) the cartoons. This book must be in your business library. It says some things about the way we manage (and are managed) in the business setting that cut right to the quick of our personalties. I couldn''t read this book at work because it was too laugh out loud funny');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (27, 31, 21, 5, 'This is the kind of book that you are likely to have extreme opinions about.  You''ll either love it (I fall into this category), or you''ll find it completely unreadable.  There is a plot (of sorts) revolving around the Infinite Jest video (the book''s McGuffin), an &quot;entertainment&quot; so completely involving that viewers will starve to death watching it over and over.  However, this is merely the backdrop for a series of stories involving tennis, drug and alcohol recovery, the nature of addiction:  the stories go on and on.<br />The book is VERY long, but  I found myself enthralled by Wallace''s storytelling ability - for all of the book''s modernist quirks, the good old fashioned storyteller''s art saves Infinite Jest time and time again.  As with any book of this length, there are passages the book could probably do without (for my money, a long sequence involving a nuclear war game, Eschaton, would be cut), but I didn''t want the book to end.  At 1000+ pages (with footnotes), some ');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (28, 41, 170, 5, 'This is one of perhaps 8 books that I would give a 10 to<br />and would be my unhesitating answer to the question, &quot;What<br />is the best sci-fi novel of all time?&quot;<br /><br /> Herbert has achieved what very very few sci-fi writers do:<br /> he has created a complex and utterly believable &quot;universe&quot;<br /> that is almost wholly alien to our own. Yet despite this<br /> yawning gulf, Herbert spells nothing out; we learn about the<br /> universe by seeing it through the eyes of the<br /> extraordinarily compelling characters who inhabit it.<br /><br /> This is not an easy read, and it takes more than a single<br /> reading to really appreciate it. NB: do NOT make any assumptions based on the movie. It simply<br /> doesn''t compare.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (29, 27, 35, 4, 'Despite arguements about the precision of the facts in the book, I found this book engaging and impossible to put down.  For all those jaded literary snobs, don''t bother, but if you like a good story and are prepared to suspend disbelief for a short time you will find this book just what the doctor ordered');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (30, 28, 84, 5, 'And you thought only science fiction could take you beyond where you are today.  James Clavell submerges you in 16th century Japan where you experience the power struggles,  romance, and even the language.  By the end of the novel,   you you will have seen peasants   getting chopped up for not bowing low enough, samurai   commiting seppuku for arriving late, and Jesuit priests   grovelling for converts.  This is probably  the best book I''ve ever read in terms of connecting with  the characters'' own triumphs and tribulations.  Wakarimasu   ka?  Enjoy!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (31, 50, 101, 4, 'I would advise people who want to read this book to take it slowly.  Michael Ondaatje''s unusual style of prose can make it very difficult reading.  But once you get through it you are definitley home free.  I really enjoyed it and advise people to open it up and enjoy.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (32, 4, 29, 5, 'This novel is the best novel I read of John Grisham. This novel has a bit of everything: a a lot of humor, a bit of action, a bit of romance, and it has a lot of suspense. As  the story ends the suspense rises and doesn`t stop until the  last few pages.  It shows viewpoints of issues like spousal   abuse.  The best thing of this book is the complex plotting.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (33, 24, 125, 5, 'In the tradition of Lord of the rings (Tolkien) and Memory Sorrow and Thorn (Williams) here is another trilogy with an unlikely hero. Royal Assasin continues the story of Fritzchilvary, the bastard son of the late Chivalry. Despised by the current heir and recenly recovered form an attack by poison initiated by the curent heir to the throne he returns home to to find that things haven''t become any better in is absence. This book relates the second part of Fitzchivalries life in which the red ship raiders become ever bolder and the plots of the enemies ever thicker resulting in the eventual evacuation of buckkeep.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (34, 11, 144, 5, 'The Crying of Lot 49 is truly one of the most amazing books  I''ve read -- period.  The story involves one Oedipa Maas and  the adventure she has while being the executor of Pierce   Inverity''s will.  She encounters a possible postal conspiracy   dating back to Roman times, characters and stores that vanish   from the planet, and enough mysteries and confusion to last   a lifetime.<br />   This book must be analyzed at some level as you   read it to take full advantage of all the layers, symbols,   and themes.  The more you analyze it, the better it gets, but   the more you have to analyze!  I still don''t know how   Pynchon keeps everything separate!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (35, 32, 159, 5, 'It really happened: only the names have been changed...<BR>  Yoshi Toranaga was Tokugawa Ieyasu, the founder of the  Tokugawa Shogunate. There really was a Battle of Sekigahara,    although Ishido (Ishida Mitsunari) was beheaded, not buried   while passers-by sawed at his neck... Toda Buntaro   (Lord Hosokawa) had a Christian wife, Gracia (who appears   in the story as Mariko). The Taiko was Toyotomi Hideyoshi,   and he really did order an invasion of Korea. The dictator   Goroda was Oda Nobunaga, and he was a nasty S.O.B., even   by daimyo standards. <br />   [...] &quot;The Crisis Manager&quot;');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (36, 32, 39, 5, 'Whoa!!! This book makes you an offer you can''t refuse! It''s like when you start this book, you have this ENORMOUS need to finish it! The Movie Is an American Masterpiece, but if you haven''t read  the book, you''re only getting Half the story! I doubt i''ll read  another book, quite as amazing as this one, any time soon!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (37, 32, 137, 5, 'This book rocks.  Footnotes in fiction?  Fascinating.  By page 77 I was sad because I knew that someday much too soon I would finish it. It is engaging, captivating, mesmerizing; and at 1000 pages, much too short.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (38, 30, 89, 5, 'Uncannily accurate and devastatingly funny. You''ll want to xerox<br />every second cartoon and send it to somebody in your company.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (39, 24, 90, 5, 'Treasure Island was written by Robert Louis Stevensonand is considered by many to be his best novel, topping,among others, &quot;The Strange Case of Dr. Jekyll and Mr. Hyde,&quot; &quot;Kidnapped,&quot; and &quot;The Master of Ballantrae.&quot;  Perhaps it is  because of his superb use of symbolism; the name Jim Hawkins containing the word &quot;hawk,&quot; the name of a very majestic bird.  Maybe its because of its because of the book''s excellent excellent storyline, full of excitement and fantasy.  Re- gardless of the book''s best quality, if there is just one, it is wonderful reading for young and old.  Don''t miss it!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (40, 28, 116, 5, 'This book is a &quot;must&quot; for all of us that dream of that one &quot;perfect&quot; love that comes but once in a lifetime.  If you want to be transported to another time and place and realm in all that love has to offer, this book is exactly what you have been searching for');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (41, 15, 22, 5, 'Treasure Island was written by Robert Louis Stevenson and is considered by many to be his best novel, topping,among others, &quot;The Strange Case of Dr. Jekyll and Mr. Hyde,&quot; &quot;Kidnapped,&quot; and &quot;The Master of Ballantrae.&quot;  Perhaps it is because of his  because of his superb use of symbolism; the name  Jim Hawkins containing the word &quot;hawk,&quot; the name of a very majestic bird.  Maybe its because of its because of the book''s excellent  excellent storyline, full of excitement and fantasy.  Re- gardless of the book''s best quality, if there is just one, it is wonderful reading for young and old.  Don''t miss it!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (42, 27, 52, 5, 'This book combines all the elements that grab me and ensnare me,viz.suspense, mystery, intellectualising but in an accessible form. I''ve always wanted to learn more about the history of philosophy but it is a severely daunting subject usually encased in great tomes that intimidate far more than they entice.  Jostein Gaarder makes one wonder why everyone else always over complicated the matter. I wish I could be chosen   as someone''s Sophie and could enter a world of wonder and discovery, constantly being stimulated towards deeper  understanding of our un-understanding.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (43, 3, 84, 5, 'If you have anything to do with medicine - except from being a patient - read this! Amazingly funny in the beginning it turns to become more and more cynic. Includes the 10 rules of the House of god! If you don''t have this book - get it now');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (44, 39, 2, 2, 'Barbara Tuchman''s attempt at this is unbelievable.  The  book is essentially a rambling of medival history which often refers back to a certain dynasty.  It is filled with  hundreds of obscure French names which have nothing to do  with anything.  Tuchman jumps from one topic to another,   creating a loose (even non-existant) organization which  leaves the reader lost and confused.  Tuchman seems to   think that her reader already knows the information she  is trying to convey.  It is almost as if Tuchman sat down  at a typewriter and asked herself, &quot;what do I know about  medival European history?&quot; and then wrote whatever came to  her mind, when ever it came to her mind.  With the exception  of the 5th chapter, which details the death and suffering  of millions during the various plagues, the novel is as dry  as sand.  The book''s only merit is its informational value,  which if the reader can follow, or for that matter even  stay awake, he may gain something from this book.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (45, 15, 13, 5, 'Joe Simpson''s writing style is perfectly balanced for  creating a sense of sustained tension. I read this book  in two sittings and found it to be among the best adventure  books I have ever read. Simpson''s follow-up book, &quot;The Game   of the Ghosts&quot; is a must read after this one.  After reading &quot;Touching the Void&quot; I find myself looking at  personal motivation in a different light.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (46, 3, 193, 4, '<br />Barbara Tuchman''s work is in the genre of the essayists of the 19th century. Like them, she is erudite, humorous, and  at times, disorganized. <br />But how could it be otherwise? Imagine writing such a work about the 20th century, attempting to describe for  someone 600 years hence how we have   lived over these last hundred years, and how we have changed.<br />   This is a work which some may wish to plow though in several days; others will   put it by their best arm chair and read a section at a time. <br />   Given the horror of Bosnia, the tedium of politics, and the    daily drudge (which at times seems in spirit to be remarkably similar to that which Tuchman describes) such a work of Tuckman''s can lift us up and help us to see beyond our own calamitous   century -- plus ca change; plus la meme chose.   <br />   KRH<BR>   [...]');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (47, 36, 48, 5, 'Not since the discovery of Parkinson''s Law and the formulation of The Peter Principle has there been anything quite as poignant and timely as the conception of The Dilbert Principle. &quot;The most ineffective workers are systematically moved to the place where they can do the least damage - MANAGEMENT.&quot; That''s the essence and message of The Dilbert Principle. With over 250,000 copies in print and a meteoric rise to No. 1 on Business Weeks''s hardcover business books best-seller list, this revenge of the cubicle dwellers is a mix of cartoon strips and Scott Adams'' succinct observations describing ridiculous company policies and dysfunctional management practices. Not surprisingly, the message is coming in loud and clear in high places. Reengineering guru Michael Hammer has jumped on the Dilbert bandwagon by suggesting that &quot;there is more truth in one volume of Dilbert than there is in 10 volumes of Harvard Business School case studies.&quot; Dilbert pokes fun at organizations ');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (48, 36, 26, 5, 'Rated 9 only because I lacked the courage to rate it 10.    If you like to read books you will probably be swept away  by this novel, the first of a thankfully long series by   Patrick O''Brian.    The subjects are the British Navy of the Napoleonic Wars and  two men: Aubrey -- a naval officer and (one quickly assumes)  one of the best sailors who has ever lived and Maturin -- a  physician and &quot;agent extraordinaire&quot; who seems to be  bent  on giving Thomas Jefferson a run for his money as  the man who knows the most of everything that could  be known.    O.K. so you don''t like war, sailing, or the early 19th century.  After a few minutes reading this book, you will.  Even lazy  readers (myself for example) will suddenly develop a great  interest in the rigging of three-masted sailing vessels of  the era.      And did I mention, color, romance, and character   development?  A lot of natural science as well.    The publisher offers the whole set of Aubrey/Maturin  novels in hardb');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (49, 48, 76, 5, 'Thoroughly entertaining, plus it gives you insight into all the events and EVENTS that led up to the other series of books by Eddings.  I couldn''t put it down!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (50, 12, 78, 5, 'This is the kind of book that will take you out of whatever section of our often dreary, unkind world you inhabit, and settle you down in its own place.  You''ll meet characters who know which rules to break,  and how to break them properly. The writing is lovingly  infused with the flavor of the south, and with a kind  of humor that an author couldn''t take on if it weren''t   genuine. And when it''s over, you''ll be sad that you don''t  live in Whistle Stop, but it will be OK, because Whistle  Stop lives in this book and you can always reread it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (51, 31, 49, 5, 'Ender''s Game is an incredible,unforgettable book that will stay with you. It follows the early years of a &quot;Third&quot; child. A misfit in society. From his home on Earth to a military academy in space, it tells a gripping and unpredictable story that will keep you guessing until the shocking end. This is one of the few books to have made an everlasting emotional impact on me. I give it my highest recommendation');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (52, 19, 22, 5, 'Hardly in need of further literary acclaim, Herman Hesses Siddhartha nonetheless forces this reader to relate yet another positive response.  From the standpoint of a recently undergraduated copywriter in need of a solid vision for the future, Siddharthas trials and eventual spiritual grounding and discovery are meaningful and, at last, comforting revelations that have forced me to examine my own spirituality, materialism, romances, and values.<br /><br />The importance of observing and feeling everything with an open heart and mind while following your own deepest inclinations and directions is the only way to truly determine where you belong, Siddharthas words and actions inform the reader.  From forest to town to river, Siddhartha is welcome and loved for he learns from and gives to all that come to know him.  He gives questions to a spiritual leader and passion to a woman.  He gives success to a business and instruction to a friend.  And finally, Hesses creation gives the reader in');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (53, 38, 171, 5, 'So I cheated.  I haven''t read the book, but I saw the movie, and if that is any indication, this is a book in the spirit of A Clockwork Orange and other drug-induced classics.  I highly recommend both the book and the movie to anyone at all interested in the obsessions of drug addicts and their culture');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (54, 31, 43, 5, 'Finally, A Time to Kill, John Grisham''s first novel, is a feature length movie. I just read this book, but I knew it was realeased in 1989. I''m only thirteen, and this was my first Grisham book.  In this story, Grisham hits us with a subject that most might not like to discuss: child rape. Ten-year old Tonya Hailey is brutally raped and almost killed by two drunken rednecks; perhaps the saddest and hardest part to get through with the addition of little Tonya''s dream of her father running to get her. After this horrid crime is committed, Tonya''s father, Carl Lee exacts vengeance on the two rednecks, and kills them. He is put on trial, and lawyer Jake Brigance is introduced to us. He takes Carl Lee''s case and must face his hated enemy, Rufus Buckley, in court. The days leading to the trial are filled with KKK threats, riots between blacks and the KKK, and several other chills and spills. Finally, the trial comes and the small town of Clanton, where the trial is held, is occupated by jou');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (55, 36, 118, 5, 'A serious all-encompassing look at the rags-to-riches versus silver spoon stories as only Jeffrey Archer can do.  This is the inspiring story of two men who have each built vast  media empires and are now battling to save them.   Their   daily decisions are fatally influenced by their backgrounds  as is the intricate network that links them together.  This   book is written by an expert in human affairs who writes an  easily readable and simply incredible novel.  Very highly  recommended.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (56, 48, 142, 5, 'Like Toranaga, Ishido, Mariko, and the other major characters,  John Blackthorne was a real person. From W. Scott Morton (1994, McGraw-Hill), &quot;Japan: Its History and Culture,&quot; pages 118-119:   &quot;It was by a strange accident that he [Ieyasu, or ''Yoshi Toranaga'']   found one of his most valuable experts, a shipbuilder, Will Adams,  pilot-major of a small Dutch flotilla, who was one of the  few survivors of a typhoon which severely damaged the flagship,   the ''Liefde'' [Erasmus]. ...&quot; Adams was from Kent, England. In his youth, he  was an apprentice to a shipwright. Adams warned Ieyasu about Spain''s  and Portugal''s desire to propagate Catholocism into Japan, and said that  other nations (England and Holland) were interested only in trade.   Now, for what became of Blackthorne after Toranaga''s victory at   Sekigahara... he acquired a large estate in Japan, and married a  Japanese woman. Adams never returned to England. He died in Japan,   laden with honors (presumably fro');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (57, 21, 157, 5, 'Welsh''s voice is unique, and some have said that getting through the dialect requires a &quot;near-Olympian&quot; effort. Not so; certainly the glossary which appars in the US version (I read the British one) will help those with no background in Scottish slang. Trainspotting is sharp, funny, horrific and insightful - altogether unforgettable. Don''t miss Welsh''s other collection of short stories, &quot;The Acid House&quot;.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (58, 13, 147, 5, '&quot;Remains of the Day&quot; is the bittersweet tale of a man who placed perfectionist professionalism above his personal desires, living to regret it.... a bittersweet and painful love story. Ishiguro takes the reader into the narrator''s conscious thoughts, leaving the unmentioned unconscious emotions as a subtle, yet powerful aftertaste....although love, desire, and loss are never mentioned outright, the final product leaves the reader feeling the lonely emptyness Steven''s feels, but never admits, even to himself.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (59, 12, 10, 4, 'This is one of those books you''ll read voraciously, then put down and go, &quot;Huh?&quot;  While revealing anything about the plot you won''t read in the first few pages will give too much away, suffice it to say that Clarke''s opinions about the fate of humanity may raise your eyebrow.  You''ll probably either love it, or wonder if you''re time wasn''t wasted.  As I said: fascinating, though not for everyone');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (60, 45, 138, 5, 'From the first page to the last a gripping novel which  keeps you attention.  Marvelous outcome.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (61, 40, 93, 5, 'I picked up this book while delayed for several hours at Detroit Airport, and wow!  I couldn''t put it down.  I read it almost straight through over the next couple of days, and it is one of the best books I''ve read.  Very exciting');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (62, 14, 186, 5, 'Bradley''s Mists of Avalon is one of the best novels I''ve ever read; I''ve given it to a variety of friends with vastly different tastes in reading and everyone has loved it. Reams have been written about the Arthurian legends, but Bradley spins her tale from a different perspective--that of the women of Avalon--and creates an beautiful, enthralling novel. It''s one of the few books I''ve never wanted to end. Her post-Mists books don''t come close to this one');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (63, 17, 127, 5, 'This is a must have for Agatha Christie fans. The novel is equal to &quot;Murder on the Orient Express&quot; in  spellbinding plot. The characters are well developed and you are drawn into their lives. I read this book every summer and I still find it captivating. Even my sister who is not a &quot;Christie&quot; fan was glued to the   TV when the movie version was playing. This is a tough one to figure out but you might get a clue if you read carefully.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (64, 14, 142, 5, 'When I first came across Trainspotting in the fall of 1994 I was reluctant to immerse myself in the graphic protrayal of heroin addicts. After seeing the film on a visit to &quot;Auld Reekie&quot; this spring I reconsidered.<br />  I say to anyone who isn''t quite sure about whether or not to take on the adventure of Trainspotting that it is worth it. Yes, much of the subject matter is dark (comedy) but Welsh''s writing is spectacular, you begin to understand the depths of the human condition and how we get there. (PS- Scots can be tricky but most of the slang can be understood from context)');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (65, 14, 78, 5, 'I say &quot;gripping&quot; because I can''t put the book down.  Ordered it through Amazon a little while ago and it''s AWESOME!  Better than &quot;Icebound.&quot;  If you like Cussler and Clancy you''ll love Koontz');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (66, 10, 57, 5, 'It is my first John Grishams book.  I get the book from my  Australian co-worker when come to US for a meeting.  This  book turns me into a Grishams book fan overnight.   <br />   The book is easy to read but hard to put down.  It forces   my hand to into a page turning machine.  The characters in   the book can be found in real life.  A kid, father, lawyer,   judge, black folks, KKK members and journalists, all run   into each other life and create all the tensions and loves.   It is a good book to read but you will hate it because it    stop you from doing everything else.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (67, 19, 104, 5, 'Burgess himself has criticized and attacked this novel which he published in 1968, but which has come to be regarded alongside such dystopian classics as _Brave New World_ and,  perhaps more appropriately, Yevgeny Zamyatin''s _We_. An  unsparing story of a sociopathic hoodlum, Alex, _A Clockwork  Orange_ is shocking and often a difficult read despite the  bizarre and sometimes surreal street language employed by  its narrator, a dialect of some archaic words, a few   neologisms, and a great deal of Anglicized Russian. The   film by Stanley Kubrick is equally disturbing, but, as   Burgess himself notes in the introduction to this edition,  leaves off the crucial twenty-first chapter, a chapter that  is vital to the book both for its numerical significance  (twenty-one being considered the age of maturity), and its  philosophical poignance.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (68, 30, 170, 5, 'Allen Ginsberg''s Howl is W.C. Williams vision of a &quot;New Measure&quot; made concrete.  It is not only a poem, as such but a lyrical cry  that echoes  throughout the page and the reader''s mind as he/she  lets the words rebound off a boundless  mind/soul.  It is as if Ginsberg broke free from   the word-form lines that confine thought and   let his untampered ideas flow free onto the page  and then just leave them there to reform themselves  in the readers mind exactly as Ginsberg thought  them.  He not only cast his un-strained thoughts   onto the page but also poured them into a mind-  breath mould that allowed them to be measured   by each breath the mind takes, re-inhaling the  glorious fumes with the base repitition of &quot;Who...&quot;  This not only gives the poem a measurable quality but  also an ethereal quality because it is not measured  physically but with each breath of the mind.  The second stanza is one of industrial wickedness  and power-hunger as well as divine-righ');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (69, 30, 115, 5, 'This book has been called the &quot;Science fiction book for people who don''t think they like science fiction.&quot;  Although cliche aliens are there I understand that was intentional and is all part of the overall story. I didn''t read it for the action but it there (in the form of the Battle Room).  It portrays the desperation of a species trying to survive and what it is willing to do to one child (Ender) to accomplish this goal');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (70, 29, 127, 5, 'This book made me a fan of Terry Goodkind, if the first one had not.  It was hard to put down and I finished it in one long weekend.  I have read a lot of Sci-fi and Fantasy but not much this good.  I am totally captivated by the characters, the world they live in and their stories.  The writing is tight and well done, the plot well thought out and the story twists enough to keep you turning the pages til 2 or 3 in the morning.  I am looking forward to more in the third book of the series...I can hardly wait to see what happens next');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (71, 12, 23, 4, 'The Stone of Tears is an excellent sequel to Wizards First Rule, and though I must admit that I liked the First Rule better, the Second book was quite enthralling.  It further probes the love of Richard and Kahlan and reveales valuable insight into our own lives.  2 thumbs up');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (72, 47, 6, 4, 'Having followed Dilbert and especially Dogbert with complete devotion for several years now, I was itching to get my hands on this latest &quot;serious&quot; book by Scott Adams.  I participated in the Dilbert Principle On-Line Trivia Contest and became a finalist...still waiting to hear who won!  This, I believe, qualifies me to say that I have read the book from cover to cover and back again.  The actual e-mail that Adams has received from readers about their work situation (ie corporate culture) and dumb things done by &quot;superiors&quot; is priceless. Adams has a flair for understanding the world of work from the end user perspective.  There are numerous classic Dilbert strips as well.  Some of the chapters are a bit too long and drawn out, but overall this is an amusing book.  I recommend giving it anonymously to your boss for Christmas.  You know you''ll just be recipient of yet another fruitcake!  Besides, the Dilbert Web site is a riot!      DNRC Members: this is a must-read!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (73, 18, 4, 5, 'The summary on the back of the book will tell you that this  is a novel about the relationships between brothers. If you  read the author''s dedication, however, you will come to understand that   this book is Steinbeck''s life''s work and, as such, deals with the subject   that he held most dear. It is a book about man''s concience; a   great book -- one of the greatest I have read, and its epic storyline   is filled with wonderful characters and constant action. <br />    The story transcends three generations, the breadth of the country   and several families and explores its characters and their actions   as only Steinbeck can. Read it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (74, 16, 111, 4, 'This was a thoroughly enjoyable read.  As with most of Dean Koontz''s books, I do not recommend reading it at home alone at night.  In this book Dean Koontz manages to make the characters three dimensional, even  the non-human characters.  As with many of his books, he has included  a dog as one of the main characters in this book, and his ability to  explain canine behavior is very enjoyable.       This book focuses on the escape of two very different creatures from  a laboratory conducting DNA research.  One is a golden retriever with  near human intelligence.  The other is a vicious hybrid creature   genetically engineered to be a terrifying force on the battlefield.  The creature is stalking the dog and killing anything that comes in   its path.  The dog teams up with a paralysingly shy young woman and   a depressed man and turns their life around.  The dog and the couple  are then hunted by the NSA, the creature and a crazed psycopath.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (75, 44, 1, 5, 'This book is a must read for fans of the Eddings'' &quot;Belgariad&quot; and &quot;Mallorean&quot;.  It finally answers all those questions we had about Belgarath, and is written with all the poignancy, warmth,   and humor we would expect in a tale told by Belgarath himself.    I couldn''t put it down.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (76, 32, 184, 5, 'A riveting book. I couln''t put it down until the last page was read! This book is what Sci-Fi should be.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (77, 40, 46, 5, 'The Doorstop''s Here   A hellaciously gifted young writer named David Foster Wallace has just written a   huge new novel called ``Infinite Jest,'''' and somebody really ought to smack him with it.          It takes a special kind of nerve to write a book with roughly the mass of a medicine   ball, and then end it so unsatisfyingly that the poor reader perversely finds himself wishing   it longer. But Wallace''s limp coda only disappoints because the preceding three-and-a-half   inches of ``Infinite Jest'''' have succeeded so well at projecting a world of brain-scalding   complexity.     But when is Wallace carefully teasing out a recurrent motif, it''s worth   wondering, and when is he just repeating himself? Literally from first page to last, though,   Wallace has given us a meditation on addiction -- the addiction of a tennis prodigy to   organic narcotics, of a paroled second-story man to inorganic ones, of the terrorist to his   cause, the couch potato to mindless pleasures, and ultimatel');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (78, 45, 63, 5, 'On the surface, this novel is an unapologetic story  about junkies. But there''s much more to it than that: You''re missing half the meaning of the novel if you  don''t catch the references to Kierkegaard. Ultimately,  the characters are wrestling with the concept of morality.  Renton mirrors Kierkegaard''s spiritual development, but   with a twist. I don''t want to give too much away, so you   must read it yourself. Each chapter is a story unto itself,  full of wit and irony. I couldn''t put it down!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (79, 25, 17, 5, 'The above critique is harsh and unfair. This is (so far, I haven''t read Children of the Mind&quot;) the best Ender''s Series Book. It is much more indepth and thought-provoking than  Ender''s Game, but it doesn''t have the same intense flow of  an action book that Ender''s Game does. The view the reader  gets of Ender in Ender''s Game is only a misleading scratch  in the surface of this caring, human-nature genius. This  book has more originality and drive than Xenocide. Speaker   for the Dead is very different than Ender''s Game, it is not  another &quot;war&quot; book, it is a &quot;serious&quot; book, and definitely  worth reader AFTER Ender''s Game    the adult Ender.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (80, 46, 76, 5, 'Gerald Durrell recounts his childhood in Greece.  His very British, highly eccentric family - and his love of nature - blend in unexpected ways. By turn hilarious and poignant,  the book draws sharp character sketches of the author''s  relatives (including his equally famous brother, the  author Lawrence Durrell).  Sharing the spotlight are the  fascinating flora and fauna young Gerald stumbles across  on his island.  Even if you thought you couldn''t stand   Biology as a student in school, Durrell''s descriptions are  so beautifully written, each discovery so exquisitely etched  that you cannot but wonder at the beauty of Nature - and  the amazing gift of prose that Durrell, a naturalist by  profession, brings to this unforgettable book.  It makes you  thirst for more of the same, and happily for us, Durrell has  written several books.. worthy sequels to this tour de   force.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (81, 13, 37, 5, 'Truman Capote''s novella Breakfast at Tiffany''s is another caseof the book far outstripping the movie in terms of characterizationand content.  Those familiar with the movie will find a much less uplifting experience in the book, but an experience well worth the time.  While I thouroghly enjoyed the movie, the book shows different sides of the characters and portrays more of the angst which is only touched upon in the movie.<br />This book receives my highest possible recommendation.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (82, 29, 121, 5, 'Quite simply, this book is hilarious (in a good way). Reading Wallace reminds me why I can never be a great writer.  I love the right brain/left brain jazz that is  Wallace''s style.  I also just finished &quot;Girl With Curious Hair&quot;, Wallace''s  collection of short stories which is also great.  If you''re scared of the length of &quot;...Jest&quot;, check out his  short stories first.   You''ll be back');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (83, 31, 2, 4, '_Into the Wild_ is a good read, but frustrating. It is part confession, part narrative, and part meditation on what motivates people-- generally young men-- to make  high risk journeys. Krakauer is at his best when he is  able to suspend rumination, and make the imaginative leap  into the queer, bright, grandiose mind of Chris McCandless,  who starved to death in Alaska after choosing to neglect  almost every common sense measure for wilderness survival.  Krakauer''s own autobiographical chapters illuminate his own   long entanglement with risk, but tend to break up the main   story. As with Krakauer''s articles in _Outside_ magazine,  I wished for a strong editor, and one good rewrite.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (84, 25, 76, 4, 'Yeah, it''s hilarious, and yeah, comparisons to Hitchhiker''s Guide are inevitable, but, well, look. Forget ''Who Wrote the Bible?'' because this is it. The first chapter says it  all. The humor is excellent, and the theme of the reality  behind the supposed war between heaven and hell is one that  Gaiman has explored more than once; it''s reminiscent of  &quot;Sandman: Season of Mists&quot; and the short story &quot;Murder  Mysteries&quot; (from the collection &quot;Angels and Visitations&quot;).  This is an ideal partnership and one that I, for one,  applaud.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (85, 34, 119, 5, 'I will simply add to the praise posted here; this book is wonderful. Like another reader who has posted a review, I first read this novel in high school. Not only is it a  beautifully written, evocative novel, but in the wider  perspective it contains a valuable lesson about  historical perspective. What would the pre-Christians say,  if we could hear their words today? This book offers an  answer.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (86, 47, 26, 5, 'Stephen King, The master of horror tells the story of a young family of three who take the loneliest job in the world... Winter caretakers for an isolated hotel with a very colorful hystory.<br />The father, trying to avoid the bottle, the wife trying to be supportive and their 5 year old son.<br />Danny is not a normal 5 year old however... He shines! He has the power to feel people''s thoughts and to project his own thoughts into other minds... But Danny sees more then thoughts in the hotel, he sees other gruesome scenes from the hotel''s history... Blood from a Mafia shoot out, dead people seeking revenge...<BR>But they are not real... They can''t hurt you... That''s what his friend the cook told him... But powered by Danny''s extraordinary abilities... Who Knows...<br />The hotel will do anything in its powers to get Danny''s powers, including turning his close ones against him!<br />Stephen King''s writing is diffrent... The beggining of the book is very slow... But when the situation ge');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (87, 37, 60, 5, 'People keep comparing this book to &quot;A Clockwork Orange&quot;, but I''d throw in &quot;Catcher in the Rye&quot; and &quot;Last Exit to Brooklyn&quot;, yet perhaps with more heart and pathos than any of those. Also an outstanding example of how dialect can work in the hands of a skillfull writer');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (88, 23, 4, 5, 'I think this book is really the best book I ever read. It is both interesting and funny. I have read all of Gerald Durrell''s book and this is my  favorite. Another lovely book by the same author  is &quot;The Bafut Beagles&quot;.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (89, 24, 13, 5, 'Immediately interesting and continuously funny, The Crying of Lot 49 ascends into that small Pantheon of modern American classics.  Full of eccentric characters  and set against the backdrop of an expanding suburban west,  Pynchon displays a tremendous affinity for showing us America  (at its most mediocre) and making us laugh at what we see.  As herione Oedipa Maas travels up and down the Californian coast,  attempting to uncover a bizarre conspiracy, she unravels  a new reality that challenges us to question ours.  With each re-reading, the books yields new meaning, a testament of Pynchon''s deep understanding of language.  Driven by  humor but full of thought, The Crying of Lot 49 is truly a sparkling and fresh novel.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (90, 17, 41, 5, 'Too bad Kennedy is no longer among the living, because he''d<br />still be a hit on Nightline!  The leader of this confederacy<br />lives out the dark side of the mind of most baby boomers...<br /> those of us who wave a &quot;Pre-generation-X&quot; flag.  If you read<br /> this book and don''t smell the sex and used liquor and diesel<br /> fuel from the passing ships and the pastries and sea food in<br /> the air of New Orleans, you must forget the stuff you learned<br /> from Evelyn Woods.  Savor this again now that the images have<br /> fermented for a decade and a half.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (91, 32, 195, 3, 'I cannot tell you how disappointed I was with this book.   T. Goodkind lost the art of combining dialog with  horrifying violence with a purpose going toward an unforseen   yet sensible outcome.  His characters just went a little nuts.   It seemed like the ending was disjointed and left a   lot of details out that needed to be there.  I hope TG gets   back on track with the finale.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (92, 4, 80, 5, 'If either author has ever appealed, read this and snigger. Giving new life to the &quot;The Omen&quot; story of Apocalypse Soon, and avoiding the worst excesses of both authors, Good Omens is very, very funny. At times, the individual authors styles seem to risk creeping out and overwhelming the book, but overall this is a surprisingly cohesive and charming tale guaranteed to bring out the (devils) child in anyone');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (93, 47, 84, 5, 'Many of us found Hesse when we were searching youngsters,<br />filled with a longing that Western thought failed to fill<br />(yes, this was before the Reagan years, before crass materialism<br /> seemed to fill the spiritual void for so many waylaid Americans)<br /> Go back and reread this marvellous story of the Buddha, told<br /> in loving and respectful prose by this German master. It<br /> stands the test of time well, and opens up the door to a<br /> different way of viewing reality, as told in lyrical and<br /> loving language. There''s a reason this book speaks to youth<br /> who are longing: it''s elegant, simple, and rings with truth.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (94, 32, 198, 1, 'The most intriguing thing about Ender''s Game is trying to figure out why it receives raves.  The backbone of the plot can be explained in a sentence and while it  might have supported a short story (the resolution  of the story is predictable half way through)  it''s too flimsy a frame for a novel.  The  no-gray-zone series of leadership-lesson episodes read like Card wrote a story to the  table of contents in a US Army basic training  manual.  My only explanation for the book''s popularity is  that it hit a sweet spot of readers with their hands on  the joystick,   hungry for a rationalization  fantasy for the hours and quarters that they  squander in video game parlors mastering   Missile Command.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (95, 25, 92, 5, 'I was checking on this book because I just recommended it as an acquisition for the library at the community colllege where I teach.  The book describes the life of a brilliant Nobel Prize-winning physicist, and shows him as a completely accessible human being.  He gives a marvelously entertaining account of some of the experiments he conducted while a college undergraduate - all of them completely understandable to a layperson.  But the book continues through his adult life: his attempts to learn Japanese, his experiences as a patron and legal defender of a local strip club, his encounters with military stuffed shirts during WWII, and dozens of other adventures.  If you want to convince yourself or someone else that it''s possible to be a brilliant scientist and a real human being simultaneously, then this is the book.  Both as entertainment and as information, it''s a smashing success');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (96, 34, 27, 5, 'In a simple, yet thorough fashion, Deepak defines the key spiritual laws which are essential to our financial success and personal development.  He provides the reader with a clear road map for applying each of the laws in our own daily lives.  A must read, which could be read in one sitting or periodically picked up and applied at the readers own pace');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (97, 39, 106, 5, 'Excellent book for employees and bosses - there may even be some real (scary) wisdom between the cartoons.  On days that life in the office is getting you down, or if you ever fear you''re taking life in the office too seriously, this book is a sure antidote.  And, laughter is after all, the best medicine.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (98, 40, 143, 5, 'This is not a typical Marion Zimmer Bradley book.  Although I''ve enjoyed all of her books, this is the one I''ve lost over 10 times &quot;lending&quot; it out to friends who never returned  it.  I have to keep re-buying it, since it stands up so well  to repeated reading.  The Arthur legend has been retold so  many times, but never like this.  Forget the other versions.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (99, 33, 145, 5, 'Bill Bryson is a traveller''s travel writer. Not content to  follow well-worn tourist trails, he blazes his way across  nations by the seat of his pants.  This is no dry,   philosophical tome on travel and its affect on the psyche,   or an author attempting to ''find himself'' while on a daring  journey.  No, this is the story of Bill Bryson stumbling his   way across Europe, encountering all manner of misery, joy,   and hilarity along the way. Written in an uproariously funny,  conversational tone, ''The Lost Continent'' will make your sides  ache with laughter as you read (and re-read) it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (100, 18, 60, 5, 'WOW!!  This book examines love, heartbreak and rejection in such a clear concise way that you realize that Mr. Hornby has finally articulated, and beautifully, the buzz of feelings in your heart and head.  I give this book to all my friends.  I eagerly look forward to his next book');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (101, 11, 83, 5, 'This book quite ably demonstrates the stoic foundations of both Buddhism and Christianity.  To the reader who carefully reads it and follows its principles it offers both clarity  of vision and inner peace.  Regardless of your religion, it  would be difficult for this philosophy to violate any of its  precepts.  The dominate themes of love, forgiveness,   non-judgement, and lack of condemnation found in both Buddhism   and Christianity texts are stressed without any pretenses of  understanding the after-life.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (102, 44, 26, 5, 'By far my favorite book of all time.  I was gripped from the first chapter many years ago, and the characters have become a part of me.  This sounds odd, but  Koont''z characters in this book seem so real that life seems a disappointment when you put the book down.  By far the best of Dean''s works, I reccommend this to all friends, family and even strangers such as yourself');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (103, 14, 164, 5, 'This was a Booker Prize winner (1992?).  I was prepared to dislike it--seemed a little too introspective for my tastes (not to mention I usually avoid WWII stories).  What a pleasant, if unsettling, surprise; this book is marvelous.  The writing is sensuous, the characters dramatic, and the setting surreal. The book opens with Hana, the war-fatigued nurse, left behind (by her choice) after the evacuation of the Allies from Italy.  She has seen so much death and so much devastation that she cannot move on with her fellow nurses.  She throws away her uniform and cuts off her hair and settles  in to finish the war in her own way.   Hana is caring for a man she presumes is English, but who is so badly burned that he has no identifying features.  He is an encyclopedia of knowledge of Bedouins and the desert; he quotes from Herodotus frequently, and he has thorough understanding political forces behind the war.  He cannot move but is dependent on Hana to relieve his pain, feed him, and read ');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (104, 46, 165, 5, 'Hey, I''m female and I loved this book.  I thought it was very funny and actually quite sweet.  Sure, the guy was kind of a dope, but aren''t we all?? (women included!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (105, 49, 146, 5, 'Ubik is Philip K. Dick''s wonderfully satiric look at reality, psychic abilities, and advertising.  The book follows the trials of the members of Glen Runciter''s company as they try and figure out who died in a bomb blast.  Things are never as they seem as various members try and understand what happened.  Dick again crafts a truly unique story that is full of wit and discussion on the nature of reality.  He also pokes fun at advertising as the characters search for the mystical substance Ubik- the cure for all of their worries.  Dick manages to keep the reader guessing and involved pretty well.  There are times when things get very confusing, but rest assured all makes sense by the end.  This review, like Ubik, has been informative and safe if read as directed');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (106, 45, 194, 5, 'I have read many, many books.....varied in nature, and this  is singularly the most enchanting and mesmerizing one ever. My mother, who passed away 13 years ago, had told me over  and over that I would love this book.  It took a stranger  recommending it to remind me that she had so wanted me  to read and enjoy it.  It is the only book that I have ever  finished one day and immediately started rereading the next. If you don''t love this book, you are missing out on some  magic in your life!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (107, 22, 187, 3, 'I have read &quot;Ella Imagina&quot; and  &quot;Tonto, muerto, bastardo e invisible&quot; and this last one &quot;El desorden de tu nombre&quot; was a real dissappointment. It is easilly read, but it is a very predictable book.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (108, 39, 172, 5, 'Written in an engagingly familiar way, but full of informative and interesting facts about the complexities of English.  Essential for anyone who has an innate curiosity interest about the origins of the way much of the world''s population speaks and writes');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (109, 32, 117, 5, 'A fast pace page turner. The story is simple but Grisham wrote it in such a way that the suspense kept readers on the edge of their seats. The ending is predictable, as in many other fictions, but it is still worth the readers'' time to finish the book. Real life lawyers might find the story a little difficult to believe but for the general readers, don''t miss it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (110, 47, 171, 5, 'This is an excellent book written by David and Leigh  Eddings.  This book fills in the gaps of information left out  of the previous two series, the BELGARIAD and the MALLOREAN.   This book recounts the tales of the ages before the events of   the other two series through the eyes of Belgarath the    Sorcerer.  This book is intended to be read after the other   two series, since much of the finer details will be missed by   someone new to the series.<br />    This is also the first book to feature David Eddings''    wife Leigh, as an author.  In the beginning of the book, Eddings''   explains that she was always an author, but never recognized.<br />    All in all, this is a great book.  To anyone who has    read the first two series and feels unsatisfied with the explanations   of anything, or to anyone who wants to know more about Gods,   or the brotherhood of sorcerers, or even the beginning of empires, this is the book to read.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (111, 45, 171, 5, 'I have read all of Grisham''s books, and this one is by far the best. The characters and situations are captivating and exciting');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (112, 29, 10, 5, 'AS always WWII for one who dadn''t directly experience it, looms myth-like in clearness of intent. Perhaps without extraordinary language the story shines brighter in it''s testinment to our humanity.  The authors objects are aways clear that he didn''t undertake this voyage for a noble reason but for a precious gift of understanding oneself.  I stayed up all night, granted I don''t sleep well,  this book make me glad of the insomnia');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (113, 28, 7, 5, '_The Mists of Avalon_ is one of my top five favorite books  of all time.  For me, this has become the true story of the  legend of King Arthur.  It is told through the eyes of all   the women, but mostly through the eyes of Morgaine (Morgan   La Fey), Arthur''s half sister.  Other Arthurian stories make   her out to be pure evil.  Here Morgaine presents her point   of view (as well as that of the other major women).  And   what a fine job she does of it.  The story pulls you in and   the pages just fly by.  Bradley draws her characters with   such detail that I felt strongly one way or another about   almost every one of them.  I have never been so sad when the   book came to an end and I had to leave this incredible world.    I recommend it every chance I get. It''s a magical experience.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (114, 15, 161, 4, 'You can read the rest of the reviews for a discussion of the plot, characters, etc., but the way I read it best describes  it.  I used it as a soporific at night, and eventually got to   the point where like an addictive sleeping pill, I couldn''t   skip a night without tossing and turning.  I have eighty pages   to go, and I''m beginning to worry about what will happen   when I have to go cold turkey.  Maybe like an earlier reviwer,  I''ll have to maintain the addiction and read it again, looking   for the seeds and stems.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (115, 23, 65, 5, 'Einstein wrote a book for lay people to explain the  theory of relativity.  I''ve read it twice, and I still don''t know what Albert''s talking about.  Ansel Adams wrote   three books on photography, The Camera, The Negative, and  The Print, for lay people to explain how to take   good photographs.  I''ve read ''em all, and at least  I know what Ansel''s talking about, even if I can''t take  photographs like his yet (gimme fifty years of practice).  Whether you like Adams'' style or not, in technique, he  is to photography what Einstein is to physics: a single  authoritative master who''s work can be relied upon.    Of the three books, _The Negative_ is the most important;   but if you are just getting started, the Camera is   where to begin.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (116, 34, 9, 5, 'I was so impressed with this book that I went out and immediately bought twelve copies and shipped them to friends all over the country so they could share the experience with me.    The history of philosophy interspersed throughout this book is amazingly accessible and thoroughly readable.  The plot within a plot within a plot engages the reader from the very first page driving you on to find out what will happen next to the incredible cast of characters.    My only regret is that I will never be able to have the experience of reading this book for the first time again');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (117, 18, 85, 5, 'I throughly enjoyed Seth''s A Suitable Boy.  He follows the story of Lata, a young Indian woman whose mother feels is  now ready to marry.  What Lata will have to face is whether  she will marry for love or marry the man chosen by her   family.  Seth combines romance with the history, politics  and religion of India to make a very enjoyable glimplse of  life for this young woman and the people around her.  While  Lata is the focus of the story, he has several side stories  that help to give a better picture of their life in India   and of the complexity of the decision that Lata faces.  I   found it very difficult to put this book down at times and   once missed my train stop because of it.  I highly recommend  to those who would like to learn about India and enjoy a   good story in the process.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (118, 4, 132, 4, 'Through solid research and observations made in her own therapy practice, Dr. Aron uncovers the facts about being highly sensitive. It does not mean being a crybaby, a 90-pound weakling or a scaredy-cat but rather possessing a sensitive nervous system -- an inherited biological trait. This book is about the 15 to 20f us who experience life at one end of the human spectrum. Highly Sensitive People (HSPs) process sensory input more finely and to deeper levels than average.Being aware of subtleties in your surroundings can be a great advantage. It may also mean that stimulating environments can bombard an HSP''s system until s/he is exhausted. This trait, like any other, clearly has advantages and disadvantages.Dr. Aron addresses the impact of cultural ideals on the life experiences of HSPs by examining learned coping behaviors, common experiences and the self esteem struggles of those who have been constantly chastised to \\\\"toughen up.\\\\" While providing practical advice on crafting a l');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (119, 34, 31, 5, 'I think I may have made a tactical error the other day when I told my boss that my career goal was to win the lottery.  But last week I read The Razor''s Edge and ever since I''ve been wondering what made me think that work was so important.  Here''s the story:  Larry Darrell is a changed man when he returns to Chicago after serving in World War I.  During the war he witnesses the death of a good friend and comes to the inescapable conclusion that life is too precious to waste.  Armed with this insight, he alarms his friends, family and fiancee when he turns down the plum job and heads to Europe to begin the great adventure of his life.  From the coal mines of southern France to a lama''s monastery on a mountain top in Tibet, Larry Darrell steadfastly resists the pressure to succumb to the societal norms of money and career and instead pursues the meaning of life with a single-minded intensity and a touch of grace.  So how are you going to live your life?  Have you had that gnawing feeling');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (120, 49, 81, 5, 'Ender''s Game is the most riveting and moving sf novel I  have ever read. For me, it was impossible to put down and never  rang a false note. The ending gave me goosebumps. I believe   that this book is the standard against   which all pure sf should be measured. (Fortunately I do not   write pure sf myself, but as a new  novelist I''m both awestruck and jealous of Orson Scott Card for having  written such an amazing story.)  James Halperin');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (121, 18, 103, 5, 'In this work of Eric Lomax, one finds direct contrasts between brutality and meekness, revenge and forgiveness. The author was a signals officer in the Pacific Theater of the war and  was captured after the fall of Singapore. He was then sent to  the POW camps involved in the construction of the then Siam-  Burma railway (Remember the &quot;Bridge Over the River Kwai&quot;?).  There he had first-hand experience of the Japanese''s brutal  treatment of POWs, himself included. He never forgot the face  of the Japanese interpreter accompanying the soldier who beat  him to a pulp. He narrates how he had to cope psychologically  with normal life after the war, how his wartime experiences  kept on haunting him. Coincidentally, he chances upon some  information regarding a Japanese trying to make reparations  for his wartime brutalities, and indeed confirms that this  was his former tormentor. After a lot of soul-searching, he  finally meets the Japanese in a war memorial beside the Kwai  River');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (122, 41, 72, 1, '<br /> Although the pro-ecology message in the book is good, I have serious doubts as to the authenticity of the story. I am an Australian, I lived in the bush with Aboriginal people when I was a boy. I studied Aboriginal art, history and material culture at University and I now work in a programme devoted to training Aboriginal people. These people are my friends, I know them. <br /> This book reads like one of the 18th century travel novels, i.e Gulliver''s Travels etc.. Not in the quality of the written word but in the vagueness of the tale and details. The country that is said to be Australia could be any ex-colonial nation. The people could be native American or African. The details of Aboriginal culture that are thrown in are clinical in a way that makes me think they were copied from the same texts I studied from. <br /> The lack of any place names, store names etc, those little details that mark the quality travel books, is explained away by a need to protect the &quot;real peop');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (123, 49, 93, 5, 'A political history masterpiece. No other Secretary of State is as good prepared and culturally fit as him');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (124, 4, 73, 5, 'It opens your eyes to a new way of seeing and perceiving other men and women.  I discovered I have some women traits and it helpmed me to learn more about myself and how I can improve my working and pesonal relationships with women.  As a male I always thought that I had only male traits as other men do but it''s nice to know that I can be comfortable with my female traits!  Thank you so much, John Gray');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (125, 22, 198, 5, 'Neil Gaiman''s extraordinary storytelling abilities combined with Terry Pratchett''s sense of humor makes this the funniest book you will ever read.  To merge two great talents into something even greater  is the hardest thing to do.  But Gaiman and Pratchett''s many phonecalls over the atlantic  ocean payed off big time.  If you want a great story and a thousand laughs this is  the book for you.  If not, why do you read books?');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (126, 42, 19, 5, 'An elegant short novel, filled with simple and timeless truths about our universe and its inhabitants. If you enjoy sharing stories, this one is a delight to read aloud to audiences of all ages.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (127, 25, 16, 5, 'Contrary to most expectations, I did not read Eddings'' Belgariad and Malloreon series first.  I had always been turned off by the sheer number of books in each series.  How good could they be? <BR> When Belgarath the Sorceror came out, I took the opportunity to get a feel for Eddings'' work without having to plunge into the entire series.  While I missed a lot of the &quot;present time&quot; references, I still thought the book was fantastic.  Over the next two weeks, I read the entire Belgariad and Malloreon, then went back and re-read Belgarath with a whole new appreciation. <BR> This series is not to be missed by any fan of Feist, Brooks, or Goodkind');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (128, 27, 93, 5, 'A young girl''s common existence is interrupted by a  strange journey through the development of western philosophy, from the first mythologists to modern nihilism. As Sophie learns from a mysterious mentor, every new reality gives way to to another. Gaarder elegantly questions perception in a manner that would make Kant grin. Sophie''s World is rich with ideas and entertainment. Anyone who has believed that philosophy is inaccessible should take trip to Sophie''s World');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (129, 3, 80, 5, 'I first read &quot;The Right Stuff&quot; over 10 years ago and I<br />typically re-read the book every two years.  Tom Wolfe has<br />produced one of the best looks at manned flight starting<br /> from 1947 and the breaking of the &quot;sound barrier&quot; up to the<br /> end of Project Mercury.<br /><br />  The chapters are well thought out, from the beginning in<br /> which we learn that the mortality rate for test pilots in<br /> the 1950''s was 24%(!!) to the chapter that explains why all<br /> airline pilots sound alike, to the description of Chuck<br /> Yeager losing control of a Starfighter at over 100,000 feet.<br /><br />  I cannot recommend this book too strongly.<br /><br />  Dave Zechiel');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (130, 19, 81, 5, 'Talbot presents a new, exciting and plausible paradigm of the mind and universe. His arguments are logical, well presented, and based on the very latest findings in science. Through many examples, he illustrates how what are considered inviolate laws of the universe are broken regularly. The reader is drawn to the conclusion that all things are possible, and limitaions are of our own making');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (131, 35, 24, 2, 'The weakest of Grisham''s stories, this one reads as if it was written to be the Sunday night &quot;made for tv&quot; special --- doesn''t even make the big screen! The character development leaves us with nothing more than caricatures. And the  only satisfying part about the ending was that the story was over.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (132, 30, 185, 5, 'I once worked in a thriving bookstore whose primary source of sales came from romance novels.  I mean cheap, tawdry, breath- less stuff with Fabio on the cover; I couldn''t bring myself to  read more than two pages without laughing.  It was a shame,  too, because I''m as romantic as the next person.  SO imagine   my shock of delight when I ran across a REAL romance, with  images that resonate as deep as an ocean, written in English  that best represents the state of modern literature.  Canadian  Michael Ondaatje''s lyrical and disturbing tale of four wounded  lives at the close of World War II and the memories of loss and  hope that flicker across the pages is a book to be read out loud,  a book that inspires through its sheer force of poetry.  It has  all of the intrigue and wonder of a romance, but without the  guilt; this is a tale of love for adults.  Forget those nice  little novellas about geriatric passion and read passages that  can illuminate corners of your mind, those opinions ');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (133, 22, 133, 5, 'Watership Down is a beautiful story.  The adventures of a few rabbits  from Sandleford Warren is told with great interest and much character.  It is purely a classic and deserves a perfect 10!  Hazel, the leader   of a group of outcast rabbit, leads the party trying to make the right   decisions to keep them safe.  They faced perilous dangers and must   learn to get along.  Together they make it to their new home, but what  will happen next as they face the dreaded General Woundwart and his   Warren?  It''s all in this epic tale of leadership, heart, and bravery.  It will surely dazzle the hearts that are touched by this book.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (134, 34, 171, 5, 'An amazing collection of the foibles and predilictions of the modern business world.  It extends, amplifies, and corrects the concepts presented in the Peter Principle. Workers after rising to their level of incompentence are promoted into management where they will cause less harm. The book is a compilation of incidents observed and made known to Scott combined with appropriate Dilbert cartoons.  I could not put the book down but was afraid to let it be seen in my cubicle.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (135, 3, 106, 5, 'This book leads you down a path into a world of mystery, suspense, and romance. You witness the journey of young Walter Hartright, a drawing master, as he meets the Woman in White, Marian Halcombe, and falls in love with Laura Fairlie. His love for Laura and concern for the Woman in White compel Walter to find out the Secret that could ruin the evil Sir Percival Glyde, the accomplice of the enigmatic Count Fosco. I love this book because of the endearing characters, clever villians, and numerous plot twists');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (136, 37, 59, 5, 'A wonderful read.  It read better than most &quot;page turner&quot; novels. With a clear consise style, Lomax illustrates deep truths- The horrible brutality of the Japanese prison camps, the agonizing will to survive, and the amazing capacity to forgive the most heinous of  wrongs.  Read this book');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (137, 18, 70, 5, 'I found this book both incredibly easy to understand, and surprisingly complex. It started out slow but interesting, and quickly became more and more compelling.  The way that the two people''s lives slowly became entwined really got to   me...I found myself wondering who existed and who didn''t. The story left me   with many questions, both about the book and myself. I would recommend it to   anyone who was willing to read about such a confusing topic.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (138, 14, 6, 5, 'This is among the best books I''ve read in recent times;<br />both within and outside the genre.  The characters are<br />believable and multi-dimensional.  The plot develops<br /> at a spanking pace with enough twists and turns to keep<br /> you guessing.<br /><br /> I await the second volume with great anticipation.  This is<br /> up there with Jordan''s Wheel of Time series.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (139, 21, 53, 5, 'Open the book and you are plunged into another world, peopled by shattered humans who will rouse you from the complacent present, and draw you inexorably to their world of suffering and (sometimes) redemption. Filled with incredible details, written with grace and knowledge, you cannot help but be caught up in the lives of these mysterious survivors. There is much to learn in these pages, and Ondaatje is a marvelous teacher. The story flows seamlessly along until the last few pages. There it unaccountably falls off track, into an incongruous jeremiad against racism, which contains a vital message, but seems artless and contrived. The ending in no way detracts from the grand achievement of the book, which will linger in your heart for years');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (140, 35, 6, 5, 'Just finished reading it for the second time and I still  think that this book should never find its way into the hands of a woman!  Tremendously funny and insightful novel.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (141, 16, 49, 5, 'The detail and the sheer enjoyment of the thrilling adventure put me on a high for a week.  Though I have read this book  several times before, and loved it, this past time, I took  my time reading it.  Though it took me about two weeks, I  read every word, and was really able to take in the perfection   of Richard Adam''s work.  This is to date the most wonderful   work I have ever read.  Shardik''s next.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (142, 23, 131, 5, 'As an Intern in my first year of residency training, what Shem writes about is at times familiar, comfortable, and occasionally, outrageous. Although medicine has changed dramatically in the years between which Shem wrote this book, he touches a common thread which all physicians face during this pivotal time in their careers. Deep down, his story embodies the human struggle for acceptance and understanding in the complex field of medicine. On the other hand, the cynicism he presents should ask us to examine all physicians as what they truly are - fellow human beings - with all  the foibles and fallacies that this condition entails');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (143, 49, 33, 5, 'One of the few books I''ve ever read and movies I''ve ever seen where I &quot;experienced&quot; the feelings, the emotions, the highs, and the lows for each and every character.  I &quot;lived&quot; each person''s life and enjoyed every minute of the time I shared with the To Kill a Mockingbird cast, both reading and watching');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (144, 20, 80, 5, 'If you''ve ever designed an OO system and fell into the same traps and gotcha''s, this book will save you.  The 23 design patterns detail solutions (and caveats) to some of the most common computing problems.  And you''ll never be without a buzzword or phrase to stymie the newbie OO developer');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (145, 13, 49, 4, 'The optimal flow model is an excellent conceptualization of our search for happiness.  However, the exemplars of this model include the Nazi war criminal Eichmann, which made me question mine and the author''s notion of happiness');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (146, 38, 166, 5, 'I read this book on a plane trip and I aplologize to all those passengers who heard me laugh out load so many times.  This book is in a class by itself;  insightful, humorous and intelligent.  A must read for anyone who has worked for a large, beauracratic company.  Recent collede grads beware!  You might learn something useful from this book');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (147, 19, 32, 5, '<br />Perhaps a few hundred years from now, critics , students and teachers of history and literature will recount this book with great passion and the effect that it had on the people of the 20th century who read it. <br /> The Book sets out to prove a single point and in the authors own words it is: &quot;Man''s Ego is the Fountainhead of Human Progress&quot;.<br /> A Man who stands for himself and what he beleives in usually stands alone. That is the way to live, the reason for creation and the only human morality.  Ayn Rand in this book defines the true meaning of human ego and what it takes to be a true egotist. A good thing &quot;ego&quot;, not a bad one.  <br />I for one is someone who has read the book and for the most part beleive in it''s presentation, conclusion and application of the ideas presented in the book in real life.  Whether or not you fully agree with the principles presented in the book, it is a must read if you fulfill one criteria.. you must be a human');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (148, 48, 103, 5, 'This is by far the greatest book I have ever read, blowing<br />away any &quot;Great American Novel&quot; or Shakespearean play for<br />both depth of plot and riviting story line.<br /><br /> In addition to it''s pop culture standing as the difinitive<br /> title concerning mafia life, this book teaches valuable<br /> life-lessons as applicable in New York''s rough streets as<br /> in the Heartland.  Puzo''s definition of family and duty are<br /> among the most valid and vivid since Vergil.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (149, 48, 167, 5, 'Orson Scott Card''s novel, Ender''s Game, is one of the most  exhilaraiting books that I have ever read.  Not only does it  draw you into the life of an amazingly bright child who must   save the world, but it captures you in a world that is unknown  and mystifing to the common man.  This is definately one of   the greatest science fiction novels ever written.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (150, 45, 199, 5, 'My brother, whose library generally begins and ends with accounting, medical journals, and organic gardening tomes, recommended this book to me.  Reluctantly, I read it as he kept asking me if I had.  AND I LOVED EVERY MINUTE.  Which goes to prove that truly great books transcend all things -- even the abyss between a liberal arts major and a CPA/physician/farmer!  I laughed aloud countless times.  It is a shame that the author did not live to see his success, but somewhere I know he has the angels in stitches');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (151, 3, 34, 5, 'Don''t let the title mislead you.This is not Tom Clancey''s latest novel about the Red October sinking. It is though just as exciting an adventure as you would hope to read.This extremely well written book corcerning a group of rabbits and thier variety of animal and human friends and enemies is throughly absorbing.It should plant the seed of imagination for both adults and children alike');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (152, 24, 195, 2, 'I feel like I''m swimming against the tide writing a  negative review of this book,  but in all honesty I  didn''t really enjoy it.  I found the characters to be   very one-dimensional.  All of the Christians were stupid,   dull and brutish.  All of the goddess worshippers were   gentle, wise and interesting (unless they became Christians   in which case they became stupid, dull and brutish).    The idea of writing an Arthurian romance from a women''s   perspective was a good one, and some of Ms. Bradley''s  twisting of the legend was well done, so I haven''t given  it the lowest review.  However, I certainly wouldn''t  recommend it to my friends, or be tempted to reread it.   In the future I''ll stick with Mallory for King Arthur,   and with Katherine Kurtz for fantasy.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (153, 25, 69, 5, 'Ender''s Game is an AWESOME book, and I think that n e 1 who thinks differently had better go get their head checked (no offense, of course).  <br /> ''Nuff Said!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (154, 32, 17, 4, 'Grishams experience of struggling through law school was so accurate that it brought back a flood of my own memories of school.  Willing to take jobs no matter how sleezy they were.  For anyone who has dealt with an Insurance company, this novel brought back very vivid memories of dealing with the slimmest business in the world.  The struggle and conflict of the main character gave you moments of joy, sadness, fear, and anxiety.  John Grisham had is very best novel, in my mind, until he gave up on the novel to meet a deadline.  Meet a Deadline, is the only excuse I can come up with for the lame ending of this novel.  In the ending, the main character, who would be fine role model for any attorney to acheive, kills a man.  Come on Grisham, you are my favorite author, ask for the book back from the publisher so you can rewrite the ending.  Either that, or give back part of the $6 million given for the novel, or better yet send me a check for $25, the cost I paid for the worst ending of a');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (155, 30, 92, 5, 'Yergin''s grasp of the broad view of the history of oil and its context in world history is amazing.  Scholarly and yet as compelling as the best fiction, this book is a masterful work');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (156, 25, 55, 5, 'This book is an amazing collection of Beatles Scores.  Every song the Beatles recorded is included here, including the early Rock and Roll covers.  The scores are transcribed exactly as recorded, including Guitar tabulature, altered tunings, piano parts, and string parts.  Occasionally large sections are reduced to a single staff, such as the orchestral part in A Day in the Life.  Each song is prepared by hand yet the look is entirely readable, and beautifully done.    If you are a musician interested in Rock music, this book is a must.  Definitely worth its $60+ pricetag.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (157, 43, 181, 5, 'I don''t often cry because of the power of a book.The Bell Jar, however, is no ordinary book.  From thebeginning, in her Salinger-esque style, Sylvia Plath traces the tortured downward spiral of her own soul, the story made ever-so-much more effective by the heartwrenching true tale of her own suicide. A wonderful book, suitable for the young, the old, and  everywhere in between; NOT, however, for those afraid to reflect on their own depths and faults, and those of society.                                  -Anthony Gabriele');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (158, 49, 99, 5, 'The anticipation for this book had almost crippled me.  When I was finally able to read it, I couldn''t put it down.  The immense amount of history that is contained in Diana''s books, are absolutely breathtaking.  Her descriptions take me from my home straight to Claire and Jamie.  When reading a historical novel I sometimes skim the paragraphs before the interesting information, but with Diana''s books I read every word, every paragraph and digested it as a rare and exotic meal.  From the moment I opened Outlander to the time I closed Voyager, I have lived in another world.  I am sure that my husband was very thankful for the hiatus.  Bravo Diana!  Encore!  Your devoted reader, Nedr');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (159, 31, 29, 5, 'Ms. Morgan found herself in the Austrailan Outback with a tribe of Aborigines on the adventure of a lifetime.  For 4 months she lived with this particular tribe as they prepared her to receive from them their many secrets.   At the end, she had learned many things about the tribe and herself.  She became more like them and was constantly amazed at the things she was learning.  In the end, she was given many secrets of the tribe, which spoke to many problems in the world and the need for them to be addressed.  They selected this particular author, because of work that she was doing with other Aborigines in Austrailia and they thought that she would be a good person to spread their message.  She learned a lot and I did to just from reading the book.  Enjoy');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (160, 24, 36, 5, 'The best analysis of the medium. Just that. And that is the reason why I wanted it in Italian too. So I looked for a publisher and now you can find it in Italy. Take a look here [...] to see the Italian edition.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (161, 38, 122, 5, 'Frank Herbert takes you on a voyage of discovery that is unparrelled. His explorations of politics and religion are enlightening. Anyone would thoroughly enjoy this wonderful book');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (162, 17, 166, 5, 'Again the author has not let us down spinning her continuing tale of Claire and Jamie.  This is a book that I could not put down, I had to know what was going to happen to two people I already genuinely cared about.   Not withstanding, the rich historical content of this novel by itself is obviously painstakingly researched and I find my self learning many things about Scottish history.  I am eagerly awaiting the book, Drums of Autumn, due out in January of 1997');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (163, 28, 191, 5, 'The intersteller battle domes, the armies of teens and children, and the brilliant aray of technology incorperate together to make one of the best books for adults and  children written this decade.  The story of a boy passing  into manhood is, in my opinion, one of, in not, the best  novels in Sci-Fi.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (164, 17, 18, 5, 'A monumental tome but worth wading through.  The list of characters can get almost baffling at times but David Wallace keeps up a breakneck pace for most of the thousand pages in this monster.  Irreverence, intelligence and wit live on in the younger generation');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (165, 23, 190, 5, 'This is an amazing book and one that is essential to anyone interested in communicating ideas visually.  Would love to hear McCloud''s take on the Web');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (166, 24, 75, 5, 'The best book written on the Indian wars of the west. One of the few books supporting the Indians cause');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (167, 28, 59, 5, 'Angela''s Ashes is a captivating and compelling journey  through an Irish childhood that is both sad and funny;  at times I was not sure if I should laugh or cry.  Frank   McCourt''s ability to step back into the shoes of his   childhood is truly remarkable for its clarity of insight,  and I would recommend this book to anyone who has grown   up either Irish or Catholic or both.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (168, 33, 178, 5, 'The author''s findings might well be taken into consideration by virtual reality and video game developers, since &quot;flow&quot; is a neurophysiologic event which may be potentiated by external stimuli.  Flow is about being fully engaged - which can result in happiness, but more important, satisfaction, fulfillment, self-realization');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (169, 20, 151, 5, 'The impact of this book on the reader is incredible. Pirsig is like a weaver who combines philsophy and keen insight into a wonderful tapestry depicting modern American culture and a  new way to go. A must have on any bookshelf.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (170, 35, 76, 5, 'As an avid &quot;road-tripper&quot; across the United States, I found Bryson''a account to be both accurate and hysterically funny at the same time. My husband and I actually spent several weeks reading chapters aloud to one another each night before going to sleep. I passed the book on to several friends who had not travelled to many of the places Bryson explores, but who came back to me with high praises nevertheless. For anyone who truly appreciates the distinctly different flavors of our nation''s cities and regions, this book is a pure treasure. Thanks to Bryson, those of us who have been to Des Moines, Boston, Philadelphia and Los Angeles, can relive many of our own observations at the time. And, for those who haven''t been to all these places yet, Bryson seems to give just enough description to make you desire to experience it all first hand. Delightful');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (171, 49, 161, 5, 'Scott Adams has reviewed the Peter Principle and put it in  context for today''s world. What is more he keeps up the  tradition of Northcote Parkinson by teaching us how to   become managers, and keeping it outrageously funny. This is   not a book about becoming an effective manager. It is all   about becoming a successful manager. And it''s all about  workplace situations we all know so well.   I first read a few pages of the book at Barnes and Noble  and soon attracted stares from all around when I was  rolling in the aisles, doubled up with laughter.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (172, 17, 113, 5, 'DAHL IS AT HIS BEST.A CHARMING VIEW ON THE LIFE OF A CHILD');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (173, 45, 76, 5, 'Michael Ondaatjee''s &quot;The English Patient&quot; is a stunner. This writer is  a master story teller.  Be patient and pay  attention to detail as the carefully woven plot is revealed.  His is a style that is totally authentic, free of artifice  and of any straining for effect.One of the most competent of  contemporary Canadian authors.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (174, 33, 187, 5, 'Marilyn''s fan or not if you like the women or want to know the unsolved mystery about the night of august 4, 1962 you must have that book in your library.  What can I said more about  the Spoto Marilyn...as a Marilyn  fan who have more than 100 books about her this is the   best story of her live that I ever read! Try it, you won''t  be dissapoint!  Edith Robitaille, Quebec.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (175, 27, 160, 3, 'This one picks up a year later where the last one left off. After a year, young Jamie is living in a clinic, unable to speak, the result of the prior Halloween night. As her step-sister, Rachel, and her friends are murdered, Jamie is forced to take a stand, alongside old friend Dr.Loomis. As the story takes place, a mysterious &quot;Man in Black&quot; appears, showing a dark side to his nature and once again preventing ultimate peace in the tortured town of Haddonfield. END');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (176, 28, 20, 5, 'I first read this book when I was a teen, reread it in my early twentys, again a few years later, and most reciently, at the age of 42.  Each time, a new discovery, and new feeling of triumph.  It has been at the top of that &quot;must read&quot; list that exhists in every avid readers mind, the list that every new aquaintance must listen to at least once.  The list that starts &quot;Oh, if you like to read you MUST read.....&quot;  Always number one on my list since that first accidental discovery (It was a last minute grab in the school library as the bell rang..) Watership Down has given me untold hours of pleasure, both in the reading and rereading, as well as the sharing.  Not a person alive should allow themselves to forgo the pleasure of &quot;Watership Down&quot;');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (177, 4, 148, 5, 'In the scene where Atticus leaves the courtroom and the child ren are told to rise in their father''s honor along with the black people, I tear up everytime.  I find it to be a quiet  memorial to his diligence in the name of justice, truth,   honesty, dignity and the equality of all.  It is a show of re  spect for a man of immense honor and fairness.  It is an act  of quiet desperation in the face of overwhelming injustice,  prejudice, racism and bigotry.  It is all they can give to him  but it speaks volumes.  I share the novel each year with my   10th grade students and each year, they say, &quot;I love this book&quot;.  I am honored to be in the presence of students who perhaps for  the first time in their lives &quot;feel&quot; the injustice and prejudice  that far too many prople have been subjected to for numerous  reasons.  I also love the evolving maturity and love in the  unusual Finch family.  I see the family representing many feel  ings that are unspoken in my students'' eyes');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (178, 23, 12, 5, 'My therapist lent me this book to read at a time of crisis in which I had no sense of self-worth. I was suicidal. There were many instances descibed in this book where I found similarities in my emotional make-up although my sufferings were no where near that dramatic and &quot;hopeless&quot;.  In the words of Nietzsche : &quot;He who has a WHY to live for can bear any HOW,&quot; I found peace within chaos.  Although I did not understand some of the more difficult arguments, the book set me on the path to find  my own meaning of life and the courage to live. I think that the meaning of life need not be one thing or   action but can be several but I can only think of one thing now. The meaning of my life now is to  touch the people I know or care about in the most tender and deep way I know how. And to see them happy even  for a brief moment by what I do for them is quite enough. And everyday is a new day and there is opportunity  me to do something positive in my own ways.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (179, 29, 31, 5, 'Still greiving for Paul, Honor finds a new home on Grayson.  And, once again, Honor takes on all-comers to do the right thing.  Defending her adopted home of Grayson, she and Grayson''s small Navy, hold their own against an invasion by the People''s Republic.A great read.  Make sure to check out the entire series.  David Weber is a great story teller');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (180, 29, 122, 5, 'A dark, disturbing, and fully engrossing novel that is unlike anything ever written. Its colorful use of language, imagery, philosophizing, and gruesome detail is used in liberal doses throughout, and an exceptional and coherent story shines through a complex surface.  I have to say the bottom of the book is engaging, and horrific.  With precision, care, and great imagination, Burgess has created a tale that is dark, grim, yet undeniably brilliant');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (181, 44, 101, 5, 'This is the most poetically written book I''ve read in years. His writing stimulates the imagination and senses, taking you on the journey with him. You can feel the breezes, smell the smoke, taste the blood and tears. Highly stimulating and thought provoking. From the bombed out ruins of Europe  to the tragedy and desperation of the desert, you encounter the emotions of the Englishman''s existence. A must read for late nights.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (182, 29, 192, 5, 'This first novel of a trilogy of World War I is the most powerful although it was the last one, Ghost Road, which won the prestigious Booker Prize.  The setting is a hospital in England for those recovering from shell shock. The protagonists are a psychiatrist and his patient who is opposed to the endless slaughter of the war. Clearly to &quot;cure&quot; the patient, to find him sane, is to send him to his probable death.    The entire novel takes place within the hospital yet the horror of this  war is omnipresent, the images sharp and overwhelmingly strong and sad. It is an amazing book because of the author''s ability to portray the horror of war without being in the battlefield and the permanent scars left on the psyche.    Interestingly this novel has been built on the foundation of meetings between real people. I found this book irresitible and memorable, and immediately read the rest of the trilogy, but it is this one that is haunting.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (183, 13, 111, 5, 'Many books about writing are huge, but &quot;The Elements<br />of Style,&quot; the best of them, is extremely short: 92 pages,<br />including index. Read them all. Briefly and vigorously,<br /> Strunk and White will tell you, for example, when to use<br /> (and not to use) commas, which words to avoid, how to divide<br /> paragraphs, and generally how to pare your writing down to<br /> essentials. Many professional writers advise reading Strunk<br /> and White cover-to-cover once a year. If you do any regular<br /> writing, of letters or anything else, then follow that<br /> advice.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (184, 45, 52, 5, 'This book started out with the end and then explained why, an effective technique that is well used here.  The plot is about 2 media empires and how they were built: by &quot;monsters&quot;, who did anything to get their way.  By portraying the monsters first as boys growing up, we get to see how they changed and became the powerful figures as adults.  Every scene is related to something that happens later, but because the men are immoral, only one side is presented.  We don''t get to see any redeeming qualities of the man who is the worse of two evils, and the man who survives is only too glad to gobble up the empire of the one who fails.  That the two lead characters of the book closely parallel the actual lives of media moguls cannot be overlooked.  The problem is discerning what is fact from fiction.  Since the characters are so overwhelmingly immoral, it detracts from the being able to say &quot;so that''s how it was.&quot;  I can understand why Robert Maxwell wanted to stop the boo');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (185, 38, 41, 5, 'Ender''s Game is the first (and best) in a series about Ender, a young boy bred to be a leader in a society where more than two children is illegal. An alien race, insect-like possessing a hive mind (sound familiar? see The Madness Season), has attacked Earth, and we live in fear that they may strike again, even though it was decades ago. Ender, a child of the state, is drafted into this war, and he is forced to survive a bitter and difficult life in military school. His sister and brother (his brother Peter seems to be based on a popular killer, who dissected roadkill in his backyard), take over the Earth while he''s away at war - an idea that''s doesn''t sound so silly when you read how they manipulate the internet society. True genius at work, Ender''s greatest triumph and worst tragedy make for a powerful ending. Once you''re done reading it, put it down and read something else unrelated - the rest of the series doesn''t carry as much of a punch.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (186, 21, 57, 5, 'Having spent a year''s worth of High School English with Mr.<br />McCourt, I thought there would be very little that I hadn''t<br />heard.  I was wrong.  Mr. McCourt has written a wonderful<br /> tale about growing up poor in the USA and Ireland (in that<br /> order)  With all the bad that happens, Mr. McCourt keeps<br /> tone with an almost youthful innocence.  I cried at the same<br /> time that I was laughing.<br /><br /> For a first book (at the age of 66), it is very impressive.<br /><br /> You''ll enjoy it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (187, 39, 111, 5, 'If you''re like me, you''ve never really understood the mystical and murky meanings of Eastern philosophies. I had that humanities class and all, but it never really sunk in while I was sitting in the lecture hall behind some giggling freshman. These amazingly simple  books have taught me the secrets of life and happiness. Well, not really, but they do  teach you the way to get through life without life getting to you. Better than the Stress  Ball and less expensive than a trip to a swanky health spa, it has been helpful to me. Hoff  explains Taoism through beloved characters from the Winnie-the-Pooh stories by A.A.  Milne. Yes, that''s right, Pooh. I know it sounds weird, but it really works. These books  are very charming, funny, and witty. I now understand Taoist philosophy (I think), Pooh,  and Piglet better. I''m sure some Eastern philosophers are annoyed (or rolling over in their  graves) at these books, but, hey, it''s the only way Americans are every gonna understand  it at all!  [.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (188, 28, 53, 5, 'I read this book before the explosion of electronic games, and although I am not a Game Player, it offers anyone who is into games a kind of &quot;Gee, what if I could do this with   my games&quot; scenario.    For everyone else, a fun, fast read.  Once I got into it   I went through it in one night and then spent several weeks   reading every Orson Scott Card I could get.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (189, 31, 125, 5, 'Chilling, real, life and a story that should be heard by all. From one young man who died on the line, &quot;Just don''t forget us.&quot; Thank you for the interest, they now live through you');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (190, 12, 45, 4, 'The English Patient is a complex novel that interweaves four characters and their separate stories in a plot centered around WWII.  While the movie focuses on just one story attached to the present narrative, the book is much richer, fully developing all of the characters.  The main narrative creates a moving world of its own, as the characters find a safe haven from the war and their personal tragedies.  The novel can be difficult to follow, as the flashbacks to the characters'' prior stories are not linear.  However, the difficulties are well worth the effort.  The English Patient is a book that will endure and inform');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (191, 32, 72, 5, 'For all of those who love Anne Rice''s books, this is Rice at her best.  Fast paced and difficult to put down, you hope that by the time you finish, Rice will have the sequel ready  to go.    A must read!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (192, 24, 49, 5, 'Definitely one of the most original series currently on the bookshelves, Royal Assassin is one of the few fantasy novels that provides surprises...as well as making you actually fear for the safety of the characters');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (193, 47, 78, 5, 'Each word, each sentence, each image was chosen for a reason.  There is no sentence that isn''t absolutely essential to the story in all of the Crying of Lot 49.  Most books are stories; here, Pynchon has transcended the written word to create a piece of art.  Read it and you will understand what I mean');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (194, 45, 84, 1, 'Before considering reading this, I think that one should look to Norman Spinrad''s review of it as it appeared in Issac Asimov''s Science Fiction Magazine. Failing that,  at least realize that the entire book is a deliberate   button-pushing saga, following the patterns of human  mythology that are older then history, in a completely  manipulative way. Read Frank Herbert and you''ll see that he  wants to show the emptiness of the Messiah complex; Card  celebrates it. Herbert wants to explore what humanity is  about; Card wants to explore how much money it has.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (195, 18, 99, 5, 'this book is an example of card''s wonderful ability<br /> to use science fiction as a medium for exploring the human<br />''condition''. the characters are wonderful and the plot moves<br /> along swiftly... even if you aren''t a fan of ender''s game (which<br /> i most certainly am) you will find something to enjoy in this<br /> book.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (196, 20, 56, 4, 'I thought that the style of writing for this book shows a greater maturity and it clearly shows that much more thought was given behind the philosophy behind good and evil and how things may not be so black and white.  While it was not as action packed or mythical as the rest of the vampire books, I enjoyed this one all the same');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (197, 37, 3, 5, 'Just a quickie: I just picked up this book for the second time.  It''s one of the funniest books I''ve ever read.  Feynman was a wonderful eccentric.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (198, 15, 98, 5, 'Daphne Du Maurier has done a wonderful job in her story.  Rebecca is one of her finest works.  The characters are so real and the story is very intense and addicting.  You never really know the outcome until the last words.  A must read for all');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (199, 39, 45, 5, 'Watchers is about love, loneliness, fear, tragedy, the wrongs of genetic engineering/humans playing God, and, of course, horror and suspense. Watchers is about a man who has had a horrible  past, Travis Cornell, who thinks that anybody he gets close  to dies. It is also about Nora Devon, a woman who has been  kept isolated from the world by Aunt Violet, a character we  learn to hate. Also in the cast are a superintelligent dog,  a deadly human-made beast, a hitman, a lawyer, and two NSA  agents.  Watchers is by far one of the finest pieces of work ever  printed. Dean Koontz shows us that he is much more than a  horror/suspense writer. While keeping suspense at a maximum,  Koontz tells us a gripping tale about friendship. Some of the  characters are so charming that we wish they were real, while  some are just the scum of the earth.  Watchers pulses and overflows with Koontz''s God-given talent  for suspense, humor, and flat-out great storylines. Read it  as soon as possible!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (200, 18, 115, 1, 'After hearing all the hype, I picked it up. Unfortunately, I was disappointed. This has to be one of the most poorly written books I have ever read.  The dialogue is forced, unreal and just plain boring. The storyline is less than romantic, simply another re-hash of the old farmer''s wife and the milkman story.  I''m astounded that people are actually reading this drivel, never mind that so many actually find it remotely interesting');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (201, 48, 48, 5, 'I''ve read Ender''s Game a number of times and it never ceases to impress me.  I''m not really even a sci-fi lover, but the writing, in its style, is impressive and Card creates characters rather than charicatures or parodies.  This book poses genuine questions without falling into the trap that some sci-fi does of making everything really &quot;futury&quot; and giving alternate names to every aspect of human life in the future.  It is a fine book');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (202, 31, 57, 5, '<br />If you have only seen the movie the &quot;English Patient,&quot;  you do not know Michael Ondaatje''s &quot;English Patient.&quot; <br />You do not truly know the extent of Hana''s detachment from   the world around her and the reasons for that detachment,  you do not know of Carvaggio''s previous life with Hana and  her father, and you do not know of the physically abusive   nature of the relationship between Katherine and Lladislaw.  <br />Most importantly, you have not read:  <br />  <br />&quot;A man in a desert can hold absence in his cupped hands  knowing it is something that feeds him more than water.&quot;  <br /> or  <br />&quot;Her life with others no longer interests him. He wants   only her stalking beauty, her theatre of expressions. He   wants the minute and secret reflection between them, the   depth of field minimal, their foreignness intimate like   two pages of a closed book.  <br />He has been disassembled by her.&quot;  <br />  <br />Finally, the curious involvem');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (203, 10, 40, 5, 'McCourt''s Angela&quot;s Ashes is worth its weight in gold and I found it to be a good read but also informative about  history/religion and it''s effect on our culture.    I gave the book to several senior''s including  my mother who found the book too difficult because it made  them relive their poverty and many painful memories. To those  who have lost children or siblings through poverty you may  want to avoid this book because it is painful enough to  read without having to have gone through that experience  oneself.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (204, 25, 102, 3, 'Although the plot was very well designed, and the characters very well fleshed out, something about the way goodkind writes seems to cast a pall over the whole book.  Not a very enjoyable effect Although he hadn''t been the cheeriest of authors in Wizard''s First Rule, somehow he got worse.  Still, if not easily downheartened by the general despair, it is a very good book to read.  I finished it in one continuous span of reading, just watch out for how your feeling at the end!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (205, 41, 33, 5, 'I have read Ender''s Game so many times I can''t remember the first time.  My copy is so worn, and the cover creased.  It''s a wonderful story.<br />  Ender is a wonderful character.  He has so many facets that you forget he''s only a very young child.  It is invigorating to see someone so young battling against those a few years older than him, and those fifty years older than him, and winning at both.<br />  This story is a must read for anyone from age 12 to 112.  I highly recommend it.<br />');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (206, 43, 124, 5, 'This is the most exciting story I have read. I have owned  a half dozen copies, and keep mistakenly &quot;loaning&quot; them out to friends, never seeing this book again. Read it the first time  for the excitement of a story that you cannot put down. After  read it 5 more times like I have and learn more about human  nature and the dark subtle forces that drive us humans. Each  time I pick this book up to read, more I learn about who we are   and how easy we are to manipulate.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (207, 22, 1, 5, 'Bladerunne');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (208, 14, 83, 5, 'I have read the other 3 but can''t wait for the new &quot;Drums of Autumn&quot;. I have started a reading group at work (I provided the books, and everyone else reads) and you can guess which is the favorite series. One person  in the group has read them all in less than a week!  My order is in for  &quot;Drums of Autumn&quot;.  I can understand why it takes so long for each book  to come out, all you have to do is pay attention to the detail. I hope that  Diane writes for many, many years to come.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (209, 17, 199, 5, 'As a classics major (and there aren''t too many of us) I enjoyed this book tremendously. It doesn''t seem like it has over 600 pages, it flows so quickly! I''ve read a large number of novels set in the ancient world, and this one ranks up there with I, Claudius and the earlier Mary Renault novels');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (210, 36, 57, 2, 'I have read the first 4 books of the Vampire Chronicles  and loved them all.  They are all action packed and give us an in-depth view of Lestats life and struggle.  Now  Rice goes into a 400 page long debate on Good versus bad  and God versus the Devil.  I would rather read the Bible  for that.  This isn''t about Lestat or Vampires at all!  I   had several friends tell me &quot;Don''t read it - it is boring   and slow&quot; But I didn''t listen.  I couldn''t read it past 120  pages and I couldn''t even get through the cassettes.  If   you like Anne Rice you should hate this book because it  has nothing to do with her former stuff at all.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (211, 30, 112, 5, 'Shogun deals with John Blackthorne,and his crew who ends up shipwrecked in Japan.  What seemed like a primitive culture, turned out to be an advanced and scheming one.<BR><BR> This book deals with corruption, love, and power to the fullest degree.  Yet educates you in Japanese history so nicely, that you will find a new respect.  Heck, you''ll even learn a few Japanese words.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (212, 33, 185, 2, 'Frank McCourt''s relentless catalogue of the horrors of his upbringing, while accurate in his case, were not typical of the vast majority of Irish poor of that time.  His family  life was an extreme - his father was an extreme - the death  of three siblings was an extreme.  McCourt does a wonderful  job portraying his mother''s courage and in showing the   psychic baggage the Irish Catholic poor are lumbered with.  But this is a mightily flawed book and the acclaim it is  receiving astounds me.  The child''s point of view is finally  tedious and wears us down; the pathos is well-worn and   tired; the book lacks any lyricism.  This is a still-born  book and McCourt should try again to give us the book that  all the critics are raving about.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (213, 38, 48, 4, 'I loved this boook, althouhg the story was too quickly resolved. I like this author/series for the exact reasons that the previous poster did not. Goodkind takes old cliches of the fantasy/sci-fi genre, and makes them BETTER. Somehow he improves on these authors'' stories. While I did not like the way he plagiarized the Aes Sedai idea from Robert Jordan. The stories you mentioned are some of my favorite stories. I could like nothing more than I like Star Wars. (Star Trek sucks!) I have read only one of Eddings books, but I have heard he, like Jordan, gets very boring after a just a few books. I have read all of Jordan''s books by the way. Goodkind''s greatest asset is not his ability to create a universe in which you can completely immerse yourself (like George Lucas'' Star Wars), but his ability to draw the reader into the story from page one, and keep the book moving along at an unbelievably fast pace. Jordan and Eddings can only wish they had the same talent. Goodkind is the best author');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (214, 47, 57, 5, 'I have read the other reviews and I agree with all of them.<br />Many aspects of the series have been touched upon by all the<br />reviews. This series is the ONLY set of books that I could<br /> not put down. Like others I interested friends and<br /> co-workers to read the books, even men! through much<br /> assuring that it was NOT a trashy romance despite the<br /> location in the book stores. (Real men can buy a book from<br /> the romance section.) People I encouraged to read the books<br /> told me: they refused to answer the phone, the door,<br /> cut short evenings out (much to their spouses dismay) and<br /> generally ignored the outside world till there were no more<br /> books to read. Best books for anyone sick in bed, that<br /> can''t stand convalescing. These books sparked heated debates<br /> on where the characters were going, why they did what they<br /> did, what they TRUELY felt instead of what they said. I had<br /> a friend tell me &quot;Its just a book, calm down');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (215, 49, 178, 5, 'Is it possible for a book to merit all the above adjectives above? Yes, if it is Catch-22; in the setting of World War II, Heller depicts the sheer  waste and tragedy for humans, when ''nations'' are at war. Catch-22 seeks to show the waste exemplified by the War , without ever depicting a direct attack by the  enemy, the Germans. The protagonist of the book, Yossarian, sees through the sham that war is, and questions  his superiors relentlessly about their ideas of patriotism, when it is he  who is going to die ''for the country''. the novel moves back and forth in time, through  events and from the farcical to the tragic at a machine-gun pace. Yet within this seeming disarray, a  tale builds up- in the end you wonder who the real enemy is - the Germans or Yossarian''s superiors');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (216, 43, 78, 5, 'I will never not own a copy of this book. I will never stop having to buy new copies as I give away older copies to friends, with the injunction &quot;You MUST read this!!&quot');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (217, 32, 47, 5, 'If you liked Tolkein''s Lord of the Rings, get set to enter<br />a world even more engaging! George R. R. Martin has set us upon a journey following<br />the House Stark of Winterfell and their quest of peace for their family in a land<br /> where it is denied them at every turn. I don''t know when I''ve ever read a book as<br /> captivating as this one is. This is the first volume of four (the second, due in the<br /> summer of ''97) and as much as I wish all were available right now, the time lag here<br /> will give me time to re-read A Game of Thrones another time or two before the<br /> second is released. If you like to get so wrapped up in a book that you can''t wait to<br /> get back home to read some more, this is the one you need to get into. Every time<br /> you think you''ve figured out what the next turn of fate will bring the members of the<br /> Stark family, George Martin snatches the rug out from under you as you pour into the<br /> next chapter. This is the finest writing I');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (218, 33, 149, 5, 'This was the first book I read of Orson Scott Card''s. I first read it in the sixth grade(I''m 14), and I loved it. I forgot about it until last year when I saw the book again. I found all the sequels to it including the recent &quot;Children of the Mind&quot;. I even read the &quot;Earthfall&quot; Series and his &quot;Alvin Maker&quot; series. You have got to read this book. The psychology/action theme makes this a great page turner');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (219, 48, 78, 5, 'This book is great from beggining ''til end. It''s definatly one of the greatest books I''ve ever read. Grisham keeps you turning pages until your done. It won''t let you take your eyes off of each and every page! This book is great if I had to buy it again I would. You won''t regret this. Is a book you should really spend your money on, or just rent it at your local library. It''s the BomB!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (220, 30, 52, 5, 'Betty Eadie not only teaches you about life after death but more importantly teaches you about life and why we are here. She explains some of the most burning questions of the human soul in analogies that are so simple yet so complex. A must read for anyone with a soul');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (221, 30, 153, 5, 'If you could check circle 20, it would still be an underestimation of this incredible novel. Something Wicked is without question the finest piece of contemporary american literature to ever be written.  Starting as a child''s tale or fable, the book expands into a mult-layered, multi-complex novel involving death, life and all parts in between. The dynamic tension of freindship, lost loves and puberty  are all dealt with in this amazing piece of work. The premise, a &quot;dark&quot; carnival ariving in a small mid-western town in October is common Bradbury territiry. And there is no doubt of the autobigraphical  nature of this work. As the story weaves itself through the town''s population, the two boys at the center of the story, are the only ones that sense the approaching darkness that the carnival brings.   In classic Bradbury prose, the reader is trasported with eloquent descriptions into the story itself. One of the two climaxes of the story, a confrontation between one of the boy');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (222, 32, 181, 5, 'I read a lot of material on dreaming and dreamwork, so some of the books I pick up seem a bit repetative. Conscious Dreaming takes the standard fare to a whole new and exciting level beyond the struggles with the personal unconscious into fantastic realms that are available to us in dreams');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (223, 33, 97, 5, 'Until IT was published, The Shining was by far my favorite. It made a wonderful story perfectly suited to a movie. And then there was the movie...booooo.  I hear King''s reissuing  the movie...great.  King is the most versatile author in the  U.S. ever. His styles are legendary, his books compelling.  Hooray for S.K.                                       Bud');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (224, 24, 174, 5, 'Perhaps oe of the greatest fictional stories ever written, Ondaatje''s &quot;The English Patient&quot; is a true masterpiece.  Set in the post-WWII era, in the hills above Florence, Italy, this  story captures you from the start.  The characters have a deft  and masterful power about them, particulary the Patient, whose  majesty and subtlety are brilliant.  The end leaves you awed,  its'' tragedy and sacrifice fills one with a sense of true  desolation.  Sublime and intoxicating, like a draught of fine  wine, this book is a must-read.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (225, 30, 89, 5, 'As adults we forget to keep asking the philosophical questions that were so stimulating in our early adulthoods.   This book reminds us of all those questions:  Is there a God?  What is the meaning of life?  What is human knowledge and where does it come from?  It is very exciting to stretch your mind again over the theoretical.   This book is the tool to help you do so.  Before you become entrenched in the mundanity of life''s day to day problems again, enter Sophie''s World');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (226, 42, 185, 4, 'The concepts discussed are applicable to not only the computer industry, but every industry, career or personal endeavor.  I do not appreciate the title or the concept of &quot;Only The Paraniod Survive&quot;.  A better title would have been &quot;Be Open To Change Or Dead&quot;.  Andrew Grove gives a great personal introduction to the cassette.  The content is easy to listen to and gives a fresh perspective');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (227, 47, 97, 5, 'Ten Strangers on a cold, isolated island.  Brought here by a queerly anonymous invitation.<br /><br />The evening begins with light conversation and witticisms.  But it soon degenerates into beastly fear and mistrust.  One by one, each of the 10 are being found murdered.  And the murdered is clearly one of the 10...but which one?<br /><br /> Every turn of the page is like stumbling through a dank horror house.  What grisly find waits around the next corner?<br /><br /> You''ll never solve this mystery.  It''s too cunning.  But you''ll relish the goosebumps that sweep over you like a cold sea-wind, and the horror that catches in your throat like poisoned wine.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (228, 12, 19, 5, 'Bill Bryson''s travelogue of the United States can be best described as a side-splitter.  Like many of the others who have reviewed this book for Amazon, I found myself reading it out loud to anyone who was close by. A great way to make friends at crowded airports.   This is the tale of Bryson''s travels as a young adult with many references to his childhood experiences in Iowa doing such things as traveling on summer vacation with his parents and sister.  While the book has a definite Iowa slant, his experiences are so universal that they will be enjoyed by all. What man has not wondered why the nubile cuties of his youth look as if they had swallowed airmattresses 10 or 15 years later.  Bryson is cynical, jaded, snide and sentimental all at the same time.  A good book for anyone who has traveled to Boston, Washington DC  and particularly good for anyone with Iowa roots.  And, by the way, his mother seems to be still alive and well - I saw an article in the Des Moines Register recently ');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (229, 31, 84, 3, 'After reading the reviews here and seeing the movie, I bought the book with a great sense of anticipation. The plot: a review of the life of a perfect English butler who has the twilight  of his years to look forward to. Perhaps the movie gave too  much away, but I did not find the book amongst the more engrossing  that I have read. The last five pages are the only ones  where I got a sense of the pathos of the character. Read &quot;The  Postman&quot; instead and see what I mean.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (230, 45, 157, 5, 'Drums of Autumn carries the story of Jamie and Claire Fraser beyond happily ever after to the reality of the rest of their lives.  In doing so, Gabaldon creates a believable and poignant portrait of a marriage that works. Their relationship continues to involve the reader because both Jamie and Claire grow individually within it. This is marriage at its best; offering love, security, and the freedom to be and become.  These books are not romances, nor histories, nor adventure stories.  They are, instead, accounts of one couple''s struggle to find themselves through each other in their struggle to establish &quot;a marriage of true minds&quot; under the most unlikely of circumstances.  Never maudlin, the series celebrates the best of love, marriage, committment, and mutuality. I am only sorry I have finished Drums of Autumn and will probably have a long wait until the final(?) book in the series is available');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (231, 27, 98, 5, 'Watership Down is more than just a good book. It''s that rare story that comes alive, and will stay with you long after you finish reading');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (232, 34, 37, 5, 'I have been on bedrest since 9 December and will remain so until mid-March when my second child will be born.  I  anxiously await the arrival of Diana Gabaldon''s newest   edition to the saga of Jamie and Clair.  Just over a year ago I   purchased the original three of the series, having great   difficulty due to the fact I''m stationed overseas with the   military.  Upon completing the books my husband unwittingly  sold them in a yard sale and I was so upset I could barely   speak!  My biggest wish was to get the serious again for my  birthday or Christmas.  My Mom sent them to me and I have   not been able to put them down, again.  I have reread these   terrific books.  They are my means of escape.  I love   learning about the Scottish history, and can put myself out   of my bed and into the pages of Mrs. Gabaldon''s books.  It   is with exceeding joy I find her fourth book is out and as  I complete the final pages of &quot;Voyager&quot; I await the arrival  of &quot;Drums of Autumn.&qu');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (233, 37, 80, 5, 'This book offers wonderful quilt block patterns for great quilts and projects including baby quilts, cat quilts, holiday projects, Noah''s Ark, Sewing Motifs, and much more. In addition, it includes many patterns for traditional quilt blocks and some lovely applique patterns. My absolute favorite quilting book');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (234, 49, 174, 4, 'I thought that the main idea of this was very good.  In the beginning it was very stupid though.  I don''t really care that these people want to get a look at Boo Radley.  That is so stupid.  However towards the end, teh trail and the action sfollowing were very good.  This book was perverted though.  The author of this book was sick, I am sorry to say');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (235, 41, 50, 5, 'The happenings of Matilda are what every kid dreams of having');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (236, 10, 9, 5, 'An outstanding evergreen book! Every single phrase tells you something USEFUL about Advertising: a 224-page book WORTH BUYING, believe me. Incredible, so uniquely clear and clever!     David, you have sign-posted THE Job of my life  (Michele Re, an Italian lover of Copywriting - and Ogilvy, naturally).');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (237, 15, 59, 5, 'Incredible!  Everybody loves Ender, the boy genius, plucked from his home, his family, and his planet and shuttled off to Battle School to fight the Buggers; an alien species, intent on colonizing Earth and destroying the human race.  A non-stop action adventure and perfect for everyone young and old.  The best science-fiction book for anyone who claims not to like the genre. The first time I read this book I did so on a 45 hour road-trip from my home in New Jersey to Jackson Hole, Wyoming.  Myself and three buddies from college all read it during our two-week adventure.  It was recommended by the brother of one of the guys who was a West Point cadet.  It turns out Ender''s Game was on the Required Reading List for his freshman class.  While in Jackson, I bought book 2, Speaker for the Dead, and read it on the trip home (naturally putting it down when it was my turn to drive). Since then, I have given this book to my mother, two of my sisters and their two sons.  All loved it.  In fact,');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (238, 25, 105, 5, 'So now that we have all patiently waited to find out what is going to happen to two of the sexiest characters in any book, when does the next one come out?  Please don''t make us wait quite so long this time');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (239, 31, 159, 5, 'This is a terribly funny book, and it can be used as sort of a personality test.  If you let someone read this book and they don''t think it is funny, then that person probably scores well into the negative on the personality scale.  (They are an anti-person)  ((Like anti-matter, but less explosive and much more annoying)');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (240, 44, 165, 5, 'Well organized book on history of philosophy. The history part &quot;sneaks up on you.&quot; Novel and history all in one book!  Easy to read and hard to put down! The author states that &quot;the only thing we require to be good philosophers is the faculty of wonder,&quot; and the book helps us tap that faculty. I''m going to read it more than once');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (241, 22, 58, 1, 'People are like corporations? Get a life! This book has been studiously ignored by even the mainstream business press who otherwise worship anything associated with Intel. If you must buy this book, wait until it hits the remainders table');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (242, 25, 171, 5, 'I find it hard to imagine a better book for reading during a long, cold, miserable winter day.  With 880 pages, DOA is the kind of satisfying read that is hard to find these days.  The characters are compelling and well-developed.  The story is fascinating and filled with marvelous twists and turns.  The author does not shy away from painful or difficult events or topics.  The history is well-researched and then brought to life.  I can comfortably recommend this book to anyone who enjoys reading');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (243, 16, 82, 5, 'Seldom have I read a book as compelling and memorable. This book is about the triumph of the spirit, even considering  the catalogue of childhood horrors Mr. McCourt provides.  When I finished it, first I wanted to dance a jig; then I wanted  everyone I know to read it');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (244, 15, 33, 5, 'This book is incredible! It has just the right mix of adventure, action, comedy, romance, and many other fine points. This is the start of an amazing series of Dragonlance books that have already grabbed an impressive amount of fans. Join the club, and read this first series, Chronicals. I guarantee that once you start reading these great characters'' stories, you''ll never put them down');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (245, 47, 102, 5, 'Card''s insight into human nature is remarkable. Ender, to me, represented all humanity. We have the power to make things happen, but we are pushed and pulled by the very things that make us human... Our beliefs. Card, i think had this in mind when he sat down to this book. Ender''s belief that it was &quot;just a game&quot; is the reason he was so good at winning. It was only when he was mounted against &quot;unbeatable&quot; odds that he lashed out. If he had known the truth, he would have reacted diffrently in each simulation. knowing that his actions, would have reprocussions on his fellow humans. Overall, it was a wonderful book, nicely told but &quot;deep&quot; in its own nature');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (246, 23, 6, 5, 'I must have purchased this book 5 times by now - copies keep ''disappearing..''  Provides insight into human behavior, training, war and child development. Remarkably easy to read.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (247, 34, 51, 5, 'This book has my kids and me in constant laughter. My children never tire of listening and/or reading it to themselves. The illustrations are also a howl');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (248, 34, 138, 5, 'I have been married for four years--just long enough to get over the honeymoon.  My husband and I have even recently tried some marriage counseling.  I have been searching for solutions to my disallusionment of marriage.  This book has changed my life! I now understand my husband''s true needs and he finally understands mine. While reading &quot;The Five Love Languages&quot;, I thought of five couples that could benefit from this knowledge, and several marriages that might have been saved.  Though the author points out that, ultimately, the key to a successful relationship is choosing to love, this book puts it within anyone''s power.  I would recommend it to everyone--especially those who are engaged to be married.  Had I known these principles earlier, I could have saved myself and my spouse a lot of heartache.  I feel hopeful about the future and look forward to the rest of my life with my husband');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (249, 35, 15, 5, 'John Kennedy Toole''s work left me laughing so hard I was gasping for air.  The life of Ignatius truly allows the reader to glimpse the worlds of those millions of people who barely hang on by clinging to the fringes of society.  This book is a masterpiece and should be read by everyone, including Bob Dole');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (250, 12, 197, 3, 'Dr. Murphy gives you some usable ideas on why what we think influences how our life turns out. Although written in a religious bordering tone it can be - if you know how to read it - be very insightful');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (251, 46, 200, 4, 'This desk is very study and it i has  a beautiful finish,  I think that it a just a little  pricey for the size.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (252, 46, 48, 5, 'Great item');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (253, 4, 170, 5, 'Perfect fit for my bedroom, been wanting one since I was a little girl');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (254, 40, 118, 3, 'We use this on a trundle bed.  So, it does not get that much use.  This was a much better choice than getting a low end spring mattress for the same price.  I do not think I would use this on anything other than a trundle.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (255, 42, 34, 3, 'The product is fine...just seemed like it took awhile in the mail for something small you could throw in an envelope and mail.  Not unhappy just moderately satisfied.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (256, 46, 34, 5, 'Love this product, amazing delivery, thank you');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (257, 24, 92, 5, 'I love this bench, had one in Black for over five years, and moved it more than 5 times to different houses after a few chips and broken pieces, I decided to buy the White one as it matches our current home decor better, plus it is much easier to locate shoes especially black ones! the black cubbie bench was too dark, and most of our shoes blended in and hard to see. This is perfect. Easy to put together. I painted the back white as well, as it was going in an area with the all sides shown.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (258, 32, 160, 5, 'Have had this for over a year.  Very well made and durable!  Great storage capacity.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (259, 27, 105, 5, 'This is the best step stool I have ever used.  So compact when collapsed so is very easy to store.. no hidden latches.  Have already recommended to friends.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (260, 18, 26, 5, 'my son loves it!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (261, 24, 187, 5, 'Great product');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (262, 46, 146, 5, 'bought with sleep contour 8&#34; foam. arrived ontime and my kid had no trouble assembling it. shipped it to his off campus apt.. he says its most comfortable bed hes ever owned!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (263, 47, 15, 5, 'Delivery was on time. I was very satisfied with the product. The table is very sturdy and it exceeds my expectations!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (264, 37, 17, 5, 'Exactly as pictured. Plush, soft and great for in front of a sofa.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (265, 37, 6, 5, 'Beautiful table.  It''s good quality and heavy.  Put it together by myself, it took about 3 hours, but the instructions were the best and clearest of any item I''ve had to build.  I was worried because it looked like there was a crack in the top of the table itself until I looked closer - that''s how good the laminate is, it REALLY looks real.  Love it and would purchase again.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (266, 50, 159, 1, 'I have cleaned up the last mess from using this tray, the legs collapsed again. It was also much larger and bulkier than I wanted.<br />But if your looking for a big tray without a lot of support this is the one.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (267, 21, 81, 3, 'First one came in damaged. Ok bed for the price.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (268, 30, 126, 4, 'Good deal to get a nice chair for study in a low price');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (269, 23, 142, 5, 'Comfortable and easy to fix...');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (270, 21, 180, 5, 'As advertised. Very comfortable. Great color. Prompt delivery.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (271, 18, 59, 5, 'Very nice rug for a reasonable price. Exceeded my expectations.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (272, 39, 96, 5, 'Product was as described. Delivered on time. Overall a sturdy box spring. Not at all difficult to put together. We bought Mom a tall foam mattress from Costco. With this low profile box spring my Mother has no problems get in and out of bed now. Also good quality materials for the price, which wasn''t bad either. I recommend and will purchase again if needed.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (273, 28, 133, 3, 'Functional but too lightweight - I ordered 2 and attached them together');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (274, 42, 44, 5, 'I love these stools. Perfect for a toddler. I had to order another one');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (275, 30, 131, 5, 'so comfortable!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (276, 10, 78, 5, 'Love it!! Easy assembly and nice quality.  Great table for the price.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (277, 41, 49, 5, 'These rescued  my son''s bed from the floor. Was easy to install and has legs for support, wooden slats did not. Very happy! Thank you');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (278, 41, 22, 5, 'Replacement for the one in RV that had a blow out. Husband loves this air mattress.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (279, 23, 59, 2, 'Not for every day use. Support leg underneath bent in just a few weeks with a normal sized teenager. Maybe okay for a small child.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (280, 21, 63, 1, 'Saggy mattress');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (281, 28, 185, 5, 'This is a nice frame.  Fairly easy to set up and it looks very nice.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (282, 12, 94, 5, 'Since I do not own a truck I contemplated how to get a queen size mattress home which my daughter needed for her new bed frame. Finding this item on Amazon with Free Shipping was perfect! Easy to get upstair and unwrapped - The mattress comfort is excellent and the price could not be beat anywhere in my town - Best Purchase Ever!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (283, 21, 39, 3, 'It''s the right size but the padding is really thin, not as cushion-y as I would have liked but it''s okay.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (284, 26, 138, 5, 'Absolute steal!! This desk is very cheap and is so awesome! I love it already! It is a great use of space!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (285, 13, 197, 1, 'Not only did the design not match the photo, but the center image was well off-center and looked pretty awful.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (286, 15, 106, 4, 'This took forever to put together for small table but I love the look of it. One of the holes wasn''t pre-drilled so that was a little of a challenge but I made it work. We bought the set (headboard, night stand, dresser) for my sons room and am very happy with the purchase.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (287, 14, 69, 2, 'Very uncomfortable, hurt my butt and edge cuts into your hamstring after sitting on them for a few minutes.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (288, 20, 119, 1, 'Very low quality. Ordered two and both had dings and dents. Pore packaging and thin metal. Returned both.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (289, 27, 65, 5, 'Gift for granddaughter ~ she has it at entrance to her bedroom....loves it!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (290, 21, 38, 5, 'Great affordable firm, but comfortable mattress');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (291, 15, 161, 5, 'Great table!! Liked it so much I bought a second one!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (292, 34, 41, 5, 'Best futon mattress I have ever used. No feeling the bars or slats through this. I did buy a cover for it as it seemed like it would pick up lint/dust very easily and my cats like to scratch.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (293, 4, 86, 3, 'i purchased this table for studying. But it turns out to be shaky.<br />But it is still ok to read, write and code on this table. Not bad');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (294, 34, 33, 5, 'Great stand!<br />Material is very nice, no complaints!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (295, 27, 78, 2, 'Love the look, disappointed that the holes were not drilled out & none of the hardware worked.  Not what I expected !');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (296, 17, 16, 5, 'Fast shipping. Exactly like the picture. looks great in our living room!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (297, 49, 124, 5, 'Bought this chair for our security gate house. The main concern was comfort. As this chair is used 24/7 comfort was a must and it hasn''t disappointed in that aspect. It was also very easy to put together. Took me 40 minutes to put completely together with no hassle. Only issue I have is that both arms keep getting loose and need to be retighten every other day. Other than that, chair is great!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (298, 3, 57, 5, 'Exactly what I thought and wanted. Works great in my living room especially with a 7 month old around.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (299, 48, 178, 5, 'Speechless, nice product!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (300, 20, 123, 1, 'It still give my elbow discomfort.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (301, 35, 106, 4, 'This is very concentrated and smells okay, but the scent does not last after drying. My laundry just smelled like clean clothes, which is fine, but kind of defeats the purpose of jasmine-scented laundry detergent. It cleans fine, doesn''t cause any allergic reactions, and the packaging is fine. However, it had leaked a bit during shipping despite being in a plastic bag.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (302, 11, 124, 5, 'Just bought this mattress, and it is wonderful! With any new mattress I have bought, it takes a few days to get used to it. Not with this mattress! Did not have to get used to it at all. Slept the whole nite thru. This is not the less expensive and not the most expensive...right in between. You won''t go wrong with this mattress.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (303, 35, 64, 4, 'This is a beautiful island but it is not solid wood. The back consists of 2 pieces of board that I think are plastic they are only about 1/4 inch thick. I think the shelves are particle board.  It arrives in 3 boxes. One box consists of the top with the drawers already attached. You will need to attach the leaf.  It has very clear instructions. We did have a problem with both of the doors not wanting to close so we took the hinges off and turned them over and reattached them. One door the hinge had to be upside down with the pin going up instead of down. The other problem we had was the leaf it was not level with the island so we had to drop the wood hinge down so it would be level.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (304, 50, 43, 5, 'This rug is kind of  unique and that is what I was looking for ; combines couple of different rug materials, shag and berber, to present such a contemporary, interesting look. Very soft ! Seems well made. Colors are true to the picture, and go very nicely with our chocolate brown sectional in a neutral color room.  Highly recommend.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (305, 34, 21, 5, 'I love it - i was hesitant about ordering this online but the material and quality of the fabric is perfect and the gray-blue is just what i was looking for...');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (306, 46, 22, 4, 'Cute table. Easy assembly. Picture true. Matched perfectly.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (307, 39, 157, 5, 'These went in perfectly find and event fit an older bed frame.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (308, 13, 18, 5, 'Very difficult to assemble....');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (309, 19, 6, 5, 'Works great and super easy to put together. Very happy.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (310, 34, 160, 4, 'I like it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (311, 35, 163, 5, 'It was as advertised and perfect for our bar stools.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (312, 36, 170, 5, 'Fits my TV and my room perfectly.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (313, 41, 195, 4, 'Beautiful');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (314, 17, 173, 4, 'Made in Turkey. Decent quality, not the best I''ve seen. But totally worth the price. The colour is a little darker than what''s shown in the picture.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (315, 24, 165, 4, 'It''s exactly as I expected. Assembly is easy if you''ve got a power drill. The couch is very firm and thus far it''s been sturdy. Definitely worth the price');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (316, 17, 90, 2, 'Small');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (317, 23, 110, 4, 'Looks great, but is not very stable');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (318, 49, 8, 5, 'Very comfortable I love these & so does my family & friends when they come over, I would buy them again if anything ever happen to them just because of the feel & for the price you can''t go wrong..');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (319, 30, 79, 5, 'This made my crappy mattress feel like a glorious cloud!  I have it on a guest bed and all who have slept on it have remarked how amazingly comfortable it is.  Perfection!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (320, 40, 113, 4, 'I loved them. Lots of sparkle. It came attached to a really nice sturdy rod. I didn''t find any hooks that may or may not have come with it but no biggy, I had them handy and the only other thing is that it had room for a few more string of beads on there to make it a little bit fuller but other than that, I really loved them and it makes my closet look jazzy! :-)  .');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (321, 14, 103, 4, 'Exactly what I expected and wanted. very happy with this purchase. Looks great in my living room!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (322, 23, 93, 1, 'This was one of the worst purchases I''ve ever made.  The drawers and top are chipped, the directions are poorly represented pictures... there are no premarked holes for the areas the need nails and the screw holes for the drawers don''t line up, leading to hours of frustration and misaligned construction. I''d have done better with ikea furniture and may wind up doing just that. This will be an expensive item at my curb.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (323, 3, 180, 5, 'Shines like crazy. Vinyl.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (324, 25, 122, 5, 'I''ve been looking for ways to increase storage space. I live in a 2 bed 1 bath apartment with my girlfriend, and our two Siberian Huskies, and another couple. Needless to say, we are all packed in there like sardines! Now, let''s be honest here... 50% of the space is for the other couple, 60% of the space is for the pups, and the other 30% is my girlfriends. The numbers don''t lie... we definitely have no more space at this point! I bought this for me, in hopes that I can re-claim a percentage of space for myself. Bed risers just weren''t going to do the trick, and wooden framed with built-in drawers are much out of my price range. For me, this was a solid meet-me-in-the-middle solution.<br /><br />FIRST IMPRESSIONS:<br />The actual storage space of each of the two &#34;cavities&#34; from floor to the under-bars measures at about 12-1/2&#34;tall x 30&#34;wide x 60&#34;deep. I''ve very pleased to say that I was able to fit EIGHT (count em''), EIGHT large 12&#34; storage tubs under the bed! T');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (325, 17, 7, 5, 'Pretty good');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (326, 39, 41, 1, 'Caps were old and  crumbly');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (327, 44, 112, 5, 'Easily assembled, looks good, great price.  a little taller than i anticipated.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (328, 46, 4, 2, 'This chair is a typical manager''s chair. There was nothing showing the weight limits, but width wise, it definitely isn''t for a big person. I definitely overpaid for what is actually just a basic office chair. It was also slightly difficult to put together. The screw holes weren''t drilled correctly and I had a hard time getting the screws to catch. The two stars are for the looks. I would give another 1/2 star for comfort if I could.  If you''re big, I wouldn''t recommend. If you''re not big, you can find the same quality cheaper. I have it up now and am not taking it apart to return. I wouldn''t buy again.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (329, 35, 94, 5, 'We love the headboard. The fabric and tufted button work looks great! It is high quality and looks very modern and elegant. We have an ikea storage bed in one of the rooms and we simply put the headboard against the wall in between the wall and the bed and there was no need to screw the headboard. It appears nice and stable. Looks great!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (330, 40, 172, 4, 'Very cute floral arrangements.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (331, 29, 136, 2, 'Convenient remote control holder that can be attached to the side of a dresser or bed stand.  Comes with both wood screws and Velcro for attachment.  However, the screws broke off at the head when screwing into wood, before the screwhead was even close to the wood!  This damaged the dresser by leaving unusable holes, as the base of the screws could not be removed from the wood!  I''ve never had screw heads snap off before, and on closer inspection, the included screws appeared to be hollow!!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (332, 20, 59, 4, 'This would have been great if the kit had all of the correct pieces. I could not finish assembly because it had two left side panels instead of one left and one right. Now I have to wait to finish assembling it and hope the replacement parts are the right color. On the positive side, it did arrive about 4 days earlier than anticipated.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (333, 48, 177, 5, 'It is perfect and arrived undamaged,Thank you');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (334, 28, 25, 5, 'Fast Shipping. Comfortable memory foam to replace RV mattress.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (335, 50, 5, 4, 'Nice pantry very sturdy used for canned goods, small appliances etc. my son and I put it together in a little over an hour');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (336, 49, 144, 5, 'I love Sauder pieces. This desk was my 30th piece, and I just ordered my 31st. I call Sauder the Cadillac of Walmart. Their attention to detail is astonishing. It is par for the course to have a few pieces arrive damaged in shipping, and yes Sauder, obviously damaged in the factory BEFORE packaging. But Sauder makes it right (usually, see below). Just hop on their website and order the replacement pieces you need, free of charge. Set aside the project for a week. My parts'' orders arrive within a week.<br /><br />This particular desk is intricately designed and looks fabulous. It took more time than usual. It is a solid, well-designed desk which has a lot of pieces. It astounds me to see people criticize Sauder for furniture that does not come out well -- it is THEMSELVES who are the poor assemblers! I have assembled three or four other companies'' furniture, and all fared poorly, and we were careful and conscientious.<br /><br />The Carson Forge collection is a family''s dream furniture.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (337, 12, 34, 5, 'Superb quality and exactly as advertised.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (338, 46, 193, 5, 'They arrived quickly (long  before promised) and are well made and beautiful.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (339, 33, 72, 2, 'Low quality materials, but a good size and would be pretty functional.  But mIne came w a cracked leg and I had to jump through too many hoops to resolve the issue.  Ended up getting a refund, but still need a desk.  Try something else.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (340, 35, 52, 5, 'Came fully assembled, thank goodness. All I needed to do was switch the handles from inside the drawers to the outside. It''s real wood, not particle board and should last a long time. Decent quality. I''m happy with it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (341, 3, 77, 4, 'I would have given 5 stars. BUT... I put it together by myself.  The assembly wasn''t difficult, but when I was almost done, one of the pieces &#34;cracked&#34;!  Luckily, it is not noticeable.  I would not have been able to take it apart & send it back due to the glue.  Upon completion, it''s a really nice, heavy cabinet.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (342, 32, 120, 5, 'Good!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (343, 23, 78, 5, 'Not too firm, not too soft.  Just right!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (344, 32, 67, 3, 'ink is a bit blurry');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (345, 38, 140, 5, 'Excellent');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (346, 40, 185, 1, 'A piece of junk.  The screws is too short to set it up and a piece at the corner of the board is broken off.  We are sorry to order this particular item.  It is very disappointing.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (347, 43, 129, 4, 'Good product');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (348, 19, 181, 5, 'Great product');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (349, 42, 93, 5, 'Beautiful!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (350, 46, 80, 5, 'Great purchase.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (351, 4, 24, 5, 'We love these bar stools so much that we purchased another one. They are very comfortable and perfect for our kitchen decor.  We love the cherry red color.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (352, 41, 16, 5, 'Perfect size for a small apartment! I personally think it looks better without the wheels but overall awesome addition to my place!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (353, 34, 22, 4, 'It was very easy to put together and looks really nice. It''s very sturdy as well, my mattress does over lap the front a little so I''m unsure if that''s the frame or the mattresses fault. It does have a lot of wooden slats which give it extra stability, they are also attached with velcro, but I wouldn''t put stock in the velcro being a really strong attachment. It does come in a very heavy box.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (354, 21, 57, 5, 'I liked this desk when I had it. I had to give it away when I moved. But it''s a nice, concise desk that can fit in a corner. Well designed.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (355, 33, 58, 5, 'I bought this shelf to use as a shoe rack in my son''s dorm closet.  He has a very small space and all the shoe racks I saw were too wide.  This unit is adjustable so it fits well and can give him more area so he can stack his shoes.  The shelf was very easy to assemble and completed in a few minutes.  It is working well for this purpose. Great product.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (356, 42, 126, 5, 'Big, pretty,worth the money , like it');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (357, 44, 142, 5, 'Bought for my new 90 year old house... put in dinning room and it looks great with my square table. Perfect fit.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (358, 50, 172, 5, 'This  was the BEST IDEA EVER! Great communication, well made, arrived on time! Thank you so much Creative Letter Art!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (359, 36, 72, 3, 'This is made of hotdog wood.  I think all Sauder products are, but its still pretty cheesy.  Overall, its not a bad cabinet.  Dont expect to move it much after its put together.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (360, 3, 51, 4, 'It was everything that I needed but took a little longer to ship than I anticipated');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (361, 38, 175, 5, 'My favorite piece of furniture I''ve ordered from Amazon!!! I ordered two of them to renovate my breakfast nook area with a banquette/booth style dining. It is so elegant and yet give a very comfortable homey feel. I''m able to now sit more people in this area as we gather with family and friends often. My only suggestion is to make sure that you put stain guard on it. I would have loved if it was a little darker in color, but the stain guard I put on it immediately worked. No issues thus far! FYI- the legs to this furniture are INSIDE the black underlined velcro piece under the couch. I thought they had shipped it without legs at first.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (362, 49, 148, 5, 'This sofa tray works extremely well for having such a simple and elegant design. It''s not ugly and overbearing like the plastic ones that seem to be the most common. I use them as both couch arm trays and ottoman trays! However, note that if you have a &#34;round&#34; couch arm, this won''t actually work well for you, since it will conform to fit the shape of whatever it''s sitting on. The seller is also wonderful and has great customer service!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (363, 43, 62, 5, 'Nice lightly  scented citronella candle- soy blend - I love it, but mosquitoes hate it!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (364, 3, 120, 5, 'I absolutely love it!!!!!  The stool is comfortable.  The space on the sides is enough for brush holders, mirrors, etc.  And the mirror is  huge!!!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (365, 36, 24, 5, 'It really looks good in the kitchen.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (366, 33, 192, 5, 'great love it thanks---pt');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (367, 41, 10, 5, 'great');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (368, 46, 88, 5, 'I am sleeping great. Would buy again.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (369, 32, 27, 4, 'It''s a smidge smaller than I thOught but it''s beautiful and perfect for my entry way. Easy to clean. Seems sturdy enough for its purpose.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (370, 41, 86, 4, 'Great price for a great frame.  One of the pieces was slightly bent, but it was a great deal on the price.  I was very please with the quality for the price.  KING frame for some Kind Mattresses.  As I say in some of my other reviews, I checked out the town I have lived for 25 plus years and found some king bed frames for 5 or 10 times the cost that I found it on AMAZON.  I am not sure that I want to pay that much for the convenience of having it the same day in the little town of overpriced Elko Nevada.  I live in a mining town with mining prices but the with convenience of standard stores such as wally world, albertsgirls, rileys, and many furniture stores.  With the internet, why would I want to pay upward of tens times the amount for the same product.  Does it truly cost that much more to unload it from a truck into a store?  I simply say, it is a great frame for a great price.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (371, 48, 133, 4, 'This table unfortunately arrived with no assembly instructions, but I managed to figure things out.  I have a big chair-and-a-half that has arms that are taller than most arms on a chair.  Most of the C tables are not tall enough to use with my chair.  I found this table, with adjustable height, and it really fits into my décor as if I planned to use it all along!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (372, 20, 153, 5, 'This is Crazy Aunt Mary''s new mantra! A great novelty sign -- a &#34;must have&#34; for collectors and drinkers alike!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (373, 17, 35, 2, 'Not worth the money. It looks good but the material is cheap. I ordered 2 of these and one came with a missing piece. I was still able to assemble the drawer without the piece. And now I don''t see an option to contact the seller for this order on my amazon account unlike other orders. That''s what is pissing me off.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (374, 15, 76, 5, 'I bought this in full-size for my teenage grandson and he just loves it. He said it''s the most comfortable bed he''s ever slept on - now his little brother wants one...so do I!  It''s a great price for this product when you compare it to other brands too. It is delivered all rolled up, but easily unpacks and is ready to use in no time.  BTW, keep in mind that these mattresses are designed for platform beds. The manufacturer does not make boxsprings for this mattress. Thanks, Amazon, for a good deal.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (375, 34, 49, 5, 'Love these tables very well made, nice and heavy. They are well built.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (376, 35, 44, 5, 'Easily assembled pretty little table that I used in a tiny en suite bathroom in our house. Love it..recommend it for those who need a small table with a bit of storage. Will go anywhere, could be a bedside table, an occasional table, or a little bit of storage in a postage sized room with none at all. Very, very happy with it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (377, 30, 131, 5, 'Great gift! Well made. I''d order again.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (378, 34, 186, 4, 'just what we expected');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (379, 21, 148, 5, 'I''m using this under my flat screen tv that is mounted on the wall.  it holds my component''s and looks great too.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (380, 31, 48, 5, 'So after reading so many great reviews about this mattress, I decided to go ahead and order it. I was going to order directly from the company but remembered Discover had a promo for 5% back on Amazon purchases. Shipping was fast! The mattress came to my doorstep within a few days. Setup was easy... you basically just cut open the two layers of plastic that it is wrapped in and let the mattress expand. The mattress is on the firm side, which I kind of prefer, but it took about a week to get used to the mattress. After that, everything was awesome. I used to wake up with back pain with my old memory foam mattress, but that totally stopped after I started sleeping on the Tuft & Needle mattress. Very happy with this purchase!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (381, 48, 127, 4, 'like the desk a lot, was a little disappointed that the holes weren''t drilled deep enough for some of the pegs, even with a hammer tapping it in, some of the pegs popped through the other side of the particle board. luckily it wasn''t in a spot that was out where you can see! shipping was fairly fast, good customer service.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (382, 45, 63, 5, 'Perfect for my 5 year old. Was nervous with the negative reviews. Very happy with the purchase!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (383, 23, 76, 4, 'Good enough for the money.  Not super comfortable--I am used to a Herman Miller that cost more than 10 times this chair.  It is good enough for a few hours but may not be sufficient for all day seating.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (384, 45, 34, 5, 'So I wanted a cheap mattress for a daybed in the guest bedroom.  So I figured I should try it out and sleep on it, and this is probably the most comfortable mattress I''ve ever slept on.  I''m impressed.  I''ll probably buy another.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (385, 48, 148, 5, 'Great desk for the price.  Small, but exactly what we were looking for.  My son (middle school) is thrilled to have his own grown up space to work on school work and play minecraft, lol.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (386, 29, 28, 4, 'The only drawback is the mouse pad doesn''t fit on the tray along with the keyboard.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (387, 32, 170, 5, 'Easy to put together. Good and sturdy.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (388, 3, 92, 5, 'This is a beautiful chair...I was looking for a leather MCM chair and found many that were over this price point.  There were no reviews, so I thought...let''s give it a try!  I am soooo glad I did....the leather is beautiful...wood looks very similar to the picture.  I am actually thinking about getting another of the same to place around my fireplace!  It took a couple of weeks to arrive, but that is ok.  I needed to schedule a time to be home when it arrived to inspect before accepting the piece.  Overall, VERY happy with this chair!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (389, 23, 5, 5, 'Beautiful chest.  My son put it together without any problems and it is just SO pretty.  No issues with construction quality.  I love it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (390, 17, 135, 3, 'exactly what I wanted and fairly easy to put together');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (391, 39, 191, 4, 'So far so good, used carpet tape and secured them to the stairs, color is good, so far has held up ok.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (392, 41, 113, 5, 'Great seating for working at a raised counter top service desk.  No problems.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (393, 26, 73, 5, 'Comfortable chair');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (394, 44, 179, 5, 'Perfect, just what I need .. very well constructed too.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (395, 24, 29, 5, 'Great chair.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (396, 26, 83, 1, 'missing parts');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (397, 34, 174, 3, 'Sturdy desk for the price. Only complaint - the base for the PC is a bit annoying as it takes up leg room and I tend to kick it a lot.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (398, 42, 178, 5, 'Put this together over the weekend and am already in love with it! I love the openness of the layout and it is quite sturdy. There is so much space on top for lots of work and the shelves are quite large as well. Overall this is a great product and I am so glad that I purchased it!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (399, 3, 139, 5, 'Great product and fast delivery.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (400, 46, 71, 1, 'chair broke 3 months after purchase. How do I get refund on this one?');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (401, 36, 86, 5, 'Very well made.  I love the southwest design - not too busy.  This is a re-order - I liked the first one so much I ordered it again.  The rug is very durable.  Thanks.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (402, 36, 107, 5, 'Cute as a bug. This step stool is cute just sitting around. I hoped my cat would hop up on it to get to my bed since she is getting to be a senior cat. But so far she just sniffs it. But...all is not lost, in time I think she will use it and meantime it is cute sitting around. I like idea of not having to put it together, it folds very thin and opens very easily.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (403, 10, 37, 5, 'Our front entry carpet kept getting caught under the door, and now works perfectly!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (404, 15, 113, 5, 'Perfect for my grandaughter.  I like the safety design and it''s perfect for my small apartment.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (405, 11, 194, 5, 'Very pretty screen!  Stable on carpeting- I''m using it to hide gym equipment in my bedroom and its works great for that.  The wood is black- didn''t realize that when I ordered it-');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (406, 45, 75, 4, 'I just got mine and finished putting it together!  It looks fantastic and was exactly what I was expecting.  Only downside was the delivery was a little tricky and came about 6 days after estimate.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (407, 39, 56, 2, 'it''s cute if you just need a side table, but awful as a workstation. don''t most people want their mouse and keyboard on the same level? i know the picture shows the mouse on the main desk and the keys underneath, but it didn''t hit me until i tried to work there.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (408, 30, 123, 5, 'A full size mattress is approximately 72-inches long by 54-inches wide, and this set was advertised as being 8-inches thick.  When this set arrived, in two boxes, I went back to the listing thinking that I had misunderstood the listing.<br /><br />The box for the spring was only 54-inches by 47-inches by 5-inches.  I felt that there was no way an 8-inch spring could fit in it.  I was certainly surprised when we unfolded the spring and it expanded itself to a full size and 8-inch thickness.  I did not look closely to see how this transformation was accomplished, but just looked at it in wonder.<br /><br />Similarly, the mattress box measured 18-inches by 18-inches by 39-inches.  Again, certainly not large enough for a full size mattress of 8-inches thickness.  Once again I was totally surprised.  The mattress was rolled into a tight roll.  When we removed it from the box and unrolled it on the bed, it self-expanded to its full size.<br /><br />I have been sleeping on it for about two we');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (409, 29, 82, 5, 'This item is great! I have another rolling garment rack, but it''s not nearly as heavy-duty and nice as this one. I am very pleased with this purchase. Exactly as described. I would absolutely recommend it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (410, 41, 101, 1, 'Of all my amazon purchases...this was an expensive pile of kindling wood!arrives in literally 4dozen pieces...instructions terrible...and boards were warped .by the time I got around to sending it back was too late.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (411, 45, 180, 5, 'great mirror and easy to but together');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (412, 46, 179, 2, 'Certain holes didn''t match up to attach it to frame.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (413, 16, 179, 3, 'I like this item but have to return it.  Not sure if I want a replacement.  The hardware to put it together are wrong.  It came in different boxes for the top and the base so many that was the disconnect.  The feet are unstable because the peg on the feet are too small to fit into the base holes which are larger making it unstable.  I tried to get new hardware but was told to send it back since Amazon could not contact the manufacturer.  It is from Vietnam.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (414, 11, 111, 4, 'such a great price for the quality of the product!<br /><br />only wish the sticks in which the headboard needs to be attached to would be longer so the height could be adjusted for slightly higher beds.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (415, 37, 39, 1, 'Not worth reviewing.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (416, 3, 69, 4, 'Me and my 7yo daughter put this beast together. It was very simple and its very sturdy. Only problem was the laminate on the desk top was coming up in the corner. That was an easy fix for me.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (417, 50, 157, 5, 'Love the look of this! Easy to put together by myself.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (418, 24, 24, 5, 'Looks nice, easy assembly,and sturdy');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (419, 47, 36, 5, 'I absolute love it.....I built it myself was very easy....very happy');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (420, 32, 4, 2, 'Uneven doors after assembly, had trouble with latches, cheap product. The handles are beyond cheap looking, tried to dress it up by buying nicer ones...but they don''t fit!!! So frustrating. Save time and money do not buy.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (421, 30, 66, 3, 'Does the job we needed it to do. Sturdier feeling than the cheaper non elite version,however, frame was bent when received. Luckily my husband was able to straighten the affected area, as I wasn''t looking forward to having to send it back.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (422, 29, 59, 5, 'This is a great chair that takes up little room.  Nice for small office in house.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (423, 23, 119, 5, 'Good stool. It''s good quality');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (424, 27, 18, 4, 'Attractive. Better looking even than photo. Well made.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (425, 47, 138, 5, 'Overall we are very happy with the box spring. I did not think the wood was low quality which I had read in other reviews. It was very easy to put together and even included one set of extra bolts, nuts and screws. I also liked the added bonus of the cover.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (426, 20, 92, 1, 'Worst rug ever! I bought the Safavieh Courtyard Collection chocolate border rug and runner. They are very stiff & rough. Definitely not for indoor use. The stitching isn''t straight the rug had flaws in stitching. I returned this but Amazon charged me over $11 for return shipping. Such a ripoff for a piece of junk!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (427, 43, 78, 3, 'The construction of the table is solid. All the components fit together correctly. However, the chairs pose a problem. Connecting the seat onto the chair is a total disaster. Instead of embedding a bolt or connector into the bottom of the seat body like it is in the body of the chair, there is only a set of wood screws to work with. The screws are screwed in less than 1/16th of an inch into the seat which is not enough length to hold the seat in place securely.  Also, there is a tremendous problem positioning the seat onto the structure of the chair. You are left to guess at where to position the seat and where ever you position the seat it still does not line up correctly. East West definitely dropped the ball on this one. Fitting the seat onto the chair is total guess work and it can never be positioned correctly. East West put all the burden on the assembler. This problem could have been solved if East West had  embedded bolts or connectors into the body of the seat bottom.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (428, 26, 159, 5, 'Love seeing the organization under my sink. The plastic vented shelves are nice to store damp sponges. Can find cleaning stuff so easily now. Sturdy, plastic organizer that does the job.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (429, 29, 42, 5, 'Great for at-home-salon and fun for the kids.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (430, 26, 124, 5, 'its a big white roll of cloth that my wife and i walked on.  it worked great, and was super affordable!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (431, 24, 32, 4, 'Easy to assemble, all the parts were included.  For the less mechanically minded, it might have been a little more difficult to assemble due to very basic instructions.  Well made.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (432, 34, 97, 5, 'This is a fantastic rug for the price! It arrived quickly and is just what I needed! It looks so pretty.  I would definitely buy again! Just a quick note though: if you don''t have anything heavy going on it (I have a coffee table on mine) then I would suggest purchasing a no slip mat for rugs to go underneath it. :)');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (433, 4, 137, 5, 'Its the perfect height for what i wanted!  tall, sturdy and real wood!  to be honest, it would have taken me like 10 days and 30 phone calls to put it together myself, but it was a little beyond my scope of carpentry knowledge... but with the help of a handy friend, we got it put together within 1.5-2 hrs.  so if you are like me and not that handy... find a friend!  but i love it!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (434, 11, 104, 5, 'WONDERFUL product!  No more hurting their feet on flimsy sides of bunk beds -- idea for college dorms too.  My daughter put this together by herself in 15 minutes.  Sturdy, nice looking and does an excellent job!  Thanks!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (435, 21, 14, 4, 'Nice little table.  It is solid and looks just like the picture.  It was easy to setup.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (436, 22, 47, 5, 'This is a beautiful rug. The picture doesn''t do it justice as the colors are so vibrant and id''s made very well. I am so happy with it that I am going to order a few more!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (437, 49, 143, 4, 'The only problem with the chair is the seat pad is at a flat angle and should be slightly inclined for better ergonomics. I fixed it with a simple wedge.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (438, 48, 17, 5, 'Works great. Replaced plastic legs nicely.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (439, 45, 106, 1, 'Not the same as the one I ordered on the picture so I am really disappointed because the one I got has colours in it and not a clear mandala motiff like the one in the pic so now I have no where to put it as it clashes with all my decor :(');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (440, 18, 105, 5, 'Durable, comfortable and easy to assemble!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (441, 24, 95, 4, 'Love this chair, very comfortable, curved slightly so it doesn''t feel to stiff. Only downside I have is the back of the chair has weird plastic circles everywhere which is kind of distracting. Would have liked it to be completely smooth like the front.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (442, 13, 119, 4, 'cool rug for the kitchen');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (443, 16, 147, 5, 'Exceeded my expectations.  Not too hard to assemble.  Good price for quality.  I still hate that I am buying goods from overseas, but prices are so reasonable.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (444, 28, 15, 3, 'Shipping was slow but other than that happy with product');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (445, 13, 14, 5, 'Came on time as expected.  I needed a little extra muscle to help line up the screw holes on the back and seat when attaching the arm rests.  It went smoother attaching the arm rests to the seat back first.  It is very comfortable.  Good quality for the price.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (446, 13, 21, 5, 'This is the 2nd time we''ve ordered from Way Basics. The cubes turned up a few days early on both occasions, which was great, and they were exactly what we wanted.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (447, 48, 154, 4, 'Seems a little cheap. Pretty flimsy. Get the stands if available');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (448, 35, 93, 5, 'Very good quality for the price.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (449, 37, 108, 4, 'All items were as they said they''d be. The rug feels & looks great!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (450, 17, 112, 5, 'Noticeable cushion, holds well, good price. Had it for about a month. Will buy again.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (451, 36, 180, 1, 'Horrible.  Fell apart with less than normal wear after only two months.  Only one adult slept in the bed.  I also agree with another reviewer that the &#34;edges&#34; are sharp and seem to have been just in the right place to catch a shin on them.  I say &#34;been&#34; because it is in pieces in my dining room after unsuccessfully trying to replace the joint screw/lock combination to put it back together, I will be throwing it out.  WASTE OF MONEY, TIME AND EFFORT.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (452, 38, 123, 5, 'We have had a baker''s self for about 8 or 9 years. Of course we outgrew the hooks that came with the unit. I had no hope of finding additional hooks after all these years.I was so happy to find these. They work perfectly');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (453, 19, 64, 5, 'My wife has short legs so when she sits on a plane, her feet barely touch the ground. She said this was great and helped her relax. Compresses down to a small size for traveling too.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (454, 50, 141, 5, 'Easy to put it together and quite comfortable.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (455, 47, 104, 5, 'Received as described. Nice addition to the studio apartment.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (456, 15, 123, 5, 'I purchased and received within days.  Product came packaged securely with no defects.  My wife put it together by herself and she said it was fairly easy.  Looks exactly like picture.  Hopefully it lasts a good while');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (457, 17, 62, 5, 'This is a great product really holds up to the standard of a king size bed');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (458, 31, 42, 5, 'This is nice.  Good value');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (459, 10, 116, 3, 'I like the chair, however it is not built very well. I like the lumbar addition & the leather is ok, but the chair tilts slighty to the right. You can''t tell unless you do a full turn in the chair. We did not mess up on assembling it, so it is some kind of defect. It''s rather annoying actually.<br /> I would not recommend it. You are better buying a chair from a store, so you can return if any problems.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (460, 39, 18, 4, 'Furniture was as expected and easy to install.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (461, 33, 21, 5, 'The arctic dream mattress is 10” of total comfort and restful night. Of the 10”, 3” of it is cooling gel on top and 6.25” of polyurethane foam and top with .75” of really nice soft quilt. I honestly feel like I’m sleeping on a really expensive mattress that should have cost me in the thousands but this bed is affordable. Sometimes you have the mentality of “You get what you pay for” but this is an exception. The bed is a nice quality bed, comfortable, thick, and firmer than most pillow top mattress. The first night I slept on it, I notice that it didn’t take me long to fall asleep. I didn’t toss and turn like I did with my previous mattress. I also didn’t sweat or felt like I was heating up. I had this mattress for a month now and I still felt the same way when I first got it. I think this is the mattress worth investing in because it comfortable and the price is reasonable compare to other memory foam cooling gel mattress on the market today.<br /><br />*Received this product at a dis');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (462, 16, 99, 5, 'Comfortable chair throughout the work day');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (463, 14, 75, 1, 'Furniture came in box broke and ripped pieces were a mess. Because box was so bad had nothing to box it back up in to ship back. Would not buy it is not worth the money should of went to walmart.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (464, 23, 4, 4, 'Lovely piece of furniture, a bit of a pain to put together.  Customer Service is excellent! Desktop arrived cracked and it was replaced within 3 days');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (465, 40, 185, 3, 'While the bar stools themselves are quite nice, the packing left a lot to be desired.  Both bottoms of the set were damaged, one subtly, and one quite obviously.  The third party seller was quick to send replacements which was much appreciated, unfortunately before noticing the subtly dented bottom we had already put the stools together, and can''t manage to unseat the bottom in order to replace it with the new one.  No big deal I thought, the damage is slight so I''ll just put together the other bar stool with the very clearly dented bottom with the new bottom and be happy, since that one I noticed before assembly.  Unfortunately, the replacement bottoms are a good inch in diameter smaller than the original bottoms!  Now I have mis-matched bar stools.  My own fault for assembling the first one without a close inspection.  All of that being said these are good bar stools and very worthwhile for the price, but do a VERY detailed inspection of the bottoms for dents before putting it togeth');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (466, 40, 174, 4, 'This table really works!<br />Just remember to flip the switch.  It would have been nice to have a little more &#34;cord&#34; room, but I love it just the same and use it every night for my phone and my tablet.  The underneath storage is also super handy.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (467, 38, 42, 5, 'In great shape! And, it arrived before the estimated time so I was able to use it when I needed it! Comfortable to sleep on as well!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (468, 16, 98, 5, 'I love this mattress!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (469, 4, 26, 4, 'Good rugs but not as heavy as I would have liked.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (470, 45, 41, 4, 'This is a nice looking chair.  It sits well, and is a good height.  The seat is quite large.  The stripes do line up well on back of chair with seat of chair.  The boxing stripe on the seat cushion is a little skewed.  Wish that were not so.  The chair is fairly easy to put together.  Do not be in a hurry to put it together.  Do not tighten the screws as you go or you will have issues with parts aligning.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (471, 27, 53, 4, 'I live in a small apartment, and like many small apartments, this one doesn''t have a separate dining area.  I have a tiny corner of the living room with which to place a dining table – so I really needed one that was nice and compact.  However, I also wanted one that was big enough to serve as extra table space for when I''m working on prepping a larger meal (because, yes, the kitchen is tiny, too).  This was a bit of dilemma before I struck on the idea of getting a table with drop leaves.  Unfortunately, it seems that smaller tables with drop leaves are somewhat hard to find, but after much searching, I came across this table, the &#34;Winsome Wood Hamilton Double Drop Leaf Dining Table.&#34;<br /><br />The first thing I love about it is its smaller footprint – it measures just 30&#34; by 26&#34; across with the leaves down, and 30&#34; by 42&#34; across with the leaves fully extended (do keep in mind, though, if you happen to be trying to jam this into some tiny niche, that when the l');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (472, 37, 112, 5, 'I decided to get the arctic dreams 10 inch cooling gel foam mattress by DreamFoam Bedding. Here''s what I think about it.<br /><br />* Queen mattress<br />* 10 inch<br />* made in the USA<br />* cooling gel foam<br />* 3 inches of gel foam<br /><br />When this box was delivered I was highly skeptical. It honestly didn''t look at the size of a large twin. We unleashed it from its packaging. With in two minutes it had expanded to be a 10 inch mattress. It was truly amazing. I''m still scratching my head over that one.<br /><br />Some people are going to doubt buying a mattress over the Internet. I had the same thoughts myself. This mattress is made in the USA that''s some reassurance in itself.  It is absolutely everything it advertises to be with no doubts.  It consists of high quality materials. If I was to need a mattress in the future I will definitely purchase from this company again.<br /><br />I have been sleeping on it now for 10 days. I wanted to wait a bit to ensure I had enough ex');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (473, 20, 15, 5, 'Very easy assembly and a great looking bed');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (474, 18, 166, 1, 'Not a good investment. The old saying you get what you pay for is true in this case. Two of the slate inserts were loose and the others two were not centered and had the cement on the top and around some of the sides. No effort to size the slate to fit the opening. The finish appears to only have a single coat and has a lot of nicks and pits. The table is also not level when assembled. The top will not hold much weight because of the way it is constructed. If you push hard on the top it will fall through. If I had kept the shipping box I would have sent it back.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (475, 3, 109, 5, 'So comfortable');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (476, 15, 73, 5, 'very nice, solid construction. good quality. easy assembly!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (477, 36, 86, 5, 'Heavy as Heck!!!  We have moved it several times, use it daily.  Memory Foam is hot in the summer, but when winter comes it is a girls best friend.  Love the compartment for remotes. (Now they don''t get lost) and the drink holders have plastic inserts for easy cleaning.  Love this best purchase ever.  Next year... I will buy another one for my teen age boys.  :0)');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (478, 24, 112, 3, 'Love the look of the bed but one of the main reasons it was purchased was for the drawers shown in the picture. The drawers are sold separately but it''s not clear when you order and nothing prompts you to add drawers to your order so pretty disappointed in that. We would have bought the drawers separately had we known we needed to because I think it''s good quality');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (479, 19, 197, 2, 'It is quite nice rug, however it is pretty thin and not stay in shape');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (480, 35, 198, 5, 'Much better than shelving.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (481, 14, 14, 4, 'First the headboard and footboard are very pretty and well made. They are both a heavy metal with good welding. I gave it 4 stars for the look, but would give it 3 for the process of assembly. We already had a generic bed frame and thought it would work if we also purchased some foot board extensions. Our frame is just a hair too low for the bolt holes and the footboard holes did not match up. We had to purchase some modes to make it sort of work. It is all put together but they both lean inward because of the size difference in the frame.<br /><br />To make a suggestion. Try ordering the generic frame from the same company and maybe that will work better. Maybe.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (482, 45, 135, 5, 'Beautiful rug - just what I was looking for!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (483, 20, 6, 5, 'Thanks for completing my set.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (484, 38, 133, 2, 'The TV trays, overall, are nice but I''m not sure if they''re $175 nice.  As mentioned in other reviews, the stand is very dysfunctional, does not assemble well, and does not hold the trays well.  I emailed the company to give them feedback and never received a reply.  Hmmm...');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (485, 23, 117, 3, 'flimsily.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (486, 26, 200, 5, 'I''ve used this chair for 8 years now. Mine is starting to wear out (nothing that is irreplaceable, the material on the arm rests wore down, and I''d like a taller gas lift, etc).<br /><br />I''ve been looking around for parts for the chair for awhile and am not having much luck. It appears the older model (the one pictured) was discontinued awhile back. Luckily the 2 things that need work are not too hard to do without the official parts. I will just re-upholster the arms and I believe I can find a compatible generic gas lift.<br /><br />So why bother to review? Because this chair is solid (I weigh 250-275, varied throughout the years) and will last you a long time. And NO ONE else seems to offer this swinging seat base. Understandable as it requires a lot of metal to make it that strong and design companies don''t want to deal with a lot of heavy shipping (and it isn''t the prettiest thing in the world). However this seat literally makes the difference for me to be able to sit at my compu');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (487, 19, 188, 4, 'Ok');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (488, 25, 92, 5, 'I have to admit that I was skeptical about this bed but wow was I surprised.  It is well made, huge and definitely makes a statement.  It arrived in two very large boxes but it was well packed and the contents had no damage.  It took 10 minutes to unpack and inventory the parts, very few parts considering the size of the bed.  The assembly took under an hour from beginning to end.  I would definitely recommend an electric screw driver, the supplied allen wrench will do the job but it will take a lot longer.<br />Well worth the money and time to assemble!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (489, 27, 140, 3, 'Very pretty chair. Love everything about it except 2 things...it''s a little short and the color isn''t exactly grey grey. It looks a little between a grey and a dark blue jean color. Sometimes it looks more Jean blue. Other than that it''s nice and cute. If it wasn''t for the color I''d give it more stars.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (490, 13, 47, 4, 'The bed is perfect as a guest bed. The only downside is that it is too low to the ground. Other than that it was just as I expected it to be. Would sure recommend it to others.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (491, 29, 14, 5, 'Very nice, and well built');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (492, 14, 87, 2, 'I haven''t purchased a Sauder piece in a long time and now I remember why.  There are other budget pieces of furniture out there in the same price point from different manufacturers that are so much better in quality.  I have put a lot of furniture together and despite following the directions to the letter and tightening every screw, the whole thing still wobbles.  This table is garbage and if I didn''t spend so much time getting it together, I would return it.  I don''t see how it would stand up under any sort of moderate to heavy use.  Good thing it''s only holding my son''s alarm clock and a few stuffed animals.  I won''t buy Sauder again.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (493, 44, 77, 5, 'VERY nice and sturdy! Great price for very nice quality bar stool!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (494, 21, 8, 5, 'My students LOVE it! I got it for my high school classroom. The students lit up when they saw it and LOVE lounging in it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (495, 28, 196, 2, 'Perfect the price and area I put it :)');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (496, 46, 4, 4, 'It''s a great bang for the dollar');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (497, 44, 178, 5, 'Looks great and allows you to create a custom shelving due to shelf placement');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (498, 39, 146, 4, 'Assembled this desk over the weekend. The picture doesn''t really do it justice. Once this desk is assembled, it is very sturdy and stable. Assembly was a little problematic because the line illustrations at times were not clear and written instructions didn''t always tell you which direction some of the parts were supposed to attach. Also, a couple of the screw holes did not line up correctly. But all of the parts were clearly labeled and the desk wasn''t so complicated that we couldn''t figure it out.<br /><br />I really like the power strip holder in the back of the desk, as it keeps all of the cords out of the way and prevents having to stretch cords to plug devices in. The front drawer has a nice little space to keep all your gamer fobs for logins (for games like WOW and SWtOR). We are using a small side stand to hold the CPU for the computer, as there is not enough space on the desk for an actual CPU unit.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (499, 44, 115, 4, 'Looks pretty good on a chair that needed help.  On the chair handles I used black Gorilla tape.  The cover was really easy to put on and best of all it''s washable!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (500, 50, 56, 4, 'You get what you pay for, they work but they are a little small and flimsy, overall I''m happy.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (501, 10, 56, 5, 'Great birthday gift for a young adult.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (502, 32, 44, 5, 'It''s an Amazon gift card and with over 982398324908 items I am sure you will find something you love.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (503, 50, 129, 5, 'Good');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (504, 4, 60, 1, 'Fair');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (505, 24, 171, 5, 'I can''t believe how quickly Amazon can get these into my hands!!  Thank you!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (506, 49, 82, 5, 'Perfect!  Nice & easy plus everyone loves them.  This is one gift you''ll never have to return!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (507, 50, 116, 5, 'excelent');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (508, 35, 68, 5, 'Great and Safe Gift Giving');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (509, 41, 81, 1, 'What?????????');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (510, 32, 156, 5, 'This was just too easy~click & print!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (511, 43, 135, 5, 'Bien');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (512, 38, 182, 5, 'Easy to print from email.  I love the variety of cards available for print on demand.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (513, 39, 32, 5, 'Amazing with 10 dollar');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (514, 42, 138, 5, 'Remember Matthew 7:21');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (515, 35, 187, 5, 'good');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (516, 24, 31, 5, 'Awesome way to send a gift card!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (517, 12, 170, 5, 'I love that I have instant, helpful options when I forget a birthday! Thanks for saving the day Amazon!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (518, 27, 98, 4, 'Good gift. Easy to use. Relatively instant.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (519, 48, 87, 5, 'Satisfied as usual<br />Thanks Amazon');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (520, 33, 84, 5, 'nice');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (521, 12, 117, 4, 'my nice was quite suprised that it was a card and gift card all in one.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (522, 3, 25, 5, 'Good!!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (523, 23, 106, 5, 'is what it is');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (524, 42, 144, 5, 'Normally, I don''t like gift cards conceptually but the Amazon GC is an exception! Giving today is not the same as giving yesterday. Now, everyone knows (better than the giver) exactly what they want. The Amazon card gives them the privilege of selection, shopping online for home deliver, and the option to redirect the funds as they see fit! I now give gift cards through Amazon to anyone who shops on Amazon and does not object to this kind of gift.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (525, 39, 13, 5, 'Wow.. Thank you. Love this gift.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (526, 48, 20, 5, 'Amazon saves the day again!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (527, 4, 103, 5, 'Love it!  It is a space saver for our small kitchen.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (528, 22, 124, 5, 'It was colorful and just what my birthday person wanted');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (529, 26, 198, 5, 'Was simple and easy.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (530, 24, 126, 5, 'Worked well for a quick delivery birthday present!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (531, 26, 173, 2, 'I wanted the gift car4 for MUSIC not movies.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (532, 15, 34, 5, 'GOOD');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (533, 22, 104, 5, 'Good');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (534, 48, 57, 4, 'This is a great way to give a gift card and print it up at home.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (535, 38, 73, 5, 'i am artist');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (536, 21, 80, 5, 'Amazon gift cards are nothing new, and they are very handy to give as gifts due to the diverse nature of products Amazon offers – certainly your recipient can find something he / she will like to order.<br /><br />These gift cards, however, are a little more classy than the standard email or printed-off versions at home as it shows you went a little further, the card is in sturdy packaging, and I appreciate the fact Amazon delivers it for free with next day shipping. If you’re going to be spending $10 or more for a gift card, and have more than one person to give a gift card to, I would recommend you purchase this set of three to your recipients. On the other hand, if you are going to be spending $50 or more on an individual gift card, you may want to consider the gift box option.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (537, 43, 89, 5, 'Very easy to use.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (538, 41, 142, 5, 'Gave it to my son and his new wife as he, especially loves Amazon alot.  Was really happy about it. Thanks!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (539, 19, 165, 5, 'OK');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (540, 32, 119, 5, 'Nice!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (541, 10, 76, 5, 'We needed a present for a friend of ours who decided to invite everyone over on a Sunday spontaneously. Here in Germany stores are closed on Sundays so this was a great alternative, especially since you can just print it at home. Great present without excess packaging that''ll just end up in the trash anyway.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (542, 26, 94, 5, 'Excellent.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (543, 41, 96, 5, 'Great way to please every one! The kids can get what they want and no sweat about color, size, or fit.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (544, 46, 182, 5, 'good');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (545, 50, 15, 5, 'Printed up just like picture.  Very user friendly.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (546, 48, 29, 5, 'Ok');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (547, 11, 124, 3, 'Hey if you looking to make an extra 20.00 check the link its free but only if you load 40.00 or more [...]');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (548, 3, 93, 5, 'Great! My daughter loved the card more than the gift card😄');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (549, 36, 27, 5, 'great');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (550, 48, 92, 2, 'I was disappointed as when I received it,Golden ribbon was not there on one of the box and I was not having enough time to send it back.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (551, 43, 8, 5, 'Great and easy');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (552, 14, 34, 5, 'Super easy to add money to a gift card!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (553, 21, 91, 5, 'This was amazing');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (554, 17, 86, 5, 'Always good');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (555, 14, 177, 5, 'Easily done. :)');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (556, 50, 171, 1, 'I had no idea that the amount is listed in US dollars. I ended purchasing US $100 instead of CAD $100, which meant extra $30CAD.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (557, 47, 149, 5, 'Nice service...');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (558, 23, 28, 5, 'An Amazon gift card is always a Happy gift, good for any occasion, and always well received.  Everyone loves to shop!!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (559, 13, 92, 4, 'Nice card, easy process to generate and print.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (560, 16, 49, 5, 'I gave this to my dad. I assume that it provided my dad with $25 in Amazon credit. He loves Amazon, so I give it 5 stars as assuming that it fulfilled it''s only function.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (561, 13, 121, 5, 'My sister loved this it was a birthday gift and she was absolutely thrilled!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (562, 41, 29, 4, 'Good way to gift');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (563, 49, 84, 5, 'Nothing too complicated. It was easy as 1, 2, 3. :) This is more convenient for those who don''t want to buy gift card after gift card.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (564, 10, 178, 5, 'This was just the kind of gift card I was looking for, the right color and beautifully designed!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (565, 21, 159, 5, 'Thanks.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (566, 36, 156, 5, 'Good way to send gifts');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (567, 27, 21, 5, 'It was fast and hence, I loved it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (568, 29, 39, 5, 'Works all the time. Right color and right size');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (569, 50, 146, 5, 'I gave this gift card for a trunk party. This way the young person can order what they want and have it shipped to their school and don''t have to pack/transport items on the first day.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (570, 48, 23, 5, 'Prompt delivery. Easy to purchase and recipient was very pleased by quick delivery.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (571, 26, 109, 5, 'Can''t go wrong with a gift card!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (572, 12, 110, 5, 'satisfied');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (573, 15, 103, 5, 'Very easy to print!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (574, 35, 159, 5, 'Nice gift');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (575, 26, 89, 5, 'Very Happy. Instant delivery.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (576, 36, 88, 5, 'Easy to buy easy to use.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (577, 48, 194, 4, 'It is very good, timing arrived. Thank you.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (578, 49, 96, 5, 'The email with the gift card arrived immediately after purchase. A great gift to send anyone for any occasion.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (579, 35, 156, 5, 'Good.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (580, 40, 45, 5, 'very easy and fast... living in Canada and giving to my son in the USA, it was great that I could get the gift card in USD.....too bad the exchange rate was so bad, but that is out of all of our hands.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (581, 11, 32, 5, 'Very easy process. Easy way to clear out the old Visa/MasterCard Gift cards with the small balances, which you do not want to nickel and dime at the grocery store.....<br />Amazon makes most things easy.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (582, 47, 143, 5, 'Excellent to handle purchases');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (583, 48, 134, 5, 'great for a quick bday present and printable');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (584, 37, 124, 5, 'Never can go wrong giving an Amazon gift card!!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (585, 39, 95, 1, 'Thought I had a 10% discount as a promotion quote to next purchase.<br />But even after chatting with the customer service representative who promised to send me the promotion code.<br />The code was never found anywhere in my account.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (586, 25, 175, 5, 'Great way to give a gift that is perfect. So many designs to chose from and the card is very easy to print.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (587, 21, 89, 5, 'Gift card was received on time, and recipient was very happy.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (588, 49, 153, 5, 'Arrives quickly!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (589, 47, 169, 5, 'Nice gift');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (590, 36, 110, 5, 'Can''t go wrong with a gift card!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (591, 14, 138, 5, 'good');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (592, 45, 70, 3, 'The box was crushed in the mailing and looked cheap so it was mailed to the recipient in a nice greeting card.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (593, 43, 25, 4, 'yup');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (594, 31, 176, 5, 'everything good');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (595, 16, 8, 5, 'Bought a gift card for my nephews Birthday. Very easy to do. Much easier than going to the store and buying one.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (596, 21, 186, 5, 'Awesome gift');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (597, 25, 183, 5, 'Good as money on this site!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (598, 13, 129, 5, 'great');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (599, 19, 65, 5, 'Suited the person I sent it to  well. Graphics, song, everything was what I expected, and she loved it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (600, 45, 31, 5, 'EASY GIFT FOR STUDENTS AWAY');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (601, 10, 11, 5, 'Fast, easy, last-minute gift!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (602, 20, 103, 5, 'Everyone loves an amazon gift card. Lots of purchasing options.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (603, 32, 36, 3, 'No winners');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (604, 36, 32, 5, 'Adorable and fun!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (605, 29, 85, 5, 'excellent');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (606, 14, 136, 5, 'Amazon gift cards are perfect for birthdays, thank you''s, or any special occasion. Email delivery options are instant so if your running late on a gift it works out!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (607, 13, 200, 1, 'ordered this for a going away party thinking it should be a quick and easy process.  two hours later i called customer service as it still wasn''t &#34;authorized&#34;.  i was told it would be three hours maximum by the rep.  three and a half hours later i called back and was told it may be a full day.  unfortunately, it''s not clear that this there is a significant delay when purchasing these.  otherwise, i wouldn''t have used this service.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (608, 45, 71, 3, 'A mistake on my part-good quality though');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (609, 23, 123, 5, 'Easy to use. I appreciate the convenience.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (610, 20, 121, 5, 'This was a hit!  I love how easy it was to make somebody''s day special without even having to leave home.  Never know what to get my son-in-law but he loves shopping on Amazon, and it''s so nice to know he will be able to get exactly what he wants.  Will definitely be purchasing more gift cards in the future.  Thanks for making this service available!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (611, 32, 144, 5, 'Easy to print up.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (612, 19, 98, 1, 'I''m in italy and i bought a gift card with $ because i had to buy an object that wasn''t possible to buy with €...<br />Taken the gift card i couldn''t finish the order because i am in italy.<br />It'' such a stupid thing!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (613, 12, 112, 5, 'this was for my in-laws. they loved it! . I will buy more this year');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (614, 26, 91, 5, 'Easy to use and loaded right away.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (615, 18, 179, 5, 'Just amazing💙');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (616, 45, 183, 5, 'Pick the card, put in the $$ amount, pay & print -- doesn''t get any easier than that!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (617, 18, 153, 5, 'It''s a gift card.  Yes, it works.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (618, 14, 135, 1, 'The giftcard themselves weren''t the problem - they were cool, and used long ago.<br />The hitch was I bought the cards on Amazon''s 20th anniversary, for a special deal that entitled me to an extra 10$ free, and till this day I have seen no  indication in my Amazon account of the 10$ free coupon.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (619, 22, 178, 5, 'Just great gift. Perfect box 😊  looks nice with good quality');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (620, 26, 116, 5, 'What more can I say....it''s a gift card');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (621, 39, 171, 5, 'Nice!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (622, 18, 75, 5, '5 stars for this<br />Zero star for a order i palced for a UV tub charged on my gift card and never received ,The gift card beloind to my wife was debited');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (623, 20, 10, 5, 'a great job');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (624, 45, 198, 5, 'Great!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (625, 3, 3, 5, 'best gift ever!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (626, 47, 27, 5, 'Easy to order and arrived on time.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (627, 17, 129, 5, 'Gift Cards are always a hit!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (628, 16, 89, 5, 'My brother loved it');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (629, 47, 4, 4, 'It was giving as a gift & they appreciated');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (630, 42, 14, 5, 'I like it');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (631, 33, 164, 5, 'Easy to buy and easy to use.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (632, 38, 197, 5, 'Love Amazon Prime! Customer Service is exceptional.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (633, 28, 11, 5, 'Great for teenagers takes the guess work out of the gift giving.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (634, 38, 168, 5, 'Everything it said it would be? I mean why am I writing a review. It''s a gift card. You litterally get what you pay for.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (635, 37, 18, 5, 'muy buen producto');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (636, 24, 112, 5, 'This was a fantastic and quick opportunity to get the recipient to receive the gift within minutes.  You rock Amazon.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (637, 39, 159, 5, 'done quickly and efficiently, arrived in time for Granddaughter''s birthday.  thank you');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (638, 48, 108, 5, 'Great');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (639, 16, 69, 5, 'This is the perfect way to send a gift that will always please.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (640, 31, 9, 5, 'GREAT way to save up for Christmas');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (641, 15, 123, 5, 'This was a gift for a friend.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (642, 37, 188, 5, 'Easy to use.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (643, 36, 15, 4, 'Cool! But I think I should get interest on the balance!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (644, 4, 168, 5, 'Quick and easy');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (645, 48, 70, 5, 'I have recently sent this card to my fifteen year old granddaughter in New Zealand and my two year grandson in London.  They both loved it!!  No matter how many times I play it, it always brings a smile patricularly as I have a Jack Russell similar to the little one on the card.  What a great idea especially for family and friends living overseas.  Thank you Amazon!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (646, 10, 37, 5, 'You can''t go wrong with an Amazon gift card. My nephew is at that age where he is ready to buy himself things so I sent if for his birthday. He loved it and was very happy with what he purchased. If he got that excited, wait until his next birthday.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (647, 38, 127, 5, 'Such an easy gift to give and so very appreciated.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (648, 30, 76, 3, 'It''s a gift card. Exactly what you''d expect, why does it need a review?');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (649, 41, 188, 5, 'So convenient for last minute gift!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (650, 33, 76, 5, 'Excellent');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (651, 16, 5, 5, 'Arrived on time, cash in was easy.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (652, 24, 155, 5, 'Very easy');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (653, 41, 163, 1, 'I did not order this please cancel and return my money');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (654, 18, 42, 5, 'good');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (655, 33, 142, 5, 'This was a gift for a friend. Sometimes it is difficult to know what to give a person, so the gift card was my answer. I hope that they enjoyed their gift.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (656, 22, 17, 5, 'I stock up on these gift cards to give out as birthday presents for my very large extended family!  The kids get to pick out their own gift and shipping is never an issue because everyone has amazon prime. It makes gift giving so simple and ensures that I don''t buy something the recipient wouldn''t use or want.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (657, 29, 14, 5, 'It was a gift card, so this is going to be hard to review. The plastic on the card was .07 mm thicker than normal gift cards so it has that going for it .');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (658, 10, 103, 5, 'I lovit~!!!<br />Usefull^^');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (659, 29, 163, 5, 'Card received on time.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (660, 30, 14, 3, 'I ordered the gift card and requested delivery on August 2. This was confirmed by e-mail. A couple of days later Amazon informed me that the gift card had been mailed to the receipient on July 31. I was not happy about this change.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (661, 31, 198, 5, 'muy buen producto');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (662, 50, 68, 4, 'Very handy for the person who has everything. They can buy some Kindle books.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (663, 14, 151, 5, 'Excellence');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (664, 19, 40, 5, 'I absolutely love everything about the gift card feature that Amazon has. From the ability to add your own photo to the fact that you receive and email letting you know when the gift card was claimed. The person who receives the gift card even has the ability to send a follow up thank you message! I absolutely love this!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (665, 26, 125, 5, 'Sister loved it, bought a Red Lobster gift card with it!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (666, 24, 63, 5, 'Great gift.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (667, 46, 36, 5, 'My dad loved his bday card!!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (668, 4, 147, 2, 'I wanted this gift card applied to my account, but I cannot find a way to do this.  There is no help available, no phone number to contact, no email address to send a question to.  Please help me with this problem!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (669, 36, 172, 5, 'Great to be able to buy a gift and print it out immediately Waunakee, WI.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (670, 34, 197, 5, 'Cute gift card.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (671, 43, 13, 5, 'Easy; piecy');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (672, 28, 200, 5, 'Fun and absolutely fitting for the person to whom it was sent.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (673, 48, 105, 5, 'Perfect gift for a teen!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (674, 42, 177, 5, 'Convenience ..yes');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (675, 14, 193, 5, 'I am always adding money to m yt? Account and this an easy way to do it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (676, 37, 19, 5, 'Quick and easy gift');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (677, 14, 105, 5, 'Gift card worked fine as I used it on one of my next orders.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (678, 18, 134, 5, 'Good buy delivered on timr');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (679, 36, 195, 5, 'Ideal gift when you require a gift at a short notice. Was quick and easy to print. The ability to include your own image adds a personal touch.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (680, 16, 94, 5, 'Who doesn''t like more perks that come with auto reload 3% free money has me sold.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (681, 45, 62, 5, 'It''s good');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (682, 21, 155, 5, 'All went well. Easy way to give someone in another country a birthday gift.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (683, 50, 67, 5, 'Great birthday gift idea.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (684, 14, 131, 1, 'I had great difficulty in getting my gift card to work; in addition, the person that I talked to at Amazon.com tried to convince me that my gift card had NOT been loaded twice, when in reality it had been.  It took SEVERAL days to sort out the problem and get my product ordered; I may use Amazon.com to shop in the future, but I will NEVER use a gift card from Amazon.com again!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (685, 44, 32, 5, 'Absolutely love the electronic gift cards ... especially when you can upload your own photo. I use them for contests on my blog and website and then upload the cover of the book I''m promoting to the face of the gift card.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (686, 4, 174, 4, 'Convenient gift!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (687, 14, 134, 5, 'Awesome');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (688, 26, 123, 5, 'Perfect and super fast.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (689, 26, 152, 5, 'Works just as advertised, very convenient. I still switch back to a credit card for purchases when I want to record them separately, but this works great for books, ebooks, small stuff.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (690, 14, 46, 5, 'Happy gift');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (691, 50, 118, 5, 'Easy and customizable!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (692, 30, 111, 5, 'Easy, perfect gift!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (693, 42, 66, 5, 'Just great, Everything fine as expected ...');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (694, 17, 64, 5, 'Exactly what it says it was and worked as well as it needed to.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (695, 47, 199, 5, 'I was impressed,the card came very quickly!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (696, 26, 90, 5, 'Granddaughter loved it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (697, 44, 170, 5, 'ok');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (698, 31, 24, 5, 'GREAT PRODUCT');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (699, 36, 55, 5, 'Always the best gift');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (700, 14, 78, 5, 'Super convenient to have a card included.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (701, 12, 19, 5, 'I love sending these to my grandkids and then getting pictures of what they bought on Amazon.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (702, 45, 106, 5, 'What''s there to say, it''s a gift card. It''s great. It was exactly as I expected.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (703, 41, 45, 5, 'Was extremely well received by my son.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (704, 32, 53, 5, 'Love these e-card so! Makes long distance gift giving so easy!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (705, 21, 109, 5, 'This was so quick and easy and went over really well. I love it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (706, 40, 143, 5, 'I love that I don''t have to buy a new gift card. Sadly that''s what I had been doing until I found this easy method. Very quick to reload my balance.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (707, 18, 90, 5, 'Was very easy to purchase and deliver. Printed out the code and sent it in an envelope. Makes an amazing gift for those who shop online.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (708, 41, 161, 5, 'Easy to purchase, easy to use, worked great for me.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (709, 18, 7, 5, 'Easy shopping and receiver can use as they wish.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (710, 48, 175, 5, 'It''s an electronic gift card.  It was highly successful as a mechanism for electronically delivering monetary value to the recipient.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (711, 15, 13, 1, 'Card Didn''t come to me until the next day, and so I didn''t have anything to take to the birthday party. Said they were checking on my credit, but that shouldn''t take that long, and I buy lots of things on Amazon. So don''t rely on the claim that you will get the card to print out quickly. P.S. I have excellent credit!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (712, 35, 116, 5, 'Ideal for sending gifts to family in the US when you are living in the UK. Worked very well.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (713, 42, 151, 5, 'Cool i guess');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (714, 37, 122, 5, 'It was quick and easy to write and print.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (715, 25, 51, 5, 'This was a gift for my grand daughter.  By using Amazon gift  cards for birthdays I am helping my grands to become Amazon junkies too! Lol!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (716, 33, 25, 5, 'The gift card made her laugh and she enjoyed the song');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (717, 48, 155, 4, 'Easy, convenient, and always appreciated. The recipient picks the gift and postage expense is eliminated.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (718, 29, 128, 5, 'It was quick and easy...I like this process..');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (719, 12, 132, 5, 'Very easy way to send a birthday gift when you just dont know what to buy.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (720, 40, 82, 5, 'The card was bigger than I thought, came with a clean, thick envelope, and looked very professional.  Free shipping and no extra charge for the card?  Yes, I will definitely do this again next time I need an Amazon gift card.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (721, 15, 169, 5, 'You pick the amount you want to put on your already dwindling Amazon gift card and the balance is immediately there! It''s so easy anyone can do it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (722, 32, 97, 5, 'Amazing');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (723, 24, 87, 5, 'Gift card is a gift card.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (724, 36, 189, 1, 'Did not authorise payment. My account was hacked.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (725, 40, 136, 5, 'shipped as primised');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (726, 19, 41, 5, 'Great for last minute gifts.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (727, 38, 139, 5, 'good.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (728, 10, 52, 5, 'Can''t go wrong with this.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (729, 41, 56, 5, 'Great');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (730, 19, 12, 5, 'Whenever I get a rebate in the form of a debit card, I just by myself an Amazon gift card and add it to my account.  Then I don''t have to worry about tracking those debit cards and remembering how much I have left.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (731, 22, 114, 5, 'cute animated card');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (732, 15, 92, 5, 'Worked perfectly for a gift for teachers!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (733, 10, 38, 5, 'I was able to buy $10 worth of stuff with my $10 gift card. Amazing!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (734, 28, 138, 5, 'A very easy and convenient way to choose and pay for your fave pics and music--Fantastic!!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (735, 26, 53, 5, 'So simple and easy!  We love Amazon!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (736, 40, 76, 5, 'I like it');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (737, 21, 91, 4, 'Perfect');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (738, 41, 121, 5, 'Instant delivery and spend ability!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (739, 34, 77, 5, 'Excelente');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (740, 49, 158, 5, 'The codes were delivered promptly and I had no trouble redeeming them. As a nice bonus, I was able to purchase more than the value of the gift card and pay the difference with one of my normal payment methods, so you don''t have to worry about a small-value card going to waste.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (741, 4, 50, 4, 'very easy to do.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (742, 12, 117, 5, 'Had to have it &#34;redelivered&#34; but otherwise, great gift.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (743, 13, 68, 5, 'nice');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (744, 48, 52, 5, 'This was the best card firmly friend on his 50th we both have dogs and can relate.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (745, 38, 130, 5, 'It was a great way to give a gift to an avid reader or to anyone who likes Amazon!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (746, 44, 97, 5, 'I was very impressed with the presentation and the service.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (747, 49, 72, 5, 'Everything went smooth as silk!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (748, 33, 140, 5, 'Your cards are wonderful and it helps me so much as I am unable to get out to shop and this way I know the recipient can get what they really want.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (749, 3, 190, 5, 'Very useful!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (750, 47, 43, 5, 'Good selection, and easy to print.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (751, 44, 167, 5, 'What a great stove.  What a wonderful replacement for my sort of antique.  Enjoy it every day.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (752, 42, 161, 5, 'worked great');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (753, 42, 91, 5, 'Part exactly what I needed.  Saved by purchasing myself.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (754, 41, 188, 5, 'Love my refrigerator! ! Keeps everything  cold..will recommend!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (755, 23, 113, 5, 'No more running to the store for ice!  Works perfectly.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (756, 31, 184, 1, 'It would not cool below 55 degrees and has now stopped working all together.  I would NOT recommend this piece of junk to anyone.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (757, 50, 9, 5, 'Works awesome for apt size 110 dryer. Handles load from apt size washer just fine. It does take longer to dry. Electric cost savings over a full size 220 is worth the time. Does not add much humidity unless lint filter is full.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (758, 12, 26, 5, 'exactly what I wanted!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (759, 32, 73, 4, 'AS advertised');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (760, 44, 158, 4, 'It works as advertised, but has poor insulation in the top. Like the 3rd shelf, it comes in handy for small/short items.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (761, 43, 189, 2, 'it''s not worth 22 dollars, I''ve heard it became of some value just not that high.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (762, 4, 137, 5, 'Wonderful! It spins the clothes out fast! We use this with the washing machine just like this in our camper. Great and saves money at the camp laundry.  Just wash spin and hang up.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (763, 28, 136, 4, 'Did the job but didn''t match the original gray wheels.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (764, 30, 105, 5, 'Arrived on time and exactly as described.  Fits my need perfectly.  Very well satisfied.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (765, 48, 119, 5, 'Super');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (766, 11, 82, 4, 'Looking forward to using this product.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (767, 29, 146, 1, 'cheap knock-off. dont waste your time');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (768, 42, 175, 5, 'My wife is looking for a alkaline water machine and she told about this 4000+ machine.I doing a research online and gladly find this  M9. I call them right away and give me a good discount  and upgraded my system with no extra cost.As soon my M9 arrive it is very easy to install.I did a water test and the quality of the product exceed my expectation.I was very happy on my first M9.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (769, 37, 57, 1, '3 of the buttons stopped working after a month of using it. It was used twice a day. Do not recommend it. go use your money for something more durable. Oh and also big plates do not fit in it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (770, 14, 60, 4, 'So far so good.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (771, 43, 198, 4, 'Awesome little fridge worth getting :)');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (772, 41, 95, 1, 'Do not buy!  Recently purchased, water leaks under bottom veggie tray, ice formation also.  Bad design.  Ill be calling LG and wasting time trying to get it repaired.  Really bad for such an expensive refrigerator, stay away.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (773, 38, 5, 5, 'Arrived when promised, perfect fit - water tastes delicious!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (774, 49, 57, 4, 'nice');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (775, 22, 138, 5, 'After watching a video on YouTube, I took the dryer apart and blew it out with an air compressor and now it runs like new.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (776, 27, 143, 2, 'Unit does not keep wine below 50 degrees, ever. Look at another product.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (777, 28, 192, 5, 'This is so very AWESOME!!!!!  Love it!!!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (778, 36, 16, 1, 'The dryer for this stackable unit destroys clothes.  A loose button is found almost every time buttoned up shirts go in the dryer.  The vent holes to the lint trap are very large, and just the right size for buttons to be lodge in to be ripped off.  I have had buttons destroyed and holes ripped open when the buttons get ripped off.  All they need to do is design a replacement piece and I will get to keep my buttons.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (779, 30, 26, 5, 'It was everything I needed it to be');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (780, 50, 105, 1, 'My filter only worked for a week or Two!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (781, 31, 119, 4, 'I''ve had this product for one year and it''s has already stopped working.  I purchased the 3-year Smart Guard protection on it which at first, attempted to find someone to come repair the issue, but instead they are just sending me an entire new wine cooler.  So, I would highly recommend purchasing the protection plan, just in case!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (782, 15, 135, 5, 'Bought this for a rental unit and now considering replacing my hood at home. EXCELLENT lighting. Fan works well too.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (783, 16, 94, 5, 'very happy with purchase.  Quiet.  Used for soft drinks.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (784, 16, 22, 3, 'The rinse cycle leaves a lot to be desired. If you dont add too much soap works great though.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (785, 45, 5, 3, 'They claim that it holds 52 bottles.  i could barely squeeze in about 47 and these were at a tightness to where i was concerned that i would break the wood drawers.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (786, 50, 108, 5, 'perfect fit');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (787, 36, 176, 5, 'Arrived quickly and was easy to install');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (788, 13, 123, 5, 'Didn''t use it long so I can''t attest to that but for the price it is extremely good looking and feels like a quality build. Just know it''s small - you will not be nuking turkeys in this - and it''s not super high wattage so it may take a bit longer. So if you must have your canned soup in 2-1/2 minutes and not 3 then this won''t work.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (789, 14, 3, 1, 'Worked great until it stopped working.    Twice I''ve had one of these go out on me.  The first time I ran it without the water turned on (my fault, but it can detect that there''s no water nd it keeps running anyway -- what the hell!) and it developed a leak.  I''d had it about 30 days and the company exchanged it for me.  The 2nd time I have been using it correctly with great results for about 1 year.  Then yesterday it started making a different noise than it usually makes -- it sounded like a pump was frozen up - and there was a burning smell.  And it again developed a leak in the bottom.  Disappointed.  It''s probably past the warrantee now so I''ll likely just have to junk it.  Not sure if I will get another one or not as they all seem to be the same brand available on Amazon so they may all have the same quality issues.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (790, 27, 82, 4, 'Very nice microwave, great price');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (791, 43, 197, 5, 'Perfect');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (792, 24, 29, 5, 'Awesome');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (793, 48, 136, 5, 'sometimes comes off, but overall, just fine');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (794, 15, 178, 5, 'works great!!!!!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (795, 40, 176, 5, 'Thank you');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (796, 10, 106, 3, 'I rarely do reviews, but wanted to let people know about the deceptive marketing on this dishwasher.  We did a remodel and due to space constraints needed an 18 inch dishwasher.  We replaced a Kenmore dishwasher rated at 50 db.  The Bosch sounds like a freight train in our kitchen compared to the Kenmore.  We couldn''t tell the Kenmore was on, but with the Bosch we can''t run it when we are home.  It drowns out the TV and forget about getting any sleep when it is running (the bedroom is on one side of the kitchen and the living room on the other).  Whoever rated this at 46 db must be hard of hearing.<br /><br />The plus side is that it has great features and cleans well.  The only other negative is that door doesn''t let you prop it open.  I like to open it a couple inches after it is done to let the dishes dry thoroughly.  The Kenmore would stay in any partially open position, but the Bosch is basically full open or closed and there is no way to adjust the tension on the spring to operat');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (797, 45, 133, 4, 'Note that this only chills to a low of 51 degrees. I probably would have bought another model had I realized this as I like my white wine in the mid-40s. However it does function well, is a very nice looking refrigerator, and I don''t find it to be too loud like some other reviewers (maybe that depends on the surface on where it sits.) Also note that it only fits slim bottles of wine - anything that is a bit larger in circumference on the bottom only fits in a few of the spaces.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (798, 3, 21, 3, 'Nice unit, however, only works with what I would say is standard slim wine bottles. Any bottle that is odd size will not fit on the racks.  So, to use the fridge for varying size wine bottles you would have to remove some shelves to allow them to fit which reduces the capacity.  I''m sending mine back, which has not been a problem so far working with Amazon.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (799, 21, 36, 2, 'Great Size, Great Idea, Poor Product.  Decides to not cool on its own and causes everything to thaw out.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (800, 24, 122, 5, 'Keep everything at 55 degrees, and don''t overstress it and it works great- after the first 4 weeks so we''ll see.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (801, 21, 132, 5, 'We love this cabinet hood and at the price we got it at, it was a STEAL compared to the local hardware stores. It was easy to install and it worked so well for our house.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (802, 27, 63, 2, 'It leaks water out the door.  the carpet where it sits remains wet.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (803, 29, 154, 1, 'Purchased Dec 2012. In May 2015 icemaker quit working-had to be replaced at my cost. Used a kitchenaid recommended service company in NC (one of 2 in our area). August 2015 refrigerator and freezer quit working. Compressor was replaced by same service repair co.( under warranty). unit worked for  2 hours and then quit. Service company stalling on coming back. Call to kitchenaid was worthless. After they shame you because you didn''t buy the extended warranty.(expect a fridge to last more than 3 years) they explain that it is after all &#34;manmade&#34; They refuse to admit there is a problem with this unit. Any suggestions on how to get a recall going? I would give it zero stars, but amazon won''t let me.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (804, 41, 101, 5, 'Yes, this was just what I needed to get the old washer humming again.  It did not fit the cabinet exactly, but I took a chunk of metal out of the back of the cabinet and it went in nice as pie,');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (805, 41, 151, 4, 'Just completed a kitchen remodel and its beautiful; loud but beautiful.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (806, 40, 153, 5, 'I bought this to repair our KitchenAid blender, model KSB5WH4. I could have purchased the part from several suppliers ranging in price from $4.86 to $9 and most charged a little more for shipping. This part from Amazon does seem to be the same factory certified part as described and the package says &#34;made in US&#34; which is nice. Very easy replacement.<br /><br />The coupler on our blender broke apart, that is, the hard, black rubber part broke apart and so only the metal core/insert remained on the blender. I read a few online instructions on replacement and then watched a few youtube videos showing the replacement. Instructions are included with this part and includes a few photos. removal of the old coupler is even easier than the youtube videos show.<br /><br />The coupler core appears to be made of aluminum and is screwed onto a hardened steel shaft. The instructions require you to insert a flat screw driver under the old coupler and just pry it up a few times, rotating your ');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (807, 21, 114, 4, 'Works fine, but came out of the box dented in several places. It is pretty quiet, gets nice and cold, the door seals well, and there is lots of room inside. It is a great choice for putting under your desk at work. Just don''t expect it to be pretty.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (808, 48, 7, 5, 'I purchased this as a gift for my parents, who frequently take their camper to the lake. They LOVE this ice maker and are constantly telling me how easy it is to use, and how quickly it works. They highly recommend it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (809, 27, 133, 5, 'A real $$$ saver.  They fit perfectly with no leaks.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (810, 41, 159, 5, 'I used this in my GE side by side refrigerator. works just like the original and much cheaper than purchasing in the store. I would definitely purchase again.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (811, 3, 42, 3, 'Honestly I would just wash the clothes by hand faster and easier.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (812, 3, 10, 5, 'Looks good and works quickly.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (813, 11, 113, 1, 'Terrible Product.  I couldn''t figure out why my water stopped working after a month.  I put a PUR filter in and it has been working as expected.  Not worth the cheaper price!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (814, 41, 149, 5, 'Perfect!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (815, 49, 147, 5, 'but it has not been installed yet!  Very nice looking stove top!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (816, 15, 95, 3, 'Quiet, but does not seem like 1000 watt power.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (817, 32, 117, 5, 'Perfect!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (818, 17, 104, 1, 'This is the microwave my neighborhood''s used. Neighbor''s went out 2 years ago. Mine last week. Both - the microwave stopped heating. Seems like a common issue with previous review');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (819, 50, 107, 5, 'Works & fits great in my Kenmore side by side.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (820, 3, 161, 4, 'Works great even in exposed weather like rain and wind. I live in the tropics in Hawaii. One con is that the zipper could be more durable. I can see it ripping after a while.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (821, 16, 42, 5, 'I will never hesitate to purchase the square trade protection plans.  Our Sharp AQUOS 70&#34; TV died at 13months.  Square Trade had a list of options for replacing the TV to us in 24 hours and a new TV here in our home within a week of contacting them.  This is a service organization that understands and appreciates what it means to service their customers.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (822, 31, 50, 5, 'Works wonderful for a mixed family. However, younger children like to play with it. Sometimes you just can''t win!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (823, 34, 168, 4, 'Have had this for over a year now. No issues. Very durable. We use the dishwasher every day with a big family, so this gets it''s use.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (824, 35, 131, 5, 'I love this machine! and the matching dryer too!<br /><br />Ok to set the record straight. About 4 years ago I fell for the &#34;all about being green front loader&#34;.  I bought an LG Front loader...It has been one of the most miserable 4 years of doing laundry imaginable. I would have never expected such an absolute nightmare. My laundry room has been stacked sky high with clothes that stink so bad that I would have to re-wash them four or five times until they were even wearable. I tried everything, I called the manufacture and begged for guidance! After multiple washings, I would resort to filling the bathtub and soaking all of the dark clothes. I even turned to using bleach - which I haven''t used in decades. I couldn''t take it anymore. I bought the Speed Queen AYN412 and the matching Dryer. I couldn''t be happier with my new SPEED QUEEN I LOVE IT!. I would highly recommend this product.<br /><br />I received my new Speed Queen Washer and Dryer four days ago. It is fantastic! Yes..');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (825, 15, 4, 2, 'Seem to work except aluminum does not rust and these do. Will not buy again');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (826, 23, 195, 5, 'Use this washing machine when I''m out in my RV.  Works great and saves me money and time visiting laundry mats. Love this product!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (827, 37, 79, 1, 'The part did not match the part for my stove even though I used the model #.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (828, 49, 142, 5, 'works great!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (829, 22, 81, 5, 'I have only had this LG Pair for about six weeks.  The underneath storage drawers came with this set and I feel that I receive a great deal.  As far as performance, so far amazing!  With a large household, I believe we have cut our time in half at least for washing and drying and the cloths look and smell clean.  The units are very quiet; our laundry room is next to the kitchen, next to open den and you cannot hear them during operation.  At first we did have a rocking motion from the washer; however, we failed (at first) to level with a level and very important on the feet of the washer and dryer is to adjust the feet, level and use the locking bolt on each foot.  Once we leveled the machines and used the locking bolt to lock each foot in place, we had no additional rocking problems from the washer.  We are following all of the operation procedures for the machines, if you have not owned a front loader before there are a few additional maintenance/clean out producers one must incorpor');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (830, 14, 86, 1, 'Maytag is garbage, avoid at all costs.  Product fails with less than a year of use...  Only value you will get is the scrap value of the steel.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (831, 36, 28, 5, 'Great deal aaaa+');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (832, 22, 17, 4, 'It''s bigger than I thought.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (833, 12, 33, 1, '[[ASIN:B00JCG9H0W Electrolux EI24ID50QS Built-In Dishwasher with IQ Touch Controls, 24-Inch, Stainless Steel]] This has been disappointing, to say the least. We had the dishwasher professionally installed, and ran a test cycle. A little more than half way through the cycle, it beeped and gave an error message. I called customer service number and spent two hours in the circle of hell known as voicemail carousel, cut-off, call back, runaround, &#34;try this number instead,&#34; and so on. Finally got a repairman out, twice now, and it still has not run through a complete cycle without shutting down with an error message. It has now been 3 weeks since we bought it, and nearly 2 weeks since we had it installed, and we still do not have a working dishwasher. Update: After the backordered parts were installed, it immediately sprung another leak before finishing a load of dishes. More parts have been backordered. It has now been 46 days since I ordered this, and it has never run through a cy');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (834, 24, 25, 1, 'did not work properly');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (835, 50, 176, 5, 'Thanks!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (836, 13, 7, 1, 'So disappointing. Like another reviewer said, you constantly have to tear this thing apart when it stops draining, to unclog the filter. Now sure how quarterS and socks and undies manage to even get in there, but it''s a huge pain in the ass!! 3rd time in 2 1/2 years that I had to unclog it only to realize the pump burned out! Oh and the door has had a leak since day one but of course, the repair men say whatever they can to avoid actually fixing it. Needless to say, after 3 visits from them, washer is still broken and out of warranty. GARBAGE!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (837, 24, 107, 5, 'DANBY WAS THERE FOR US WHEN NO ONE ELSE WAS<br />#Freshmen #LonerLife');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (838, 18, 50, 5, 'Installed in 5 minutes and worked like it suppose to.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (839, 29, 65, 5, 'Just as expected!!!  AAA+++');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (840, 14, 146, 4, 'Works perfectly');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (841, 35, 190, 5, 'love it! looks great in my kitchen, functions well');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (842, 36, 68, 5, 'We have an older Samsung and the turn table plate finally cracked and broke. This replacement is the perfect fit and though pricey, it is worth it. Now the food goes round and round again when we cook in the microwave.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (843, 28, 85, 5, 'Well Made and fit exactly like it was suppose to.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (844, 17, 115, 4, 'It was good');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (845, 29, 23, 5, 'Really love this microwave. Has the one touch settings that I wanted along with the +30 seconds button.  Its a great size for a countertop.  It can be a little noisy when it beeps as others have said.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (846, 41, 164, 1, 'Same as everyone else, NEVER buy Samsung major kitchen appliances. I spent over $5K a little over 5 yrs ago. Dishwasher died in 18m and had to be fully replaced, Bosch working great since the. Refrigerator ice maker died at 2yrs, replaced and 2nd one just died at 3yrs old last month. Now SMH9187 microwave, that worked okay at least for 5 yrs in very light use, just died with broken door latch (like dozens of others hit). Fixed it per YouTube video by drilling new hole in plastic door latch and moving spring. That worked fine but in middle of night 2 days before that, microwave beeped in middle of the night on its own, then had E-13 on the display.   Reset it and now getting either the dreaded SE error or worse, it literally in under 5 minutes suddenly turns on by ITSELF showing something about cooking a potato! Now after seeing hundreds of similar complaints including that microwave caused at least a couple fires I''m now scared to leave it plugged in when not home, especially since I h');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (847, 45, 160, 5, 'Fit as advertised.  Just make sure to run a couple gallons through it as directed.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (848, 41, 194, 5, 'Works as it should. Gets hot!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (849, 18, 12, 3, 'Love the refrigerator, quiet, perfect size, love light inside.<br />Upon receiving it big  dent in the back corner. Needed for that week so I kept it, other wise I would have sent it back.<br />I read other reviews with the same issue,  I wonder it these are dented to begin with and they send them out. The company knows what a hassle it would be to return them. disappointed on packaging. Very light weight boxes. Needs better quality control...');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (850, 49, 103, 4, 'Where do I begin? I received my brand new lil washer machine today. Couldn’t be more excited to do laundry! After 12 years of schlepping to the laundry mat, dodging cars to cross the street, counting pennies to convert to quarters,  I finally invested in my own private washing machine. I have to admit, this is my 3rd attempt at buying a portable washing machine in the last month. One of the main reasons why I made a decision to make this type of purchase is that the laundry-mat disgusts me. After 10+ years of going to the Ol coin op, I finally had it. I did a load of wash, and when it was done, I took my clothes out and everything was covered in Dog/ Cat hair. EVERYTHING was covered. IM highly allergic to dogs and cats and thankfully the laundry manager was there when this happened. She gave me quarters to re-wash my clothes. Unfortunately, the second wash didn’t get all the hairs out, so after drying, I took a lint brush to every article of clothing, to try and get what pet hair was l');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (851, 50, 47, 5, 'This works perfect for our GE Spacesaver II microwave!  At first I thought it would be too big because it hangs out of the microwave 1/4&#34; or so but the door of the microwave accounts for that.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (852, 19, 162, 5, 'Works perfect for when I am out in my RV!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (853, 42, 81, 4, 'Works good and blows outside strong. Comes with a thin plastic flex pipe exhaust that I tossed & replaced with aluminum for about $7. Looks great installed & the touch screen buttons are very responsive; much better than the push button.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (854, 44, 101, 5, 'OEM parts seem to be of better quality than the  original manufactory part. The Assembly Basket adjuster was constantly breaking. Other problems with Samsung Dishwasher parts, so I''m not willing to purchase another Samsung Dishwasher.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (855, 30, 84, 5, 'worked');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (856, 33, 177, 4, 'I like it alot!<br /><br />Be wary though.. The old filter restricted water flow because it was clogged with sediment. This new filter might actually allow you to taste the water.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (857, 17, 16, 5, 'early delivery and part works perfectly.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (858, 31, 194, 4, 'We purchased this last December and had it installed in February for our kitchen remodel. I was getting frustrated with trying to keep it clean.it was beginning to look like a 10 year old stove. Then  I used Bar Keepers Friend on it and it now looks brand new! Burners are good, some pans slide on the grate, but you get used to it. If you are looking for down draft gas stove top, this one fills the bill.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (859, 45, 138, 5, 'Love them, but very expensive...');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (860, 50, 48, 4, 'Easy replacement');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (861, 43, 82, 5, 'Outstanding looks cool.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (862, 40, 150, 5, 'Very good item. Quick delivery.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (863, 33, 33, 5, 'Shipped incredibly fast, easy set up, and what you see in the pictures is what you get! There was a small ding on the top of the cooler but it''s hardly anything to complain about. The dual zone cooling seems to work well and despite some other reviews, my Pinot Noir bottles are able to fit without any hassle. Worst case, just take out a shelf if you have a larger bottle that won''t fit.<br /><br />Really my only concern is that there is no space for a standing bottle but overall it is a sleek, affordable, compact cooler that works exactly as advertised.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (864, 45, 60, 3, 'still trying to get used to it');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (865, 20, 66, 5, 'This is a great fridge. The sparkling water function is awesome. The counter-level drawer is a great spot for cold drinks. While it''s a counter-depth, it''s still pretty roomy both in the fridge and freezer.<br /><br />It would have been better if the ice maker was located on the door, but Samsung doesn''t seem to do that.<br /><br />I was a little wary ordering this over the Internet, but it came in perfect condition and the delivery guys were great.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (866, 18, 179, 3, 'The door sticks for some reason, making the fridge move every time I try to open it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (867, 33, 181, 5, 'This a very quiet fan....at one point I could not hear if over the other kitchen motors running.  It has met my expectations and then some.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (868, 16, 175, 1, 'This freezer is SO small - there is barely room for anything in it. There is a 20% restocking fee and we have to pay for return shipping so we ended up just keeping it. Wasn''t worth losing so much money for the return.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (869, 44, 4, 4, 'They worked great- however, there are absolutely no instructions and they are color coded, so we researched for 3 days to figure out which one went where.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (870, 43, 127, 3, 'I expected the water flow to be back to normal since the previous filter needed replacing and I had experienced a greater flow in the past when replacing a filter, but it did not increase at all (in fact might be more restrictive than the old filter that was overdue to be changed).');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (871, 13, 91, 4, 'I love this range! I wish it had a self cleaning oven but the continuous cleaning feature does work. It has real cast iron grates witch is a big plus, The igniter feature works more like a grill, it takes some getting use to but it performs well. I have had this range for about 2 years now and I am still happy with this purchase. It fits well into my tiny craftsman bungalow kitchen.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (872, 15, 155, 5, 'Neat! Works great! Nice and compact!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (873, 11, 148, 1, 'DOESN''T WORK.  Noticed right after 90 day warranty expired that it had quite working. I would NOT recommend!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (874, 43, 42, 5, 'perfect condition<br />Thank You!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (875, 17, 175, 5, 'Fits my whirlpool model ED5VHEXTBO1. You have to run two or three gallons out to clean the carbon dust out, and to clear the burps and spudders out of the water line. Last 6-months.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (876, 32, 152, 4, 'If you''re looking for a great cooler, this one might be the answer.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (877, 19, 26, 5, 'Replacement plate');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (878, 48, 30, 5, 'We loved it!! Installed very easily, no leaks only remember to purge before hand to remove impurities and air in the filter.  Not having to pay the hefty GE price!! Even if GE is compatible with NFS/ANSI 56 and the Waterfall Filter meets NFS/ANSI 42 and not 56, your county water companies many times have to meet even more stringent health standards than 56.  No worry, we will purchase this filter again. Cheers &amp; good drinking!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (879, 22, 97, 5, 'It works just fine.  It''s less expensive than the one we had been purchasing for years!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (880, 44, 182, 1, 'The delivery was poor. Fridge came to us scratched up and beaten. It was very heavy and going to UPS to take it back was a hassle.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (881, 21, 194, 5, 'Simple and easy to replace on my particular stove. Thanks.!!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (882, 14, 171, 3, 'Nice Fridge, but not worth $284.  Advertises that it fits 120, 12 ounce cans; more like 80 - I counted as I filled it up.  Doesn''t quite keep a 34 degree temp as advertised.  I would only recommend buying this fridge if the manufacturer dropped the price.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (883, 12, 199, 5, 'works great, and it''s super quiet.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (884, 27, 134, 5, 'fan can run loud. But man... It''s nice, does its job and was very easy to install.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (885, 45, 74, 5, 'Perfect fit. Works great.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (886, 10, 53, 1, 'Viking should be ashamed of marketing such a poor performing product.  The most powerful motor on the market is useless because the ram only travels 6 inches before returning.  You will find yourself pushing trash down by hand to fit additional trash into the bin.  Yuck!  To add insult to injury, the bin does not use a standard size bag.  You have to purchase expensive ones from Viking.  Viking is clearly not the quality brand name it use to be.  The only thing worse than this compactor is the customer service deptartment all the way up the chain to the regional sales manager. Beware!  If you buy this product, you are stuck with it!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (887, 32, 152, 5, 'Love how well this natural deodorizer works. I would recommend it to anyone who is looking to eliminate unpleasant smells such as skunk, wet dog, or recently used bathrooms!  It really does do the trick.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (888, 48, 111, 5, 'Great product with a speedy delivery. Thank you');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (889, 47, 53, 1, 'We bought this microwave 2 years ago as part of a home remodel. It was great while it worked but recently stopped working. Sharp warranty is only 1 year. For the amount of money we spent on this I would expect it to last more than 2 years.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (890, 25, 83, 3, 'The freezer has a lot of space inside but it takes a lot of time to cool down.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (891, 27, 99, 5, 'I decided to buy this dryer and I don''t regret so far.  It works great !!!!! Thank you so much.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (892, 4, 11, 2, 'Unfortunately, the product does not meet my expectation. They were extremely too small for my stove. Model no. SF302EEW. Is it possible to return the item? I will have to reorder the kit with the 4 or 5 knots.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (893, 13, 175, 3, 'when we first installed the filter the water was black that came out, i am assuming from the carbon filter, but i have never had this experience from any other filters.  it eventually stopped but it should not have been black.  we have been using it for while and the water has a haze to it... not impressed so fare, won''t buy again....');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (894, 13, 43, 3, 'Nice washer. Unfortunately, it leaked all over the floor with the first wash. I think the corrugated drainage tubing got damaged or was defective.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (895, 36, 99, 4, 'Looks okay, but old one was good so this was not used.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (896, 26, 20, 5, 'As advertised.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (897, 44, 175, 5, 'Works just like it should. No issues so far. Heavy, but simple setup. Note: keep items spread out to allow airflow or you may get a few frozen foods.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (898, 16, 106, 5, 'Great.....');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (899, 31, 104, 5, 'Works great in bathroom to preserve insulin for diabetes. Very compact and takes up very little space on counter.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (900, 15, 172, 5, 'The dryer took forever to dry clothes,then wouldn''t turn on at all. I looked up what might be the problem and ordered the thermal fuse and now it dries the clothes so fast. It only took a couple minutes and whew!! It works great.Very satisfied.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (901, 30, 72, 5, 'I love my wine freezer. Holds 24 wine bottles easily, but not champagne bottles. It has duel temperature areas to allow you to keep your reds warmer and whites colder.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (902, 21, 111, 5, 'Filter work fine, great price too');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (903, 41, 9, 5, 'Good value.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (904, 22, 132, 3, 'Its ok, just flimsy and cheaply made. It will definitely dry your clothes and i do enjoy the fact that it will fold up so small for storage. Pulled it out to use for the third time and its ripping apart at the seams... returning it😰😢');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (905, 21, 31, 1, 'Bever worked! Tried replacement twice and still did not do the trick! Beware of this product!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (906, 48, 76, 5, 'good product');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (907, 38, 29, 5, 'I am a student in family housing. This little dryer has saved me so much time by not having to use the laundry facilities nearby. It works great. The loads can''t be too big, but that isn''t a problem. I can get most of the clothes for me and my two boys done in just two loads per one load of wash.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (908, 39, 114, 1, 'I received this as a gift for my birthday last year and it''s already dead. The dual cooling units do not work anymore and the top will not cool to any less than 64 degrees, the bottom does not function at all, what a waste. Will never purchase this unit again. When we called about it the 90 day warranty had already expired and we were expected to foot the bill to get it fixed, which was more than the fridge was even worth.<br /><br />WORD OF WARNING:  When moving the unit... make sure you to let it sit so the cooling fluids settle for at least an hour before plugging the wine fridge back in. Your fridge will never work properly again if you do not.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (909, 12, 66, 5, 'Filter works just great with my fridge. Thanks for the prompt delivery too!!!😀');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (910, 27, 100, 5, 'Truly a great cook top.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (911, 27, 70, 4, 'The stove is easy to clean and compact - fits perfectly under a 24&#34; range hood (I paired with this one: http://www.amazon.com/gp/product/B000HZTM4S?redirect=true&ref_=cm_cr_ryp_prd_ttl_sol_1). Two things that don''t make sense to me are the way the temperature knobs have the high setting in the center - and then lower settings either direction - as well as the fact that only one burner (left front) has oomph for quick heating tasks like boiling pasta water. Nice looking and comes with the option to install for either NG or propane.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (912, 23, 151, 5, 'Great fun for the family, and so easy!  Makes just 1 if you want or dash off 30 or in minutes.  Jolly rancher, life savers, floss sugar, it all works great!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (913, 43, 137, 4, 'They work fine, now its just a matter to see how long they truly last.<br />It''s difficult to place the adapter onto the top that is required for my GE refrigerator, but this has been true with any of this class of filters, even the original equipment filters.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (914, 20, 72, 5, 'I hesitated for a moment before I purchased this filter because it was not the official brand.<br />But the cheapie in me said give it a try.<br />It looked and felt exactly like the name brand and fit perfectly.<br />Back in business.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (915, 15, 113, 5, 'Perfect replacement for our GE fridge.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (916, 48, 10, 4, 'Great wall oven, it works as it should and meets all of my standards.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (917, 26, 32, 2, 'Ice maker ran out of ice again today. It''s just my family (of 4) under regular usage on a Sunday. Made a smoothie in the morning, iced coffees, drinking ice water, the normal stuff. It seems like it has trouble keeping up. With a fridge this expensive I expect better.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (918, 49, 173, 1, 'This thing is worthless. It''s means of refrigeration is a fan similar to the one in you computer. It has no compressor. Calling it a frig should be punishable by law. I gave it one star only because the zero star option was not available.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (919, 36, 177, 1, 'TRIED TO SAVE $20, ENDED UP WITH A WATER LEAK & DAMAGE TO MY FINISHED BASEMENT CEILING.  NOW I HAVE TO DO DRI WALL REPAIR....  DO NOT BUY THIS !!!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (920, 35, 178, 5, 'worked perfect at my maytag');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (921, 12, 116, 1, 'FIRE HAZARD - AVOID!!!!!<br />The knobs created two fires in our house already, in the two months we have used the stove.<br />Anyone walking by can accidentally brush against the knob with barely any pressure and accidentally turn on the stove.<br />Once a shoebox sitting on the stove caught on fire, the second time it was a wooden cutting board.<br />This stove should be recalled.  When I complained to our local Samsung appliance technician, he told me that Samsung has had 100''s or 1,000''s of complaints about this, but that Samsung is actually waiting for people to die before they care to do anything about this.<br />When I called Samsung''s corporate &#34;Executive Relations&#34; office I spent over half an hour on hold, then an hour with a true idiot who provided zero assistance.  Their customer service is useless.<br />I WILL NEVER BUY ANOTHER SAMSUNG PRODUCT AGAIN.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (922, 3, 176, 5, 'Bought this fridge 10 days ago. So far very good. Very quiet which is a significant plus. Purchased at Home Depot and bought the 5 year warranty. Also extended the manufacturers warranty by 1 year with my credit card. P.S. Did not purchase on Amazon even though it was slightly less expensive.   In trying to decide on refrigerators we discovered that many of the reviews are brutal. Usually either noisy, break down, or the ice maker fails. This includes Samsung, Kenmore, GE, Whirlpool, Kitchen Aid, and LG. Have never seen an industry so beset by problems which also include poor service, expensive parts, denial of responsibility. Quite frankly this counter depth refridgerator by LG had the best of all the worst reviewed, but so far we have been pleasantly surprised. Will review again in a  few weeks to update.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (923, 45, 166, 5, 'Love it!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (924, 40, 139, 5, 'Awesome');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (925, 25, 55, 5, 'For the price this is a great little fridge for your office or dorm room. It does hold a 6pack and also can be used in the car and hot or cold settings The hot would only keep a dish warm not warm it up.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (926, 11, 42, 5, 'I live in rural Hawaii and our power goes out frequently, sometimes for days at a time.  To keep our food from spoiling we use a combination of generator power or I run it off a deep cycle marine battery charged with solar panels and a 2500 watt power inverter.  That opens up a lot of potential for voltage anomalies and I don''t want to fry a $1200.00 refrigerator.  This surge protector is unlike any I have ever seen before.  Usually they just look like an oversized male plug on one side and female on the other.  I''ve always wondered if they even work.  This unit is different. I like the translucent housing so that you can see the circuit board and electronics inside.<br /><br />I saw some other reviews that indicated they had problems figuring out the unit because the instructions were in Spanish.  Mine didn''t come with any instructions though the label was in Spanish.  I''m not sure I understand the confusion because you plug this unit into the wall, plug the appliance into it, and the');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (927, 10, 15, 5, 'The replacement microwave place fit perfectly. I couldn''t ask for more than that!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (928, 26, 138, 5, 'We have a hard time keeping ice trays full at our lake house in the summer.  This is great. It''s not silent when it''s making a batch of ice but I couldn''t call it loud either. The ice falling into the bin can be loud when you don''t know it''s going to happen.<br /><br />It''s not high volume but we rarely ran out with a family of four in the summer putting ice in our drinks.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (929, 23, 27, 4, 'This works great! It has prevented the &#34;Oops&#34; of putting dirty into clean dishes.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (930, 27, 194, 1, 'This product is a lemon. Did not cool within 16 hours. Controls are  sluggish and barely respond to touch. Oil leaked from the unit.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (931, 21, 125, 1, 'I have a frigidaire fgus2632lp which I believe this model replaced.  Mine is also a piece of junk.  Icemaker had 3 service calls in first 3 months.  I assumed the water dispenser put out chilled water but it doesn''t, which sales people didn''t even mention. Fridge interior cannot maintain constant temp; items toward rear(like pickles in a jar) have gotten frozen.  Items come out of fridge damp, and shelves are damp.  I will never buy any frigidaire product again.  I have bought another 2 years extended warranty(my fridge is 4 years old) and when it runs out I am replacing this piece of crap.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (932, 45, 12, 5, 'Delivered in perfect condition.  Runs great - no issues whatsoever.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (933, 41, 173, 5, 'Awesome product can''t wait till my new kitchen is all done .');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (934, 16, 159, 5, 'I couldn''t pass up purchasing rises because of the price. The manufacturer ones are so expensive. I was hoping they would fit and they did perfectly. I will be purchasing these again for sure');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (935, 23, 144, 5, 'This filter was packaged well and easy to install.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (936, 10, 52, 5, 'Been nearly a year since we got this and we still love it.  Keeps everything the perfect temp.<br />Bottom row works great for larger bottles.<br />Wish it had a place you could store one sitting up if you don''t finish and need to reseal<br />Can''t beat the price.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (937, 32, 143, 5, 'OMG my Clothes are finally getting Washed like the Good Old Days !<br />I waited for over 2 months to get this Speed Queen n it has been Worth the Wait. The  clothes are all washed in a More<br />gentle way n come out of the washer less Wrinkled - once in the dryer they are in better shape -Less wrinkles n<br />Here''s a Novelty CLEANED . I threw Out into the Garbage the 4 year Old Computerized Washer with the New Govm''t<br />Regulated water rationing Washing Machines .<br />This is a KEEPER !');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (938, 4, 16, 5, 'Excellent and strong and I would recommend it');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (939, 46, 55, 5, 'works well');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (940, 4, 126, 2, 'Never buy Frigidaire - I bought the Fridge, Microwave and Oven.<br /><br />Two months old the oven light died.<br /><br />2 years the microwave door handle just broke off - now I must tell you that I very rarely use a microwave. Just to boil water for coffee. Can''t be fixed.<br />after a couple months the plastic glass had gotten wierd and like blotchy looking.<br /><br />Fridge- I used to buy purified ice and put it into the freezer. A year after getting the fridge I had a RO system installed and had the technician set up RO water to the ice maker about 3 months later the ice maker died. No kidding. I would never encourage anyone to buy this brand. It was good money thrown away.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (941, 17, 56, 2, 'Don''t understand why, but it is leaking water inside. Wish it was a little bit bigger and colder.  Good for soda only.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (942, 10, 198, 5, 'I really was not sure about this thing when we bought it. I have to say I''m very impressed.  It is a little small but if what you need washed fits in it, it does a really good job.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (943, 16, 62, 3, 'I liked my 800 Plus series dishwasher the first 1.5 years I had it, I got 2 other families to buy one. Cleans great, and I really like how silent it runs. Then just 6 months after the warranty expired, my $1000 panel ready dishwasher door came crashing down hard enough to shake glasses on the counter above it.  One side of the door spring system had broken. I was hoping a $10-$30 piece of plastic and maybe some rope (probably costs $0.50 to manufacture) would fix it.  Sad to say, the springs on these dishwashers are held in place by a thin layer of plastic molded into the whole dishwasher unit case bottom.  This thin plastic fin had broken so there was no way to keep the spring in place. The fix means replacing the entire unit bottom...<br />Bosch said it would be $100 for someone to come out and diagnose the problem. Then they would have to return for service.  This all just happened, and is not yet resolved. I will update once it is.  I had hoped more money meant better product, long');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (944, 30, 188, 5, 'love it, had it for several years now and it has never lost suction.  I will buy another one when this one stops working.  I''ve tried several bottom loaded ones and all lose suction, but not this one.  Water is cold and the hot water is very hot,doesn''t need heating up.  You can also turn the hot off if you don''t want it on.  Great Product!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (945, 19, 132, 5, 'It fits perfect! Arrived on time also.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (946, 11, 135, 5, 'I LOVE this dishwasher!  It''s so quiet we hardly know it''s on.  It does a good job too!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (947, 19, 174, 5, 'Super replacement for our burned out element in our dryer. Easy to install and has performed flawlessly.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (948, 33, 152, 5, 'I LOVE this machine. Took a few tries to figure it out and you can''t put a lot in it. I just  love it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (949, 3, 158, 1, 'I had read reviews extensively before trying this filter. This filter did not work for me. It filters about half a glass of water in 10 minutes or so. Have tried to shake it and reinstall. Thought that an initial clog may eventually get cleared but 30 days down the line it''s still just a trickle of water every 15 minutes.<br /><br />This might just be a defective peice but in the last 12 years I have never had such an experience with the original filtrrs. They might be a few bucks more but am going back to them.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (950, 14, 77, 5, 'It''s a masterpiece of the kitchen, I love it !  Very quiet, nice look, good lights and a remote !  What can you ask more ?');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (951, 41, 134, 5, 'Popped it in no problem & works great!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (952, 46, 114, 2, 'It holds 6 cans and is very quite, it keep my soda really cool, no cold but it works good. I wish it could be a little colder but, I am basically happy with it.<br />Update - after a couple of weeks this little baby now keeps my soda COLD - I guess it just need to run for a bit to get broke in.. I would now give it full 5 stars!<br /><br />UPDATE 5/16/16 - in less than a year, this stop cooling at all. For the cost i could have a purchased a larger fride but want somethings small. One day it was fine the day is was warm. Very disappointing. I really loved it..');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (953, 47, 157, 5, 'It was as I expected.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (954, 39, 23, 2, 'Awesome Ice maker....One of the things my wife and I dreaded about our decision to go RVing full time was having to give up our ice maker. That is before we found out these portable little things existed. The Avalaon Bay 26 pound ice maker takes up very little space on our crowded countertop, and it makes more than enough ice for the 6-pack cooler we use on those afternoons by the pool and for our evening industrial strength beverage. I estimate it will pay for itself in 6 months vs buying ice at the campground (if it is offered) and we can store it in much smaller baggies in our always crowded freezer. I wish I''d had one of these things years ago when we only used our travel trailer on the weekends.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (955, 13, 92, 5, 'We are a family of cooks and we love this stovetop. The griddle works great. Thumbs up all around.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (956, 29, 22, 5, 'Good stuff');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (957, 47, 138, 5, 'good as original in every way, just a better price');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (958, 16, 81, 1, 'wrong one poor rep');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (959, 46, 84, 4, 'I like it, but really feel ripped off for what I paid for it.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (960, 3, 149, 5, 'Part was perfect.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (961, 19, 106, 1, 'Be very careful this product is really bad major prroblems with the icemaker and Frigidaire will not stand behind their product. Will never buy one again. Watch the model number.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (962, 29, 96, 5, 'Standard range hood in minuscule size - works ducted or unducted.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (963, 16, 77, 5, 'Delivery was great and the product works great.<br />I''m always weary when I buy replacement cartridges<br />but these worked awesome. Great product and will<br />purchase again.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (964, 42, 120, 5, 'usps driver stopped in front of my apt building, sat for two minutes then drove off.  He didn''t leave any notification as to what to do.  7:45 am');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (965, 33, 36, 3, 'not an oem part but functional');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (966, 16, 12, 5, 'The pan fit our Maytag refrigerator and it was a very reasonable price.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (967, 15, 32, 5, 'Excellent');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (968, 32, 137, 5, 'Other websites told me you had to buy the complete motor to get this pulley.<br />This one works just fine and much cheaper than replacing the motor!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (969, 40, 143, 5, 'I gave this as a gift to a friend with an apartment in an Uptown brownstone. It''s perfect because how little space it takes and how attractive it is. It sits against an old panelled wall& though it''s modern it compliments the brick & wood nicely. It is truly silent & keeps the wine at a perfect temperature.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (970, 18, 20, 4, 'Kit arrived quickly. The parts were good quality. Some instructions would have been useful as there were some items that weren''t meant for my machine.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (971, 38, 23, 5, 'Great item. did the job. Thank you');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (972, 50, 197, 5, 'These work perfectly. I should have bought them years ago! I definitely recommend them.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (973, 14, 21, 5, 'Easy to install great for rental property');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (974, 3, 176, 1, 'This dishwasher has a problem in the design of the control panel which causes it to burn up the flex ribbon wiring.  My dish washer has burned through 2 control panels in less than its first two years.  This part cost about $150.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (975, 34, 110, 4, 'It floats! It collects lint! It works! No complaints.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (976, 42, 136, 5, 'Gets cold fast and is lightweight');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (977, 14, 100, 2, 'My range hood vent is 6&#34;, and the bathroom vent is 3&#34;, so this didn''t fit either. I adapted it to fit over the bathroom vent anyway. In a strong wind, the light-weight flaps fly open and shut easily, defeating the purpose of the draft protection. It needs an additional shroud to block the wind.<br /><br />If you are looking for an excellent dryer vent, use the Lambro Ind. 289 Dryer Vent Closure instead. It is solid, sturdy, and works well. It just doesn''t work horizontally as for range hood vents and bathroom vents.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (978, 25, 5, 5, 'This was an exact replacement for my failed switch.  Works great.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (979, 4, 174, 4, 'Perfect fit. Easy to install.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (980, 36, 189, 5, 'Great');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (981, 47, 135, 5, 'Love this frig!! Perfect size and no wasted freezer space!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (982, 3, 9, 3, 'Very looking good nice good but very noisy');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (983, 42, 81, 4, 'Was pleased with the packaging and easy instructions to set it up. Worth $55 and that it was ''Prime&#34; order.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (984, 18, 9, 5, 'it''s small and compact and it''s perfect for me  as I can''t walk up and down the cellar stairs like I used to');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (985, 19, 156, 5, 'There was quite a bit of hand wringing two weeks ago when the glass turntable plate went flying out of our microwave oven and shattered in a million pieces all over the kitchen floor. I won''t name the culprit, but he''s the one who required tweezer &#34;surgery&#34; to get the glass shard out of the sole of his foot.<br /><br />Where ever would one find a replacement part for a Sharp microwave oven purchased in 2001? To my great relief, from Martin Microwave, here on Amazon!<br /><br />You need to know the model number of your microwave (hint: mine was on the back of the oven) but once you know that, Martin Microwave sends you the correct part.<br /><br />The 11½&#34; glass turntable plate I needed was a little over $20 and standard shipping was extra.<br /><br />The new plate fits my microwave perfectly. It looks and performs just like the original.<br /><br />I am very grateful to have found this part so easily and to have received it so quickly.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (986, 42, 132, 5, 'Works great.  Doesn''t get too hot, so cloths don''t shrink.  Easy to set up and energy efficient.  Great size for an apartment.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (987, 29, 102, 4, 'Has Oder that was hard to rid of');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (988, 10, 8, 5, 'Very nice stove......');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (989, 48, 184, 3, 'Good dishwasher. I like the layout, the third rack, and the large silverware basket. My biggest complaint is that there is no &#34;extra rinse&#34; option. An extra rinse option is highly desirable because most new dishwashers conserve water to a fault. As a result, after a wash, the dishes have a slippery feel to them. I suspect this is because not all the soap is rinsed off. I''m all for conserving water, but not if it means I''m consuming soap residue every time I eat or drink.  Update: If you are generous with the soap, there is a soap smell after a normal wash cycle is finished. If you run an express cycle after the normal cycle, the soap smell/residue is removed. A rinse cycle can work, but the rinse cycle does not provide a drying option, so your dishes are left soaking wet.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (990, 49, 85, 1, 'Don''t waste your money!!!! This stuff is ridiculous to try and get on and if you do manage to get it on it will have bubbles, creases, etc... despite following the instructions to the t :-( Seriously disappointed.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (991, 36, 135, 4, 'This was the first time that I bought a compatible GE filter and it is working pretty well. Like the others, I needed to run the water through the filter a bit before it tasted normal. In addition, I was very happy with the service I received on this purchase. The customer service representative sent me emails before and after receipt of the merchandise to keep me informed of the timing of receipt and whether I had any questions after installation. I''ve only had it about a week and so far so good.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (992, 49, 86, 5, 'AAA+++ just as ordered!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (993, 49, 144, 5, 'The compressor sometimes took a couple of tries to get started. Traced it to defective motor starting device. This one cured it, easy installation.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (994, 19, 195, 5, 'Great DEAL!!!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (995, 14, 41, 2, 'I did not like this product , 1.  I had to cook for double of the time instructed on the manual ,have to kept open to shake the food to cook well too .also this product is good for a Single person it did not work for my family of 5 people .<br />2. every time I wash the basket the small screws that holds it kep falling off.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (996, 16, 99, 4, 'I really like it and the price is very reasonable.');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (997, 35, 192, 5, 'AAA+++ just as ordered!');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (998, 24, 195, 2, 'Definitely heed the poor reviews on this product.  I wish I had.<br /><br />Cooling system gave out once the unit was 3 months our of warranty; however, KingsBottle would not honor the problem.  Customer service was absolutely horrible.  I''ve never experienced anything like it.  Once they indicated they would not warranty the unit I asked if they had a service agent that could fix it.  At first they said they did as I was so close to their headquarters; however, I never received any information.  When I called back, they said they did not have an agent, but would send me some recommended repair companies.  Again, I never heard from them and had to follow up.  I explained that I was waiting on a recommended service company and again they told me they would get back to me but never followed up.  I called every day for a week but could not get a simple recommendation.  I finally gave up and searched for a company on line.<br /><br />The machine looks nice and worked well for the most part');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (999, 10, 79, 5, 'I have had my wine cooler for a little over one week.  I love it.  There is absolutely no noise from it.  The very first day, it did run a lot and made a bit of noise as it was working its way down to the chosen temperature.  I am wondering if those who stated it was noisy have it too close to a wall, or a cupboard causing vibration.  It is very classy looking.  Guests love the appearance as do I.  I have mine on the floor next to a china cabinet with lots of air space around it.  I do not believe that this would fit on most countertops.  I have not seen counters in kitchens that did not have cupboards above.  It does NOT get warm on the outside at all.  I am finding that it does not run often at all and keeps a steady temperature.  I live in a desert area, so it gets very hot here (triple digits) and I do not run my AC all the time.  Frequently the inside of my house is 80 degrees and the cooler still does not run too much.  I have mine set at 58 degrees and it holds this steadily.  T');\nINSERT INTO Reviews (id, user_id, product_id, star_rating, content) VALUES (1000, 45, 149, 5, 'Works well. It is everything I expected.');\nUPDATE Orders SET created_at = DATE_ADD(created_at, INTERVAL 8 YEAR);\n